INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (1, '2025-09-30', 'Introduced in House', '<p><strong>$2.50 for America’s 250th Act</strong></p><p>This bill requires the minting of $2.50 coins to commemorate the 250th anniversary, or the semiquincentennial, of the signing of the Declaration of Independence.</p><p>Specifically, the Department of the Treasury must mint and issue a $2.50 circulating coin upon determining that such minting is technically feasible, economically feasible, and not cost prohibitive. The design of such a coin during the first five years of its issuance must be as described by the bill, however, subsequent designs may be selected by Treasury to celebrate the founding of the United States.</p><p>Treasury may also mint and issue $2.50 numismatic coins (i.e., collectible coins) in silver, clad, and other alloys, including gold.</p>', '2026-02-09T15:53:22Z', '00', 1);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (2, '2025-06-26', 'Reported to House', '<p><strong>Department of Homeland Security Appropriations Act, 2026</strong></p><p>This bill provides FY2026 appropriations for the Department of Homeland Security (DHS).</p><p>Specifically, the bill provides appropriations to DHS for Departmental Management, Intelligence, Situational Awareness, and Oversight, including</p><ul><li>the Office of the Secretary and Executive Management;</li><li>the Management Directorate;</li><li>Intelligence, Analysis, and Situational Awareness; and</li><li>the Office of Inspector General.</li></ul><p>In addition, the bill provides appropriations for Security, Enforcement, and Investigations, including</p><ul><li>U.S. Customs and Border Protection,</li><li>U.S. Immigration and Customs Enforcement,</li><li>the Transportation Security Administration,</li><li>the U.S. Coast Guard, and</li><li>the U.S. Secret Service.</li></ul><p>The bill provides appropriations for Protection, Preparedness, Response, and Recovery, including</p><ul><li>the Cybersecurity and Infrastructure Security Agency, and</li><li>the Federal Emergency Management Agency (FEMA).</li></ul><p>The bill provides appropriations for Research, Development, Training, and Services, including</p><ul><li>U.S. Citizenship and Immigration Services,</li><li>the Federal Law Enforcement Training Centers, and</li><li>the Science and Technology Directorate.</li></ul><p>The bill also sets forth requirements and restrictions for using funds provided by this and other appropriations acts.</p>', '2025-09-11T18:58:01Z', '07', 22);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (3, '2025-07-23', 'Introduced in House', '<p><strong>Resident Physician Shortage Reduction Act of </strong><strong>2025</strong></p><p>This bill increases the number of residency positions eligible for graduate medical education payments under Medicare for qualifying hospitals, including hospitals in rural areas and health professional shortage areas.</p><p>The bill provides for an additional increase of 2,000 positions per fiscal year from FY2026-FY2032; during this period, each hospital may receive up to 75 additional positions in total under the bill and current law. Additionally, one-third of the positions that are made available under the bill must be allocated to hospitals that are already operating above applicable resident limits.</p><p>The bill also requires the Government Accountability Office to report on strategies to increase the diversity of the health professional workforce, including with respect to representation from rural, low-income, and minority communities.</p>', '2025-12-02T16:40:26Z', '00', 46);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (4, '2025-09-08', 'Introduced in House', '<p><strong>Retire through Ownership Act</strong></p><p>This bill allows the fiduciary of an Employee Stock Ownership Plan (ESOP) to rely on a valuation provided by an independent valuation or business appraiser  in determining the fair market value&nbsp;of the plan''s securities if the securities are not traded on a national securities exchange (i.e., not publicly traded) and the expert or appraiser follows specified methodologies.&nbsp;</p><p>In general,&nbsp;ESOPs are defined contribution pension plans where employees accrue shares of their employers'' stock in individual accounts as part of their compensation. After separating from employment or retiring, employees receive the cash value of their shares.</p><p>Under the bill, an independent appraiser or expert must adhere to the methodology established under the Internal Revenue Service Ruling 59-60, which prescribes the factors a professional business appraiser should consider in forming a valuation of the stock&nbsp;for a closely held business.&nbsp;</p>', '2025-12-15T18:07:23Z', '00', 51);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (5, '2026-01-30', 'Introduced in House', '<p><strong>Safeguard American Voter Eligibility Act or the SAVE America Act</strong></p><p>This bill requires individuals to provide documentary proof of U.S. citizenship when registering to vote, and requires photo identification to vote,&nbsp;in federal elections.</p><p>Specifically, the bill prohibits states from accepting and processing an application to register to vote in a federal election unless the applicant presents documentary proof of U.S. citizenship.&nbsp;The bill specifies what documents are considered acceptable proof of U.S. citizenship, such as&nbsp;identification that complies with the REAL ID Act of 2005 that indicates U.S. citizenship.</p><p>Further, the bill (1) prohibits states from registering an individual to vote in a federal election unless, at the time the individual applies to register to vote, the individual provides documentary proof of U.S. citizenship; and (2) requires states to establish an alternative process to demonstrate U.S. citizenship.</p><p>Each state must take affirmative steps on an ongoing basis to ensure that only U.S. citizens are registered to vote, which shall include establishing a program to identify individuals who are not U.S. citizens using information supplied by certain sources.</p><p>Additionally, states must remove noncitizens from their official lists of eligible voters.</p><p>The bill (1) provides&nbsp;for a private right of action for certain violations, and (2) establishes criminal penalties for certain offenses.</p><p>Individuals voting in federal elections must present an eligible photo identification document. An individual who votes by absentee ballot must submit a copy of their identification document with both the request for, and the submission of, the absentee ballot.</p>', '2026-02-09T19:58:10Z', '00', 57);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (6, '2026-01-07', 'Introduced in House', '<p>This resolution expresses the sense of the House of Representatives that (1) Congress should adopt a fiscal target to reduce the federal budget deficit to 3% of gross domestic product or less as soon as possible and no later than the end of FY2030; and (2) after the target is achieved, Congress should continue to pursue further deficit reduction with the goal of achieving a balanced federal budget.</p>', '2026-02-06T19:53:35Z', '00', 66);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (7, '2025-12-04', 'Introduced in House', '<p><strong>Increasing Baseline Updates Act</strong></p><p>This bill requires the Congressional Budget Office (CBO) to submit to Congress at least two updates to its annual baseline unless CBO is otherwise directed by the chairs of the congressional budget committees. At least one of the updates must include the economic data used by CBO to calculate the update.</p><p>(A baseline is a projection of federal spending and receipts during a fiscal year under current law. Under current law, CBO is required to publish the baseline by February 15 of each year. While there is no statutory requirement for specific updates, CBO generally provides an update with its analysis of the President''s annual budget request. It has also provided some updates during the summer, depending on the timing of the President''s budget request.)</p><p>The bill also requires the President to submit technical budget data to Congress on or before February 1 of each year to the extent this is practicable. Currently, federal agencies provide the data to Congress as part of the President''s budget request.</p>', '2026-01-14T15:33:24Z', '00', 67);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (8, '2025-02-27', 'Introduced in House', '<p><strong>Billion Dollar Boondoggle Act of 2025</strong></p><p>This bill requires the Office of Management and Budget (OMB) to collect information from federal agencies and report to Congress regarding projects that are behind schedule or have expenditures that have exceeded the original cost estimate.&nbsp;</p><p>Specifically, the bill requires OMB to issue guidance directing federal agencies to annually submit specified information to OMB regarding certain federally funded projects that (1) are more than five years behind schedule, or (2) have expenditures that are at least $1 billion more than the original cost estimate for the project.&nbsp;</p><p>Among other information, the agencies must submit to OMB</p><ul><li>a description of each project;</li><li>an explanation of any change to the original scope of the project;</li><li>the original and current expected dates for the completion of the project;</li><li>the original and current cost estimates adjusted for inflation;&nbsp;</li><li>an explanation for any delays in completing the project or increases in the cost; and</li><li>the amount of and rationale for any award, incentive fee, or other type of bonus awarded for the project.</li></ul><p>The bill also requires OMB to submit an annual report to Congress containing the information submitted by the agencies&nbsp;and post the report on the OMB website.&nbsp;</p>', '2025-05-07T14:02:51Z', '00', 91);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (9, '2025-02-13', 'Introduced in Senate', '<p><strong>First Rhode Island Regiment Congressional Gold Medal Act</strong></p> <p>This bill provides for the award of a single Congressional Gold Medal to the First Rhode Island Regiment, collectively, in recognition of their dedicated service during the Revolutionary War.</p>', '2025-05-08T19:06:02Z', '00', 101);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (10, '2025-01-13', 'Introduced in House', '<p><strong>Disabled Veterans Tax Termination Act</strong></p> <p>This bill modifies provisions related to military retired pay. Specifically, the bill authorizes veterans with a service-connected disability of less than 50% to concurrently receive both retired pay and disability compensation. The bill also makes qualified disability retirees with less than 20 years of retirement-creditable service eligible for concurrent receipt, subject to specified reductions in retired pay.</p>', '2025-02-14T21:59:06Z', '00', 106);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (11, '2025-01-28', 'Introduced in House', '<p><strong>Veterans'' Assuring Critical Care Expansions to Support&nbsp;Servicemembers Act of 2025 or the Veterans'' ACCESS Act of 2025</strong></p><p>This bill addresses the administration of the Veterans Community Care Program (VCCP) and other Department of Veterans Affairs (VA) health care matters.</p><p>Among other provisions regarding the VCCP, the bill</p><ul><li>establishes in statute access standards that determine when a veteran is eligible to receive non-VA care through the VCCP,</li><li>requires the VA to notify veterans regarding their eligibility for care within two business days after the VA is aware the veteran is seeking care, and</li><li>extends the deadline for the submittal of claims under the&nbsp;VCCP by health care entities and providers.</li></ul><p>The VA must address its mental health treatment programs by</p><ul><li>establishing a standardized screening process to determine whether a veteran satisfies criteria for priority or routine admission to a mental health residential rehabilitation treatment program or a program for residential care for mental health and substance abuse disorders,</li><li>tracking the performance of medical facilities and Veterans Integrated Service Networks in meeting the requirements for mental health treatment screenings and timely admission to treatment programs under such screenings, and</li><li>establishing an appeal process for when a veteran is denied admission to a covered treatment program or is accepted into a program but not offered bed placement in a timely manner.</li></ul><p>Additionally, the VA must establish an online self-service module for veterans to request and manage appointments, track referrals, and appeal and track decisions related to requests for care.</p>', '2025-12-30T18:20:15Z', '00', 118);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (12, '2025-01-31', 'Introduced in House', '<p><strong>Drug Cartel Terrorist Designation Act</strong></p><p>This bill directs the Department of State to designate four specified drug cartels as foreign terrorist organizations. (Among other things, such a designation allows the Department of the Treasury to require U.S. financial institutions to block transactions involving the organization.)</p><p>The four specified cartels in the bill are the Gulf Cartel, the Cartel Del Noreste, the Cartel de Sinaloa, and the Cartel de Jalisco Nueva Generacion.</p><p>The bill also requires the State Department to submit a detailed report on those four cartels and any other cartels it may identify. Based on this report, the State Department must designate as a foreign terrorist organization any such identified cartel (or faction thereof) that meets certain criteria for designation as a foreign terrorist organization.</p><p>The bill specifies that it may not be construed to expand eligibility for asylum.</p>', '2025-03-17T20:52:12Z', '00', 131);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (13, '2025-01-24', 'Introduced in House', '<p><strong>Life at Conception Act </strong> </p> <p>This bill declares that the right to life guaranteed by the Constitution is vested in each human being at all stages of life, including the moment of fertilization, cloning, or other moment at which an individual comes into being. </p> <p>Nothing in this bill shall be construed to authorize the prosecution of any woman for the death of her unborn child. </p>', '2025-05-28T17:41:17Z', '00', 132);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (14, '2025-02-20', 'Introduced in Senate', '<p><strong>North Platte Canteen Congressional Gold Medal Act</strong></p><p>This bill provides for the award of a Congressional Gold Medal to recognize the individuals and communities that provided financial and other support for the North Platte Canteen in North Platte, Nebraska, during World War II.</p>', '2025-08-06T19:35:21Z', '00', 153);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (15, '2025-04-08', 'Introduced in House', '<p><strong>Nuclear Family Priority Act</strong></p><p>This bill imposes limits on various types of family-sponsored immigration visas.</p><p>The&nbsp;non-U.S. national&nbsp;(<em>alien</em>&nbsp;under federal law) parents of U.S. citizens&nbsp;shall not qualify for visas for&nbsp;immediate relatives, which are not subject to any direct numerical limits. Currently, the spouses, unmarried children under 21, and parents of citizens are considered immediate relatives.</p><p>The bill also creates a nonimmigrant visa for such parents of citizens. Such non-U.S. nationals shall not be eligible for employment or any public benefits.</p><p>The bill also reduces the baseline annual cap for family-sponsored visas from 480,000 to 88,000, and revises the methods for calculating the cap. Currently, the 480,000 cap may be adjusted depending on various factors but shall not be less than 226,000.</p><p>The bill eliminates preference allocations (visa categories subject to various annual caps) for various family-sponsored visas, including those for the siblings and married children of citizens. The bill provides for a preference allocation for the unmarried children under 21 and spouses of permanent residents, subject to the 88,000 annual cap.</p>', '2026-02-24T14:39:53Z', '00', 161);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (16, '2025-02-12', 'Introduced in House', '<p><strong>Investing in Rural America Act of 2025</strong></p><p>This bill allows Farm Credit System (FCS) institutions to make and participate in loans and commitments (and extend other technical and financial assistance) for essential community facility&nbsp;projects as part of the Department of Agriculture''s&nbsp;Community Facilities Direct Loan &amp; Grant Program. This program provides funding to develop essential community facilities in rural areas.</p><p>The&nbsp;FCS financing and technical assistance&nbsp;may be provided in order to make capital available to develop, build, maintain, improve, or provide related equipment or&nbsp;other support for essential community facilities in rural communities (e.g., certain facilities that provide healthcare, community support, public safety, educational, or utility services).</p><p>Under the bill, the&nbsp;financing provided by an FCS institution may not&nbsp;exceed 15% of the total of all outstanding loans of the institution.&nbsp;Further, an FCS institution must (1) offer at least one non-FCS lending institution an interest in the financing under reasonable terms and conditions acceptable to the borrower, and (2) report the offer to the&nbsp;Farm Credit Administration (FCA).</p><p>The FCA must submit an annual report to Congress on the activities undertaken by FCS institutions under this bill, including through the partnerships between FCS institutions and other lending institutions. The FCA must post the report on the administration''s website.</p>', '2025-05-14T13:35:00Z', '00', 162);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (17, '2025-01-09', 'Introduced in House', '<p><strong>Legal Workforce Act</strong></p><p>This bill directs the Department of Homeland Security (DHS) to create an electronic employment eligibility confirmation system modeled after and to replace the E-Verify system, which allows employers and recruiters to verify the immigration status of individuals. The bill also mandates the use of such a system, where currently only some employers, such as those with federal contracts, are required to use E-Verify.</p><p>The bill specifies documents that can establish an individual''s identity and employment authorization. During the period starting when a job offer is made until three business days after hiring, the individual must attest to his or her employment authorization, and the employer or recruiter must attest that it has examined the individual''s required documents.</p><p>Employers shall reverify certain types of employees who were not previously verified using E-Verify.</p><p>The Social Security Administration shall notify employees if their Social Security number has been used multiple times in an unusual manner. DHS shall establish programs for blocking and suspending misused numbers.</p><p>Employers that are required to use the verification system shall not be liable for any employment-related action based on a good-faith reliance on the system.</p><p>The bill establishes a phased-in participation deadline for different sizes and categories of employers, including agricultural employers.</p><p>The bill increases civil penalties related to hiring individuals without work authorization. It also preempts state laws relating to hiring and employment eligibility verification, but states may use their authority of business licensing to penalize employers for failing to comply with the bill''s provisions.</p>', '2025-03-06T15:21:00Z', '00', 163);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (18, '2025-03-11', 'Introduced in House', '<p><strong>Metastatic Breast Cancer Access to Care Act</strong></p> <p>This bill expedites payment of Social Security Disability Insurance (SSDI) benefits and eligibility for Medicare coverage for those with metastatic breast cancer (i.e., breast cancer that has spread to other sites in the body).</p> <p>Specifically, the bill eliminates the 5-month waiting period for SSDI benefits and the subsequent 24-month waiting period for Medicare coverage for individuals with metastatic breast cancer. Under current law, individuals generally must wait 5 months after the onset of disability to begin receiving SSDI benefits and an additional 24 months to become eligible for Medicare.</p>', '2025-09-02T20:31:04Z', '00', 172);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (19, '2025-02-26', 'Introduced in Senate', '<p><strong>Farm and Food Cybersecurity Act of 2025</strong></p><p>This bill directs the Department of Agriculture (USDA) to (1) assess&nbsp;cybersecurity threats in the agriculture and food&nbsp;critical infrastructure&nbsp;sector, and (2) conduct annual crisis simulation exercises for food-related emergencies or disruptions. The agriculture and food&nbsp;critical infrastructure&nbsp;sector&nbsp;includes (1) any activity relating to the production, processing,&nbsp;distribution, storage, transportation, consumption, or disposal of agricultural or food products; and (2) any entity involved in any of these activities.</p><p>Specifically, USDA, in coordination with the Department of Homeland Security (DHS)&nbsp;Cybersecurity and Infrastructure Security Agency, must conduct a risk assessment every two years on the&nbsp;cybersecurity threats to, and security vulnerabilities in, this sector. The risk assessment must include any recommendations for federal legislative or administrative actions to address related threats and vulnerabilities.</p><p>USDA must also conduct an annual simulation exercise relating to a food-related emergency or disruption in coordination with&nbsp;DHS, the Department of Health and Human Services (HHS), and the Office of the Director of National Intelligence (ODNI).</p><p>Among other things, the exercise must (1) involve a realistic and plausible scenario that simulates a food-related emergency or disruption that affects multiple sectors and jurisdictions, and (2) incorporate input from experts and stakeholders from various disciplines and sectors (e.g., agriculture, public health, emergency management, transportation, and energy).&nbsp;</p><p>USDA, in consultation with DHS, HHS, and ODNI, must submit a report to Congress on each simulation exercise, including recommendations to enhance the&nbsp;cybersecurity and resilience of the agriculture and food critical infrastructure sector.</p>', '2025-06-09T17:57:10Z', '00', 176);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (20, '2025-01-23', 'Introduced in Senate', '<p><b>Protecting Individuals with Down Syndrome Act</b></p> <p> This bill creates new federal crimes related to the performance of an abortion on an unborn child who has Down syndrome.</p> <p>It subjects a violator to criminal penalties—a fine, a prison term of up to five years, or both.</p> <p>It also authorizes civil remedies, including damages and injunctive relief.</p> <p>A woman who undergoes such an abortion may not be prosecuted or held civilly liable.</p>', '2025-03-17T22:04:37Z', '00', 177);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (21, '2026-03-04', 'Introduced in House', 'This bill designates the facility of the United States Postal Service located at 201 East Grant Avenue in Georgetown, Ohio, as the "Ulysses S. Grant Post Office Building".', '2026-03-05T09:19:05Z', '00', 199);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (22, '2025-02-27', 'Introduced in House', '<p><strong>Amplifying Processing of Livestock in the United States Act or the A–PLUS Act</strong></p><p>This bill directs the Department of Agriculture&nbsp;(USDA) to revise its regulations to allow certain packers to hold an ownership interest in, finance, or participate in the management or operation of a market agency selling livestock on a commission basis.</p><p>The bill applies to packers that have a cumulative slaughter capacity of (1) less than 2,000 animals per day or 700,000 animals per year with respect to cattle or sheep, and (2) less than 10,000 animals per day or 3 million animals per year with respect to hogs.</p><p>In addition,&nbsp;USDA must revise its regulations to&nbsp;include a disclosure requirement for a market agency that has an ownership interest in, finances, or participates in the management or operation of a packer. Specifically, the market agency must disclose the existence of such ownership interest, financial relationship, or participation.</p>', '2025-05-09T13:52:35Z', '00', 207);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (23, '2025-12-04', 'Introduced in House', '<p><strong>Right to Read Act of 2025</strong></p><p>This bill expands access to school libraries and literacy skills support for elementary and secondary school students. It also outlines certain constitutional rights and liability protections related to school libraries.</p><p>Specifically, the bill reauthorizes through FY2030 (1) the Comprehensive Literacy State Development Program, which provides grants to ensure high-quality instruction and effective strategies in reading and writing for children through 12th grade; and (2) the Innovative Approaches to Literacy Program, which provides grants to support the development of literacy skills in low-income communities.</p><p>Additionally, the bill allows Supporting Effective Instruction State Grants to be used to assist local educational agencies (LEAs) and schools in recruiting, hiring, and retaining state-certified school librarians.</p><p>Further, the bill authorizes states and LEAs to use Student Support and Academic Enrichment grants for programs and activities that promote the development of digital literacy and information literacy skills.</p><p>The Department of Education (ED) must direct the National Center for Education Statistics to biennially collect data on school libraries.</p><p>ED must require an assurance from each state and LEA receiving certain funds confirming that it will (1) protect the First Amendment rights of students in school libraries, and (2) provide equal protection in the conduct of school libraries in compliance with the requirements of the Fourteenth Amendment and nondiscrimination laws.</p><p>The bill also provides liability protection to teachers, school librarians, school leaders, paraprofessionals, and other staff for actions that conform with state or local policies regarding the right to read.</p>', '2026-03-05T20:08:20Z', '00', 219);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (24, '2025-03-25', 'Introduced in House', '<p><strong>Fairness for High-Skilled Americans Act of 2025 </strong></p><p>This bill eliminates the Optional Practical Training Program or any successor program, unless Congress expressly authorizes such a program. (The program provides an F-1 student visa holder temporary employment authorization before or after completion of the student''s studies, or both.)</p>', '2025-04-07T21:32:08Z', '00', 232);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (25, '2025-02-12', 'Introduced in House', '<p><strong>Security And Fairness Enhancement for America Act of 2025 or SAFE for America Act of 2025</strong></p><p>This bill eliminates the diversity visa program. This program provides up to 55,000 visas annually to individuals from countries with low rates of immigration to the United States.&nbsp;</p>', '2026-03-04T01:39:43Z', '00', 233);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (26, '2025-01-03', 'Introduced in House', '<p><strong> Stopping Border Surges Act </strong></p><p>This bill modifies immigration law provisions relating to unaccompanied alien minors and to asylum seekers.</p><p>The bill requires the Department of Homeland Security (DHS) to repatriate certain unaccompanied, inadmissible alien children, generally those not at risk of being trafficking victims nor having a fear of persecution. Currently, only inadmissible unaccompanied aliens from neighboring countries are subject to repatriation, and DHS has discretion whether to repatriate.</p><p>When the Department of Health and Human Services releases an unaccompanied child to an individual, it shall provide DHS with certain information about that individual, including Social Security number and immigration status.</p><p>The bill requires a stricter standard to find a credible fear of persecution and imposes additional rules on credible fear interviews.</p><p>If an alien is granted asylum because of fear of persecution in a country, the alien shall be deemed to have renounced asylum status by returning to that country, if there has been no change in the country''s conditions.</p><p>The bill also (1) expands the definition of what constitutes a frivolous asylum application, (2) imposes additional limitations on eligibility for asylum, (3) shortens the deadline for applying for asylum, and (4) extends the time period an alien seeking asylum must wait before receiving employment authorization.</p><p>Any individual who knowingly and willfully makes materially false statements or uses fraudulent documents in asylum-related proceedings shall be fined or imprisoned up to 10 years, or both.</p>', '2025-02-26T01:34:29Z', '00', 234);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (27, '2025-10-08', 'Introduced in House', '<p><b>Federal Employees Civil Relief Act</b></p> <p>This bill establishes a framework to temporarily suspend certain judicial and administrative proceedings against a federal employee or contractor during a shutdown. </p> <p>Under the bill, a <i>shutdown </i>is a period in which (1) there is more than a 24-hour lapse in appropriations for any federal agency or department because a regular appropriations bill or a continuing resolution has not been enacted, or (2) the debt of the federal government is greater than the statutory limit. </p> <p>A federal worker (i.e., an employee of a government agency or contractor) who is furloughed or required to work without pay during a shutdown may apply to a court for a temporary stay, postponement, or suspension with respect to any payment of rent, mortgage, tax, fine, penalty, insurance premium, student loan repayment, or other civil obligation or liability that the worker owes or would owe during the duration of the shutdown.</p> <p>The bill includes related provisions that restrict evictions, foreclosures, the enforcement of liens, and the termination of insurance policies during a shutdown. It also provides for the deferral of federal income taxes and student loan payments during a shutdown. </p> <p>The Department of Justice may commence a civil action against any person who engages in (1) a pattern or practice of violating the requirements of this bill, or (2) a violation that raises an issue of significant public importance. A person aggrieved by a violation of this bill''s requirements may also bring a private right of action.</p>', '2025-10-17T14:49:02Z', '00', 254);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (28, '2026-01-15', 'Introduced in House', '<p>This bill designates a portion of Interstate Route 680 in Omaha, Nebraska, as the&nbsp;Hal Daub Freeway.</p><p>Harold John Daub Jr. served in the House of Representatives from 1981-1989 and as the mayor of Omaha, Nebraska, from 1995-2001.</p>', '2026-03-12T13:08:38Z', '00', 261);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (29, '2025-05-01', 'Introduced in Senate', '<p><strong>Living Donor Protection Act of </strong><strong>2025</strong></p><p>This bill prohibits life insurance, disability insurance, and long-term insurance&nbsp;carriers from denying or otherwise restricting coverage for&nbsp;living organ donors.</p><p>Specifically, carriers may not deny, cancel, vary premiums, or otherwise impose conditions on policies based on an individual''s status as a living organ donor.</p><p>The bill also expressly specifies that recovery from organ-donation surgery constitutes a serious health condition that entitles eligible employees to job-protected medical leave.</p><p>In addition, the Department of Health and Human Services must update educational materials on living organ donation to include information about the benefits and risks of living organ donation and the impact of donation on insurance access, particularly with respect to the bill''s changes.</p>', '2026-02-26T23:06:33Z', '00', 272);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (30, '2026-02-26', 'Passed Senate', '<p>This resolution supports the designation of February 21-28, 2026, as National FFA (Future Farmers of America) Week.</p><p>It also celebrates the 50th anniversary of the chartering of Alaska as a State FFA Association of the National FFA Organization.</p>', '2026-03-14T19:51:14Z', '55', 273);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (31, '2025-01-09', 'Introduced in House', '<p><strong>National Law Enforcement Officers Remembrance, Support and Community Outreach Act. [<em>sic</em>]</strong></p><p>This&nbsp;bill temporarily&nbsp;directs the Department of the Interior&nbsp;to award a grant to the National Law Enforcement Officers Memorial Fund for the expenses associated with operating and enhancing the community outreach, public education, and officer safety and wellness programs of the National Law Enforcement Museum.</p>', '2025-04-22T20:05:15Z', '00', 290);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (32, '2025-01-22', 'Introduced in House', '<p><strong>Supporting Accurate Views of Emergency Services Act of 2025 or the 911 SAVES Act</strong></p><p>This bill requires the Office of Management and Budget to categorize public safety telecommunicators as a protective service occupation under the Standard Occupational Classification system no later than 30 days after the enactment of this bill. (The Standard Occupational Classification system is a federal statistical standard used by federal agencies to classify workers into occupational categories for the purpose of collecting, calculating, or disseminating data.)</p>', '2025-02-27T14:39:34Z', '00', 291);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (33, '2026-01-09', 'Introduced in House', '<p>This joint resolution proposes a constitutional amendment prohibiting total federal expenditures for a year from exceeding the average annual federal receipts collected in the three prior years, adjusted for changes in the population of U.S. citizens and inflation. Expenditures for payment of debt and receipts derived from borrowing are excluded.</p><p>Under the amendment, Congress may authorize specific expenditures in excess of the limit with (1) a roll call vote of two-thirds of each chamber, or (2) a roll call vote for any year in which a declaration of war is in effect.</p><p>The amendment also prohibits any bill to levy a new tax or increase the rate of any tax from becoming law unless it has been approved by a roll call vote of two-thirds of the whole number of each chamber of Congress.</p><p>The requirements take effect in the fifth year beginning after ratification of the amendment.</p>', '2026-02-26T16:02:11Z', '00', 293);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (34, '2026-02-25', 'Reported to House', '<p>This joint resolution proposes a constitutional amendment prohibiting total federal expenditures for a year from exceeding the average annual federal receipts collected in the three prior years, adjusted for changes in the population of U.S. citizens and inflation. Expenditures for payment of debt and receipts derived from borrowing are excluded.</p><p>Under the amendment, Congress may authorize specific expenditures in excess of the limit with (1) a roll call vote of two-thirds of each chamber, or (2) a roll call vote for any year in which a declaration of war is in effect.</p><p>The amendment also prohibits any bill to levy a new tax or increase the rate of any tax from becoming law unless it has been approved by a roll call vote of two-thirds of the whole number of each chamber of Congress.</p><p>The requirements take effect in the fifth year beginning after ratification of the amendment.</p>', '2026-02-26T15:58:14Z', '07', 293);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (35, '2025-12-16', 'Introduced in House', '<p><strong>Coercion and Sexual Abuse Free Environment Act of 2025 or the CSAFE Act of 2025</strong></p><p>This bill establishes a new federal criminal offense for compelling a minor to engage in certain acts: animal crushing, self-harm, obscene speech, sexually explicit conduct, or abusive or degrading nonsexual conduct.</p><p>An offense, or an attempt or conspiracy to commit an offense, is punishable by a fine, prison term, or both.&nbsp;</p><p>Additionally, in the case of an offense committed by a minor who is at least 13 years of age, the bill allows the minor to be prosecuted as an adult in federal court if certain criteria are met (e.g., possession of a firearm during the offense).&nbsp;</p>', '2026-01-08T18:25:16Z', '00', 295);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (36, '2026-01-13', 'Introduced in House', '<p><strong>Hemp Planting Predictability Act</strong></p><p>This bill extends by two years the implementation of changes to the regulation of hemp products, which&nbsp;reimpose certain&nbsp;federal controls over some hemp products.</p><p>Specifically,&nbsp;Congress enacted the FY2026 agriculture appropriations act (P.L. 119-37) on November 12, 2025. Effective November 12, 2026, the act modifies the statutory definition of hemp products that are considered to be lawful. This bill extends the effective date to November 12, 2028.</p><p>As background, the 2018 farm bill excluded hemp from the Controlled Substances Act definition of marijuana and defined <em>hemp</em>. As a result, hemp and hemp-derived products at or below the 0.3% delta-9 tetrahydrocannabinol (THC, the psychoactive component of marijuana) concentration threshold were no longer regulated as Schedule I controlled substances and registration with the Drug Enforcement Administration was no longer required to cultivate or handle hemp and hemp-derived products. However, hemp remained subject to Department of Agriculture and Food and Drug Administration regulation.</p><p>The 2025&nbsp;changes to the definition of hemp, include</p><ul><li>changing the limit to a total THC concentration of not more than 0.3% on a dry weight basis rather than only delta-9 THC,</li><li>explicitly including industrial hemp,</li><li>excluding seeds from a cannabis plant that exceed a certain THC concentration, and</li><li>excluding various types of hemp-derived&nbsp;cannabinoid products.</li></ul><p><em>Cannabinoids</em> refer to unique chemical compounds that are found in hemp and marijuana (e.g., THC) and are known to exhibit a range of psychological and physiological effects.</p>', '2026-02-24T15:19:31Z', '00', 322);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (37, '2026-01-12', 'Introduced in House', '<p><strong></strong>This bill extends by two years the implementation of changes to the regulation of hemp products, which&nbsp;reimpose certain&nbsp;federal controls over some hemp products.</p><p>Specifically,&nbsp;Congress enacted the FY2026 agriculture appropriations act (P.L. 119-37) on November 12, 2025. Effective November 12, 2026, the act modifies the statutory definition of hemp products that are considered to be lawful. This bill extends the effective date to November 12, 2028.</p><p>As background, the 2018 farm bill excluded hemp from the Controlled Substances Act definition of marijuana and defined <em>hemp</em>. As a result, hemp and hemp-derived products at or below the 0.3% delta-9 tetrahydrocannabinol (THC, the psychoactive component of marijuana) concentration threshold were no longer regulated as Schedule I controlled substances and registration with the Drug Enforcement Administration was no longer required to cultivate or handle hemp and hemp-derived products. However, hemp remained subject to Department of Agriculture and Food and Drug Administration regulation.</p><p>The 2025&nbsp;changes to the definition of hemp, include</p><ul><li>changing the limit to a total THC concentration of not more than 0.3% on a dry weight basis rather than only delta-9 THC,</li><li>explicitly including industrial hemp,</li><li>excluding seeds from a cannabis plant that exceed a certain THC concentration, and</li><li>excluding various types of hemp-derived&nbsp;cannabinoid products.</li></ul><p><em>Cannabinoids</em> refer to unique chemical compounds that are found in hemp and marijuana (e.g., THC) and are known to exhibit a range of psychological and physiological effects.</p>', '2026-02-24T16:02:11Z', '00', 323);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (38, '2025-09-18', 'Introduced in House', '<p><strong>Strengthening Agency Management and Oversight of Software Assets Act</strong></p><p>This bill requires federal agencies and Intelligence Community (IC) elements to assess their software inventory and develop software management plans.</p><p>The bill requires each agency and each IC element to complete a comprehensive assessment of the software paid for by, in use at, or deployed throughout the agency or element. The assessment must include information such as (1) the current inventory of software; (2) contracts and other arrangements used to acquire, build, deploy, or use the software; (3) costs and fees not included in the initial contract or agreement; and (4) the interoperability of the software and restrictions on its use.</p><p>Each agency and IC element must use their assessment to develop a plan to consolidate software entitlements, develop procedures for cost-effective acquisition strategies, and restrict subordinate entities from using any software entitlement without approval.&nbsp;(A software entitlement is software that has been purchased, leased, or licensed by or billed to an agency and that is subject to use limitations.)&nbsp;Such plans must be submitted to&nbsp;the Office of Management and Budget (OMB) and Congress.&nbsp;</p><p>Within two years of enactment, OMB must submit recommendations to Congress regarding government software procurement policies and practices to</p><p>&nbsp; &nbsp; • increase the interoperability of software licenses;<br/>&nbsp; &nbsp; • consolidate licenses when appropriate;<br/>&nbsp; &nbsp; • reduce costs;<br/>&nbsp; &nbsp; • improve performance; and<br/>&nbsp; &nbsp; • modernize the management and oversight of agency software.<br/>&nbsp; &nbsp;&nbsp;<br/>The GAO must report on certain related topics, including governmentwide trends in agency software asset management practices and comparisons of such practices among agencies.</p>', '2025-12-13T01:47:01Z', '00', 339);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (39, '2025-02-06', 'Introduced in House', '<p><b>Respect State Housing Laws Act</b></p> <p>This bill eliminates a provision that requires a 30-day notice period before a landlord may begin eviction proceedings against a tenant in federally assisted or federally backed housing.</p>', '2025-09-05T14:28:58Z', '00', 347);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (40, '2026-02-09', 'Introduced in Senate', '<p><strong>Fighting Trade Cheats Act of 2026</strong></p><p>This bill increases penalties for, and establishes additional enforcement mechanisms related to, fraudulent and grossly negligent violations of U.S. customs laws.</p><p>Specifically, the bill increases the maximum civil penalty for a fraudulent violation to three times the domestic value of the merchandise. (Currently, the maximum penalty is the domestic value of the merchandise.) It prohibits a person who commits a fraudulent violation from importing merchandise into the United States for a five-year period.</p><p>Additionally, the bill increases the maximum civil penalty for a grossly negligent violation to the lesser of (1) 3 times the domestic value of the merchandise; or (2) 10 times the lawful duties, taxes, and fees. (Currently, the maximum penalty is the lesser of the domestic value of the merchandise or four times the lawful duties, taxes, and fees.) It prohibits a person who commits a grossly negligent violation from importing merchandise into the United States for a two-year period.</p><p>Further, the bill applies these importation bans to an affiliated person (e.g., a family member or employee) of the person who committed the fraudulent or grossly negligent violation.</p><p>The bill establishes a private right of action for an interested party (e.g., a manufacturer) affected by customs fraud or grossly negligent violations.</p><p>The bill prohibits any person (or an affiliated person) who commits a fraudulent or grossly negligent violation from participating in the U.S. Customs and Border Protection''s Importer of Record program, and further requires revocation of their importer of record numbers.</p>', '2026-02-27T15:55:15Z', '00', 374);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (41, '2025-01-14', 'Introduced in House', '<p><strong>Healthcare Freedom and Choice Act</strong></p><p>This bill nullifies a rule regarding short-term, limited-duration health insurance&nbsp;plans. The rule was promulgated by the Internal Revenue Service,&nbsp;Employee Benefits Security Administration, and Department of Health and Human Services; is titled&nbsp;<em>Short-Term, Limited-Duration Insurance and Independent, Noncoordinated Excepted Benefits Coverage</em>; and was published April 3, 2024.</p><p>Short-term, limited-duration health insurance plans are plans that may only offer coverage for a limited amount of time and are exempt from the market requirements of the Patient Protection and Affordable Care Act (e.g., coverage of individuals with preexisting conditions).</p><p>The rule limits the length of the initial contract period for such a plan to no more than three months and, taking into account any renewals or extensions, the maximum coverage period to no more than four months. The rule also includes within the maximum renewal period limitation a new plan sold by the same issuer, or any issuer that is a member of the same controlled group, to the same policyholder within a 12-month period.</p><p>Regulations in effect prior to the rule this bill nullifies permitted short-term, limited-duration health insurance plans with an initial contract period of fewer than 12 months and a maximum coverage period of up to 36 months, including renewals and extensions.</p>', '2025-03-24T20:09:41Z', '00', 387);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (42, '2025-06-27', 'Introduced in House', '<p><strong>FMS-Only List Review Act</strong></p><p>This bill requires the Department of State to conduct an annual review to identify defense articles and services eligible to be sold only through Foreign Military Sales (FMS) (i.e., U.S. government to foreign government sales) that should also be eligible to be sold through Direct Commercial Sales (DCS) (i.e., U.S. company to foreign government sales).</p><p>For each article or service identified, the review must address (1) the length of time to complete a transfer of the article or service through the FMS program as compared to the DCS process; (2) the impact of a transfer of the article or service through the DCS process on the workload of the State Department and the Department of Defense; and (3) the benefits of the transfer of the article or service through the DCS process to U.S. national security and competitiveness. &nbsp;</p><p>Within 30 days of the completion of each annual review, the State Department must report to Congress on the results of the review.</p>', '2025-09-02T14:20:21Z', '00', 416);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (43, '2026-02-11', 'Introduced in House', 'This bill designates the facility of the United States Postal Service located at 10 East Main Street in Mahaffey, Pennsylvania, as the "Robert Allen Bishop, Sr. Post Office Building".', '2026-02-23T13:20:28Z', '00', 430);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (44, '2025-03-14', 'Introduced in House', '<p><strong>Homes for Every Local Protector, Educator, and Responder Act of 2025 or the HELPER Act of 2025</strong></p><p>This bill establishes a program administered by the Department of Housing and Urban Development to provide mortgage assistance to law enforcement officers, elementary and secondary school teachers, firefighters, or other first responders. Specifically, these individuals may be eligible for a first-time mortgage on a primary family residence with no down payment. Instead, the mortgage is subject to a one-time, up-front mortgage insurance premium.</p>', '2026-01-15T23:02:47Z', '00', 432);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (45, '2025-02-04', 'Introduced in House', '<p><strong>Railway Safety Act of 2025</strong></p><p>This bill addresses safety requirements for rail carriers and trains transporting hazardous materials.</p><p>Specifically, the Department of Transportation (DOT) must issue safety regulations for trains carrying hazardous materials to require that rail carriers or shippers (1) provide state emergency response commissioners with advance notice and information about the hazardous materials; (2) reduce blocked rail crossings; and (3) comply with certain requirements regarding train length and weight specifications, track standards, speed restrictions, and response plans.</p><p>DOT must also establish requirements for wayside defect detectors. These are used by railway systems alongside the tracks to detect defects and failures (e.g., wheel bearing failures). Current federal regulations do not require their use, but federal guidance does address their placement and use. Under the bill, DOT must issue regulations establishing requirements for the installation, repair, testing, maintenance, and operation of wayside defect detectors for each rail carrier operating a train carrying hazardous materials.</p><p>The bill also</p><ul><li>increases the maximum fines DOT may impose on rail carriers for violating safety regulations;</li><li>requires DOT to update rail car inspection regulations and audit the federal inspection programs;</li><li>establishes a statutory requirement&nbsp;for freight trains to have at least two crew&nbsp;members, with exceptions;</li><li>phases out certain railroad tank cars by May 1, 2027;</li><li>expands training for local first responders;</li><li>imposes a new fee on certain rail carriers; and</li><li>authorizes grants to improve railway safety.</li></ul>', '2025-06-18T19:06:40Z', '00', 433);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (46, '2025-07-23', 'Introduced in House', '<p><strong>Bill to Outlaw Wounding of Official Working Animals Act or the BOWOW Act</strong></p><p>This bill establishes that a&nbsp;non-U.S. national (<em>alien</em> under federal law) convicted of, or who admits to having committed, an offense related to harming animals used in law enforcement is inadmissible and deportable.</p>', '2026-02-27T19:58:49Z', '00', 435);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (47, '2023-11-06', 'Introduced in House', 'Designates the facility of the United States Postal Service located at 250 Edward Street in Branchville, South Carolina, as the "Betty W. Henderson Post Office Building."', '2023-11-07T09:02:32Z', '00', 451);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (48, '2026-02-11', 'Introduced in House', '<p><strong>Department of Homeland Security Appropriations Act, 2026</strong></p><p>This bill provides FY2026 appropriations for various agencies and offices within the Department of Homeland Security (DHS), except for U.S. Immigration and Customs Enforcement (ICE), U.S. Customs and Border Protection (CBP), and management and oversight activities of the Office of the Secretary.</p><p>Specifically, the bill provides appropriations to DHS for&nbsp;</p><ul><li>the Federal Protective Service,</li><li>the Office of Inspector General,</li><li>the Transportation Security Administration,</li><li>the U.S. Coast Guard,</li><li>the U.S. Secret Service,</li><li>the Cybersecurity and Infrastructure Security Agency,</li><li>the Federal Emergency Management Agency (FEMA),</li><li>U.S. Citizenship and Immigration Services,</li><li>the Federal Law Enforcement Training Centers, and</li><li>the Science and Technology Directorate.</li></ul><p>The bill does not provide appropriations for some agencies and activities that have been funded in prior DHS appropriations acts, including ICE, CBP, and management and oversight activities of the&nbsp;Office of the Secretary.</p>', '2026-02-24T18:00:10Z', '00', 452);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (49, '2025-02-18', 'Introduced in House', '<p><strong>Enhanced Iran Sanctions Act of 2025</strong></p><p>This bill imposes sanctions on certain foreign persons (individuals and entities) that are involved in Iran''s petroleum sector as well as certain associated persons. The bill also requires or authorizes actions to facilitate the enforcement of sanctions on Iran.</p><p>Specifically, the bill requires the President to impose visa- and property-blocking sanctions on any foreign person that, after the bill''s enactment, knowingly engages in any transaction related to the processing, export, or sale of oil, condensates, gas, liquefied natural gas, or other petrochemical products in whole or in part from Iran. The President must also impose sanctions on certain foreign persons associated with a sanctioned individual or entity. For example, the President must sanction the subsidiaries and corporate officers of a sanctioned business.</p><p>The bill provides certain exceptions to these sanctions, including specifying that sanctions do not apply to the importation of goods or to conducting or facilitating transactions for humanitarian assistance.</p><p>The Department of State must establish an interagency working group that shall seek to establish a multilateral contact group to coordinate international efforts to enforce sanctions on Iran.</p><p>The bill expands the State Department rewards program to authorize a reward payment to any individual who furnishes information leading to the identification of a person (1) subject to sanctions under this bill, or (2) that has attempted or is attempting to evade sanctions under this bill.</p>', '2026-03-13T01:35:12Z', '00', 467);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (50, '2025-07-29', 'Introduced in Senate', '<p><strong>Protecting Air Ambulance Services for Americans Act of 2025</strong></p><p>This bill authorizes payment changes under Medicare for air ambulance services based on certain collected data and requires additional reporting from providers of these services.</p><p>Current law requires providers of air ambulance services to report certain information regarding general costs and utilization to the Department of Health and Human Services; private health insurers are also required to report information relating to coverage of these services. The bill authorizes the Centers for Medicare &amp; Medicaid Services to revise payment rates under Medicare for air ambulance services based on this data, and it requires providers of air ambulance services to specifically report information relating to costs and utilization under Medicare.</p><p>The bill also requires the Government Accountability Office to report on the data that is collected under current law requirements and to recommend changes to Medicare payment rates accordingly.</p>', '2025-12-02T16:48:00Z', '00', 470);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (51, '2025-06-12', 'Introduced in House', '<p><strong>Military Construction, Veterans Affairs, and Related Agencies Appropriations Act, 2026</strong></p><p>This bill provides FY2026 appropriations for military construction, the Department of Veterans Affairs (VA), and related agencies.</p><p>The bill provides appropriations to the Department of Defense (DOD) for military construction for</p><ul><li>the Army;</li><li>the Navy and Marine Corps;</li><li>the Air Force;</li><li>Defense-wide agencies and activities;</li><li>the Army and Air National Guard; and</li><li>the Army, Navy, and Air Force Reserves.</li></ul><p>The bill also provides appropriations to DOD for</p><ul><li>the North Atlantic Treaty Organization (NATO) Security Investment Program;</li><li>the Base Closure Account;</li><li>Construction and Operation and Maintenance of Family Housing for the Army, the Navy and Marine Corps, the Air Force, and Defense-wide agencies and activities;</li><li>the Family Housing Improvement Fund; and</li><li>the Military Unaccompanied Housing Improvement Fund.</li></ul><p>Within the VA budget, the bill provides appropriations for</p><ul><li>the Veterans Benefits Administration,</li><li>the Veterans Health Administration,</li><li>the National Cemetery Administration, and</li><li>Departmental Administration.</li></ul><p>The bill provides appropriations for related agencies and programs, including</p><ul><li>the American Battle Monuments Commission,</li><li>the U.S. Court of Appeals for Veterans Claims,</li><li>Cemeterial Expenses of the Army, and</li><li>the Armed Forces Retirement Home.</li></ul><p>The bill also sets forth requirements and restrictions for using funds provided by this and other appropriations acts.&nbsp;</p>', '2025-06-16T15:17:11Z', '00', 472);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (52, '2025-08-01', 'Passed Senate', '<p><strong>Military Construction and Veterans Affairs, Agriculture, and Legislative Branch Appropriations Act, 2026</strong></p><p>This bill provides FY2026 appropriations to several federal departments and agencies for activities and programs related to military construction, veterans, agriculture, and the legislative branch.</p><p>Specifically, the bill includes 3 of the 12 regular FY2026 appropriations bills:</p><ul><li>the Military Construction, Veterans Affairs, and Related Agencies Appropriations Act, 2026;</li><li>the Agriculture, Rural Development, Food and Drug Administration, and Related Agencies Appropriations Act, 2026; and</li><li>the Legislative Branch Appropriations Act, 2026.</li></ul><p>The departments, agencies, and activities funded in the bill include</p><ul><li>Department of Defense military construction and family housing activities,</li><li>the Department of Veterans Affairs,</li><li>the Department of Agriculture,</li><li>the Food and Drug Administration,</li><li>the Senate,</li><li>various agencies that support Congress, and</li><li>several related and independent agencies.</li></ul><p>(Pursuant to the longstanding practice of each chamber of Congress determining its own requirements, funds for the House of Representatives are not included in the Senate bill.)</p><p>The bill also sets forth requirements and restrictions for using funds provided by this and other appropriations acts.</p>', '2025-09-15T18:31:22Z', '55', 472);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (53, '2025-02-06', 'Introduced in House', '<p><strong>Amateur Radio Emergency Preparedness Act</strong></p><p>This bill limits the adoption and enforcement of private land use restrictions (e.g., rules of a homeowners'' association) that prohibit, restrict, or impair the installation, maintenance, or operation of an amateur station antenna on property controlled by an amateur radio operator.</p><p>Private land use restrictions are deemed to prohibit, restrict, or impair the installation, maintenance, or operation of an amateur station antenna if they unreasonably delay, prevent, or increase the cost or difficulty of such installation, maintenance, or operation; or if they prevent or degrade the reception or transmission of a signal acceptable to the operator.&nbsp;</p><p>However, the bill permits certain private land use restrictions, including restrictions that require amateur station antennas (1) to be maintained in a structurally safe condition; or (2) to be installed in compliance with manufacturer specifications, applicable zoning ordinances, amateur radio tower ordinances, and building codes.&nbsp;</p><p>The bill also establishes certain limits on the adoption and enforcement of private land use restrictions that require an amateur radio operator to obtain prior approval before installing an amateur station antenna, and exempts certain categories of amateur station antenna from prior approval requirements altogether.&nbsp;</p><p>Finally, the bill sets forth procedures for the enforcement of these provisions and provides a private right of action for individuals harmed by violations of the provisions.&nbsp;</p>', '2025-05-28T18:09:46Z', '00', 477);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (54, '2026-01-20', 'Introduced in House', '<p>This bill provides FY2026 appropriations for the Department of Homeland Security (DHS).</p><p>Specifically, the bill provides appropriations to DHS for Departmental Management, Intelligence, Situational Awareness, and Oversight, including</p><ul><li>the Office of the Secretary and Executive Management;</li><li>the Management Directorate;</li><li>Intelligence, Analysis, and Situational Awareness; and</li><li>the Office of Inspector General.</li></ul><p>In addition, the bill provides appropriations for Security, Enforcement, and Investigations, including</p><ul><li>U.S. Customs and Border Protection,</li><li>U.S. Immigration and Customs Enforcement,</li><li>the Transportation Security Administration,</li><li>the U.S. Coast Guard, and</li><li>the U.S. Secret Service.</li></ul><p>The bill provides appropriations for Protection, Preparedness, Response, and Recovery, including</p><ul><li>the Cybersecurity and Infrastructure Security Agency, and</li><li>the Federal Emergency Management Agency (FEMA).</li></ul><p>The bill provides appropriations for Research, Development, Training, and Services, including</p><ul><li>U.S. Citizenship and Immigration Services,</li><li>the Federal Law Enforcement Training Centers, and</li><li>the Science and Technology Directorate.</li></ul><p>The bill also sets forth requirements and restrictions for using funds provided by this and other appropriations acts.</p>', '2026-01-21T13:32:01Z', '00', 478);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (55, '2026-03-02', 'Introduced in House', '<p><strong>Department of Homeland Security Appropriations Act, 2026</strong></p><p>This bill provides appropriations to the Department of Homeland Security (DHS) for the remainder of FY2026. It also ends the partial DHS shutdown that began on February 14, 2026, because the continuing resolution (CR) that was funding DHS expired and a regular FY2026 DHS appropriations bill had not been enacted.&nbsp;</p><p>Specifically, the bill provides appropriations to DHS for Departmental Management, Intelligence, Situational Awareness, and Oversight, including</p><ul><li>the Office of the Secretary and Executive Management;</li><li>the Management Directorate;</li><li>Intelligence, Analysis, and Situational Awareness; and</li><li>the Office of Inspector General.</li></ul><p>In addition, the bill provides appropriations for Security, Enforcement, and Investigations, including</p><ul><li>U.S. Customs and Border Protection,</li><li>U.S. Immigration and Customs Enforcement,</li><li>the Transportation Security Administration,</li><li>the U.S. Coast Guard, and</li><li>the U.S. Secret Service.</li></ul><p>The bill provides appropriations for Protection, Preparedness, Response, and Recovery, including</p><ul><li>the Cybersecurity and Infrastructure Security Agency, and</li><li>the Federal Emergency Management Agency (FEMA).</li></ul><p>The bill provides appropriations for Research, Development, Training, and Services, including</p><ul><li>U.S. Citizenship and Immigration Services,</li><li>the Federal Law Enforcement Training Centers, and</li><li>the Science and Technology Directorate.</li></ul><p>The bill also authorizes back pay, in accordance with current law, for federal employees who were affected by the partial&nbsp;DHS shutdown.</p><p>Finally, the bill ratifies and&nbsp;approves certain obligations that were incurred during the partial DHS&nbsp;shutdown, including obligations incurred to maintain the essential level of activity to protect life and property and bring about an orderly termination of government functions.</p>', '2026-03-03T15:15:42Z', '00', 479);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (56, '2026-01-20', 'Introduced in House', '<p><strong>Consolidated Appropriations Act, 2026</strong></p><p>This bill provides FY2026 appropriations to several federal departments and agencies. It also extends various expiring programs and authorities.</p><p>Specifically, the bill includes 3 of the 12 regular FY2026 appropriations bills:</p><ul><li>the Department of Defense Appropriations Act, 2026;</li><li>the Departments of Labor, Health and Human Services, and Education, and Related Agencies Appropriations&nbsp;<br/>Act, 2026; and</li><li>the Transportation, Housing and&nbsp;Urban Development, and Related Agencies Appropriations Act.</li></ul><p>The departments and agencies funded in the bill include</p><ul><li>the&nbsp;Department of Defense,</li><li>the Department of Labor,</li><li>the Department of Health and Human Services,</li><li>the Department of Education,</li><li>the Department of Transportation,</li><li>the Department of Housing and Urban Development, and</li><li>related agencies.&nbsp;</li></ul><p>The bill also extends several expiring programs and authorities, including</p><ul><li>the U.S. Grain Standards Act;</li><li>the Commodity Futures Trading Commission’s whistleblower program;</li><li>the National Flood Insurance Program;</li><li>the Forest Service''s participation in the Agriculture Conservation Experienced Services Program;</li><li>the Transportation Security Administration’s&nbsp;Reimbursable Screening Services Program;</li><li>the Motor Carrier Safety Advisory Committee;</li><li>several authorities and programs related to cybersecurity;</li><li>the technology modernization fund and board;</li><li>the U.S. Parole Commission;</li><li>the special assessment on nonindigent persons or entities convicted of certain offenses involving sexual abuse or human trafficking;</li><li>several immigration-related programs and authorities;</li><li>the authority for the U.S. Sentencing Commission to promulgate certain guidelines or amendments related to the use of unmanned aircraft;&nbsp;</li><li>certain bankruptcy fees;</li><li>trade preferences for Haiti and countries in sub-Saharan Africa;</li><li>the Temporary Assistance for Needy Families (TANF) program; and</li><li>several health care authorities and programs.</li></ul>', '2026-01-28T20:14:38Z', '00', 482);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (57, '2026-02-03', 'House agreed to Senate amendment', '<p><strong>Consolidated Appropriations Act, 2026</strong></p><p>This bill provides appropriations to several federal departments and agencies for the remainder of FY2026 and provides continuing FY2026 appropriations for the Department of Homeland Security (DHS) through February 13, 2026. It also extends various expiring programs and authorities.</p><p>Specifically, the bill includes 5 of the 12 regular FY2026 appropriations bills:</p><ul><li>the Department of Defense Appropriations Act, 2026;</li><li>the Departments of Labor, Health and Human Services, and Education, and Related Agencies Appropriations&nbsp;Act, 2026;&nbsp;</li><li>the Transportation, Housing and Urban Development, and Related Agencies Appropriations Act, 2026;</li><li>the Financial Services and General Government Appropriations Act, 2026; and</li><li>the National Security, Department of State, and Related Programs Appropriations Act, 2026.</li></ul><p>The departments, agencies, and activities funded in the bill include</p><ul><li>the&nbsp;Department of Defense,</li><li>the Department of Labor,</li><li>the Department of Health and Human Services,</li><li>the Department of Education,</li><li>the Department of Transportation,</li><li>the Department of Housing and Urban Development,&nbsp;</li><li>the Department of the Treasury,</li><li>the Executive Office of the President,</li><li>the judiciary,</li><li>the District of Columbia,</li><li>the Department of State and related programs,</li><li>the administration and oversight of foreign assistance programs, &nbsp;</li><li>bilateral economic assistance,</li><li>international security assistance,</li><li>multilateral assistance,</li><li>export and investment assistance, and</li><li>several related and independent agencies.</li></ul><p>In addition, the bill includes a continuing resolution (CR) that provides continuing FY2026 appropriations to DHS through the earlier of February 13, 2026, or the enactment of the DHS appropriations act. The CR funds most DHS programs and activities at the FY2025 levels.</p><p>The bill also extends several expiring programs and authorities, including</p><ul><li>the U.S. Grain Standards Act;</li><li>the Commodity Futures Trading Commission’s whistleblower program;</li><li>the National Flood Insurance Program;</li><li>the Forest Service''s participation in the Agriculture Conservation Experienced Services Program;</li><li>the Transportation Security Administration’s&nbsp;Reimbursable Screening Services Program;</li><li>the Motor Carrier Safety Advisory Committee;</li><li>several authorities and programs related to cybersecurity;</li><li>the technology modernization fund and board;</li><li>the U.S. Parole Commission;</li><li>the special assessment on nonindigent persons or entities convicted of certain offenses involving sexual abuse or human trafficking;</li><li>several immigration-related programs and authorities;</li><li>the authority for the U.S. Sentencing Commission to promulgate certain guidelines or amendments related to the use of unmanned aircraft;&nbsp;</li><li>certain bankruptcy fees;</li><li>trade preferences for Haiti and countries in sub-Saharan Africa;</li><li>the Temporary Assistance for Needy Families (TANF) program; and</li><li>several health care authorities and programs.&nbsp;</li></ul>', '2026-02-05T19:26:06Z', '59', 482);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (58, '2025-12-09', 'Introduced in House', '<p>This bill revises the procedures for appointing and removing the Librarian of Congress, the Director of the Government Publishing Office (GPO), and the Comptroller General by giving Congress the sole authority to appoint and remove these positions.</p><p>Specifically, the bill requires the Librarian and the Director of GPO to each be selected by a bipartisan congressional commission (as established by the bill) and appointed by Congress through the adoption of a concurrent resolution. (Currently, these positions are appointed by the President with the advice and consent of the Senate.) The Librarian and the Director of GPO may only be removed from office by an affirmative three-fifths vote in each chamber.</p><p>Additionally, the bill revises the appointment process for the Comptroller General. (Currently, the Comptroller General is appointed by the President with the advice and consent of the Senate. A bipartisan congressional commission recommends at least three individuals to the President, who may ask the commission to recommend additional individuals.) This bill instead requires the bipartisan congressional commission to recommend one individual to Congress, and Congress may ask the commission to recommend additional individuals.&nbsp;Congress must then appoint the selected individual through the adoption of a concurrent resolution.&nbsp;</p><p>Further, the bill revises the removal process for the Comptroller General. (Currently, the Comptroller General may be removed from office by impeachment or by joint resolution of Congress.) This bill changes the removal process so the individual may only be removed by impeachment or by concurrent (instead of joint) resolution of Congress.</p>', '2026-02-06T19:49:53Z', '00', 490);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (59, '2025-02-13', 'Introduced in House', '<p><strong>LPOE Modernization Trust Fund Act</strong></p><p>This bill establishes the Land Port of Entry Modernization Trust Fund and addresses other issues related to U.S. ports of entry.</p><p>The bill transfers specified amounts, including a portion of certain collected customs fees, to the trust fund each year. It also requires the Department of Homeland Security (DHS) and the Department of State to collect certain surcharges related to immigration and land border inspections, with a portion of the surcharges to be deposited into the trust fund. DHS may not seek to increase fees to offset the amounts transferred into the trust fund.</p><p>Subject to appropriations, the amounts in the trust fund may be used to (1) construct new ports of entry, (2) expand and improve existing ports of entry, (3) procure technology for inspecting and processing traffic passing through ports of entry, and (4) hiring U.S. Customs and Border Protection staff.</p><p>DHS must also establish the Land Port of Entry Modernization Oversight Board to advise DHS on how to use the trust fund and to review the trust fund''s expenditures.</p>', '2026-03-04T02:22:10Z', '00', 514);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (60, '2025-11-20', 'Introduced in House', '<p><b>Increasing Access to Lung Cancer Screening Act</b></p> <p>This bill provides for coverage without prior authorization requirements of annual lung cancer screenings under Medicaid, Medicare, and private health insurance for individuals for whom screenings are recommended under U.S. Preventive Services Task Force guidelines. It also expands Medicaid coverage of counseling and pharmacotherapy for cessation of tobacco use to all individuals, rather than only pregnant women. </p> <p>The Department of Health and Human Services must conduct outreach on the importance of lung cancer screenings and who should be screened, and the Government Accountability Office must report on the demographics of those diagnosed with lung cancer and recommend ways the federal government can improve screenings.</p>', '2026-01-23T15:59:02Z', '00', 524);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (61, '2025-02-12', 'Introduced in House', '<p><strong>United States-Israel Defense Partnership Act of 2025</strong></p><p>This bill requires or authorizes certain actions to increase defense-related cooperation between the United States and Israel.</p><p>Specifically, the bill requires the Department of Defense (DOD) to</p><ul><li>establish a cooperative program, with the concurrence of Israel''s Ministry of Defense (MOD),&nbsp;to develop and deploy advanced technologies for countering unmanned systems that threaten the United States and Israel;</li><li>establish in Israel an office&nbsp;of the Defense Innovation Unit (an organization that&nbsp;focuses on rapidly fielding and scaling commercial technology across the U.S. military); and</li><li>seek to engage Israel''s MOD on the ascension of Israel into the national technology and industrial base (currently&nbsp;defined in law as the persons and organizations engaged in research, development, production, integration, services, or information technology activities conducted within the United States, the United Kingdom, Australia, New Zealand, and Canada).</li></ul><p>The bill authorizes&nbsp;DOD, upon request of Israel''s MOD, to jointly conduct research, development, test, and evaluation (RDT&amp;E) of emerging technologies such as artificial intelligence and robotics&nbsp;to meet defense challenges.</p><p>Additionally, the bill extends the authority for DOD to (1)&nbsp;carry out&nbsp;RDT&amp;E on a joint basis with Israel to establish anti-tunnel and counter unmanned aerial systems capabilities through 2028, and (2)&nbsp;transfer defense articles intended for use as reserve stocks for Israel through January 1, 2029.</p>', '2026-01-15T17:05:33Z', '00', 527);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (62, '2025-11-18', 'Introduced in House', '<p><b>Closing Loopholes for Oil and other Sources of Emissions Act or the CLOSE Act</b></p> <p>This bill amends the Clean Air Act to revise requirements for hazardous air pollutants. Specifically, the bill allows (1) emissions from oil or gas exploration or production wells and emissions from pipeline compressors or pump stations to be aggregated with emissions from other similar sources and regulated as a major source of toxic air pollutants, (2) emissions from those wells to be aggregated for purposes of emissions standards for hazardous air pollutants, and (3) emissions from oil or gas production wells to be regulated as an area source of toxic air pollutants. </p> <p>The Environmental Protection Agency must (1) issue a final rule adding hydrogen sulfide to the list of hazardous air pollutants; and (2) revise the list of air pollution sources within 365 days after issuing the rule to include categories and subcategories of major sources and area sources of hydrogen sulfide, including oil and gas wells.</p>', '2026-02-24T16:53:37Z', '00', 532);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (63, '2025-06-12', 'Introduced in House', '<p><strong>Improving Access to Medicare Coverage Act of </strong><strong>2025</strong></p><p>This bill deems an individual receiving outpatient observation services in a hospital as an inpatient for purposes of satisfying the three-day inpatient hospital-stay requirement&nbsp;with respect to&nbsp;Medicare coverage of skilled nursing facility (SNF) services. (Generally, individuals must have been an inpatient at a hospital for at least three days in order to qualify for SNF services. An individual''s time spent under observation at a hospital for purposes of determining whether the individual should be admitted does not count towards this requirement.)</p>', '2025-07-25T16:12:43Z', '00', 547);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (64, '2025-04-01', 'Introduced in House', '<p><strong>Workplace Violence Prevention for Health Care and Social Service Workers Act</strong></p><p>This bill requires the Department of Labor to address workplace violence in health care, social service, and similar sectors.</p><p>Specifically, Labor must issue an occupational safety and health standard that requires certain employers to take actions to protect workers and other personnel from workplace violence. The standard applies to employers in the health care sector, in the social service sector, and in sectors that conduct activities similar to those in the health care and social service sectors. Among other elements, the standard must require each employer to (1) develop a workplace violence prevention plan, (2) promptly investigate incidents of workplace violence, and (3) provide relevant training and education to employees.&nbsp;</p><p>The bill requires certain hospitals and skilled nursing facilities to comply with this standard as a condition of Medicare participation.</p>', '2026-03-05T16:27:26Z', '00', 551);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (65, '2025-06-17', 'Introduced in House', '<p>This concurrent resolution directs the President to terminate the use of U.S. Armed Forces from hostilities against Iran or any part of the Iranian government or military unless a declaration of war or authorization to use military force for such purpose has been enacted.</p><p>The resolution specifies that it shall not be construed to prevent the United States from defending itself from imminent attack.</p>', '2026-02-27T21:02:09Z', '00', 552);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (66, '2025-09-30', 'Introduced in House', '<p><strong>Physical Therapist Workforce and Patient Access Act of 2025</strong></p><p>This bill expands certain health professional programs and Medicare covered services to include physical therapists.</p><p>Specifically, the bill expands the National Health Service Corps to include physical therapists and provides for the designation of specific health professional target areas for physical therapists under the program. The bill also expands covered services of rural health clinics and federally qualified health centers under Medicare to include physical therapy services.</p><p>The bill increases funds for FY2025 for the corps and requires a certain amount of funds to be used for student loan repayments for participating physical therapists in the National Health Service Corps Loan Repayment Program.</p><p>&nbsp;</p>', '2026-01-15T22:54:30Z', '00', 560);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (67, '2025-09-30', 'Introduced in House', '<p><strong>Prioritizing Offensive Agricultural Disputes and Enforcement Act</strong></p><p>This bill establishes a joint task force to identify and address trade barriers to U.S.&nbsp;agricultural exports.</p><p>Specifically, the bill directs the President to establish the Agricultural Trade Enforcement Task Force. Members of this task force must include employees of the Department of Agriculture''s Foreign Agricultural Service and the Office of the U.S. Trade Representative.</p><p>The bill requires the task force to (1) identify trade barriers to U.S. agricultural exports that are vulnerable to dispute settlement under the World Trade Organization (WTO) or other trade agreements, (2) develop and implement a strategy for enforcing violations of trade agreements related to those trade barriers, (3) identify like-minded trading partners for specific trade barriers that could act as complainants on disputes that are systemically or economically important to the United States, and (4) submit periodic reports to Congress.</p><p>In its initial report, the task force must include a plan for filing a request under the WTO dispute settlement process for consultations&nbsp;to address India''s minimum price supports.</p>', '2025-12-17T11:41:10Z', '00', 572);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (68, '2025-09-18', 'Introduced in House', '<p><strong>Child Care Access Means Parents In Schools Reauthorization Act or the CCAMPIS Reauthorization Act</strong></p><p>This bill reauthorizes through FY2031 and revises the Child Care Access Means Parents in School Program. The program awards grants to support the participation of eligible low-income parents in postsecondary education through the provision of campus-based child care services.</p><p>Among other revisions to the program, the bill increases the minimum and maximum grant amounts, allows grant funds to be used for additional purposes (e.g., child care subsidies and support services), and specifies additional grant application requirements.</p>', '2026-02-26T21:12:34Z', '00', 593);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (69, '2025-11-18', 'Introduced in House', '<p><strong>Aviation Funding Solvency Act</strong></p><p>This bill provides continuing appropriations to the Federal Aviation Administration (FAA) if (1) an appropriations bill for the FAA has not been enacted before a fiscal year begins, or (2) a law making continuing appropriations for the FAA is not in effect.</p><p>Specifically, the bill provides appropriations from the Aviation Insurance Revolving Fund at the rate of operations that was provided for the prior fiscal year to continue programs, projects, and activities that were funded in the preceding fiscal year.&nbsp;The FAA may use the balance of the fund, minus $1 billion.&nbsp;If the FAA&nbsp;determines that the amounts from the fund&nbsp;are insufficient to continue all programs, projects, or&nbsp;activities, then the&nbsp;FAA must prioritize compensation payments for employees of the Air Traffic Organization (e.g., air traffic controllers).</p><p>The bill provides the appropriations until the date on which either (1) specified appropriations legislation  for the fiscal year becomes law, or (2) a bill making continuing appropriations&nbsp;becomes law.</p><p>Finally, the bill permanently extends the FAA Non-premium War Risk Insurance Program. This program provides aviation insurance without a premium to eligible air carriers at the request of the Department of Defense or another federal agency, provided that the agency agrees to indemnify the FAA from all losses covered under the insurance. Eligible air carriers include those whose operations are under a federal contract and are necessary for national security or to carry out U.S. foreign policy.</p>', '2025-12-18T14:05:12Z', '00', 607);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (70, '2025-02-13', 'Introduced in House', '<p>This bill directs the Department of the Interior to remove all deed restrictions from approximately 3.62 acres located at 2956 Park Avenue, on the Paducah Memorial Army Reserve Center in&nbsp;Paducah, Kentucky. The restrictions include easements, exceptions, reservations, terms, conditions, and covenants described in the quitclaim deed that was executed on April 27, 2012. The deed conveyed land from Interior to the City of&nbsp;Paducah, Kentucky.</p>', '2025-12-05T15:23:06Z', '00', 608);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (71, '2025-02-13', 'Introduced in House', '<p><strong>Reorganizing Government Act of 2025</strong><br/>&nbsp;<br/>This bill revives expedited congressional consideration of certain Presidential plans to reorganize the executive branch, expands permissible plan purposes, and changes the prohibitions on plan content.<br/>&nbsp;<br/>The bill reauthorizes through 2026 a currently expired authority that requires expedited congressional consideration of certain executive branch reorganization plans submitted by the President.&nbsp;<br/>&nbsp;<br/>The bill also expands the purposes for which such reorganization plans may be undertaken, to include</p><ul><li>reducing the number of federal employees;</li><li>eliminating unnecessary and burdensome rules, regulations, and other requirements; and</li><li>eliminating government operations that do not serve the public interest.</li></ul><p>The bill removes the following prohibitions on the contents of such plans:&nbsp;</p><ul><li>creating new executive departments or renaming existing executive departments;&nbsp;</li><li>abolishing or transferring executive departments or independent regulatory agencies or all of their functions; and</li><li>consolidating executive departments or independent regulatory agencies or all of their functions.</li></ul><p>The bill also adds a new prohibition on content, specifying that any such plan may not create a net increase in federal workers or expenditures.</p>', '2026-01-21T23:55:26Z', '00', 610);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (72, '2025-12-30', 'Reported to House', '<p><strong></strong><strong><strong></strong></strong><strong>Save Local Business Act</strong></p><p>This bill provides that a person may be considered a joint employer of the employees of another employer&nbsp;under federal labor law only if such person directly, actually, and immediately exercises significant control over the essential terms and conditions of employment. Such control may by demonstrated by hiring and discharging employees; determining individual employee rates of pay and benefits; day-to-day supervision of employees; assigning individual work schedules, positions, or tasks; or administering employee discipline.</p>', '2026-01-12T16:39:03Z', '07', 611);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (73, '2025-02-24', 'Introduced in House', '<p><strong>Guidance Out Of Darkness Act or the GOOD Act</strong></p><p>This bill establishes requirements concerning the posting of agency guidance documents. Specifically, an agency must publish guidance documents online on the dates they are issued, publish all of its guidance documents that are in effect in a single location on a designated website, display a hyperlink on its website that provides access to the guidance documents on such website, and indicate on such website if a guidance document has been rescinded.</p><p>The documents must be categorized as guidance documents and further divided into subcategories.</p><p>No later than five years after the enactment of this bill, the Government Accountability Office must report on agency compliance with these requirements.</p>', '2025-03-06T15:46:25Z', '00', 612);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (74, '2025-09-03', 'Introduced in House', '<p><strong>Common-Sense Law Enforcement and Accountability Now in DC Act or the CLEAN DC Act</strong></p><p>This bill repeals the Comprehensive Policing and Justice Reform Amendment Act of 2022, enacted by the Council of the District of Columbia.</p><p>Any provision of law amended or repealed by that act is restored or revived as if it had not been enacted.</p><p>(The act sets forth a variety of measures that focus on policing, including measures prohibiting the use of certain neck restraints by law enforcement officers, requiring additional procedures related to body-worn cameras, and expanding access to police disciplinary records.)</p>', '2025-09-09T17:52:47Z', '00', 646);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (75, '2025-10-03', 'Introduced in House', '<p><strong>Termination of Reckless Unchecked Mandates from this President Act or the TRUMP Act</strong></p><p>This bill prohibits federal funds from being obligated or expended to promulgate or issue any executive order or presidential memorandum during a lapse in discretionary appropriations (i.e., government shutdown).&nbsp;</p>', '2025-10-21T13:31:31Z', '00', 665);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (76, '2025-11-12', 'Introduced in House', '<p><strong>Building Resources and Access for Veterans'' Mental Health Engagement Act of 2025 or the BRAVE Act of 2025</strong></p><p>This bill addresses mental health services and care provided by the Department of Veterans Affairs (VA), including matters related to personnel, Vet Center administration, care for women veterans, and access to care.</p><p>The bill authorizes the VA to waive the licensure or certification requirement for individual licensed professional mental health counselor appointees for a reasonable period of time.</p><p>The bill also extends the Staff Sergeant Parker Gordon Fox Suicide Prevention Grant Program and increases the maximum annual grant amount.</p><p>The VA must provide Vet Centers with guidance for assessing outreach activities and implement processes to periodically assess the extent to which (1) veterans and eligible members of the Armed Forces experience barriers to obtaining services at Vet Centers, and (2) Vet Center staff may encounter barriers to providing services.</p><p>Among other requirements, the VA must also</p><ul><li>survey and host listening sessions with women veterans to gauge the effectiveness of the VA’s suicide prevention, lethal-means safety, and mental health resources and messaging campaigns;</li><li>initiate efforts to modify the Recovery Engagement and Coordination for Health-Veterans Enhanced Treatment (REACH VET) program to incorporate risk factors weighted for women;</li><li>annually offer a mental health consultation to veterans who are receiving compensation for a service-connected disability relating to a mental health diagnosis; and</li><li>implement a pilot program to provide access to mental health residential treatment programs for veterans with a spinal cord injury or disorder.</li></ul>', '2026-02-23T12:32:48Z', '00', 678);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (77, '2025-11-12', 'Introduced in House', '<p><strong>Legislative Branch Agencies Clarification Act</strong></p><p>This bill revises the procedures for appointing and removing the Librarian of Congress, the Director of the Government Publishing Office (GPO), and the Register of Copyrights.</p><p>Specifically, the bill requires the Librarian and the Director of GPO to be appointed by a bipartisan congressional commission, based on procedures outlined by the bill and without regard to political&nbsp;affiliation. (Currently, these positions are appointed by the President with the advice and consent of the Senate.)  The Librarian and the Director of GPO may only be removed from office by a majority vote of the majority and minority leaders of the House of Representatives and the Senate.</p><p>Additionally, the bill requires the Librarian and the Director of GPO to each appoint a deputy within a set time frame and outlines related procedures.</p><p>The bill removes the Library of Congress''s (LOC''s) supervisory authority over the Copyright Office.&nbsp;LOC and other legislative agencies may provide support services to the Copyright Office.</p><p>The bill requires the Register of Copyrights to be (1) a U.S. citizen with a background and experience in copyright law, and (2) appointed by the President with the advice and consent of the Senate. (Currently, the Register is appointed by the Librarian.) The bill limits the term of office for the Register to 10 years, but the individual may be&nbsp;reappointed.</p><p>The bill also requires GPO to establish and maintain a human capital management system and outlines the requirements for the system.</p>', '2025-11-19T19:19:53Z', '00', 697);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (78, '2025-10-03', 'Introduced in House', '<p><strong>Stop Stealing Our Jobs Act</strong></p><p>This bill prohibits the President or the head of an executive agency from removing a federal employee from the civil service (e.g., as part of a reduction in force) during a lapse in discretionary appropriations (i.e., government shutdown) unless the employee is a political appointee.&nbsp;</p>', '2025-10-17T14:32:40Z', '00', 703);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (79, '2025-06-11', 'Introduced in House', '<p><strong>Promoting Efficient Review for Modern Infrastructure Today Act or the PERMIT Act</strong></p><p>This bill limits the scope of the Clean Water Act by redefining <em>navigable waters</em> to exclude (1) waste treatment systems, (2) ephemeral features that flow only in direct response to precipitation, (3) prior converted cropland, (4) groundwater, or (5) any other features determined to be excluded by the U.S. Army Corps of Engineers.</p>', '2025-07-08T17:06:07Z', '00', 705);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (80, '2025-10-24', 'Introduced in House', '<p><strong>Halting Education Loan Payments during Federal Employment Disruptions Act or the HELP FEDs Act</strong></p><p>This bill waives late fees, penalties, and other adverse actions for federal employees who miss student loan payments during a lapse in appropriations (i.e., government shutdown). &nbsp;</p><p>The bill applies to education loans made, insured, or guaranteed under the Higher Education Act of 1965, including loans held by the Department of Education (ED) or contracted loan servicers.</p><p>Under the bill, a federal employee who misses a student loan payment that is due during a period of involuntary disruption of pay (i.e., the employee did not receive scheduled wages due to a lapse in appropriations) may not be assessed a late fee or penalty or be subject to other adverse actions. The bill also prohibits federal employees from incurring additional interest on such loans during an involuntary disruption of pay.&nbsp;</p><p>In addition, the bill requires ED to coordinate with credit reporting agencies and loan&nbsp;servicers to ensure that no adverse information related to delayed or missed student loan payments of a federal employee during an involuntary disruption of pay is furnished to any consumer reporting agency.&nbsp;</p><p>The bill applies retroactively to any involuntary disruption of pay occurring on or after October 1, 2025.&nbsp;</p>', '2025-10-29T16:40:13Z', '00', 716);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (81, '2025-01-03', 'Introduced in House', '<p><strong>Grant''s Law</strong></p><p>This bill requires the Department of Justice to detain a non-U.S. national (<em>alien</em> under federal law) found to be unlawfully present in the United States and arrested for various crimes that would render the individual deportable or inadmissible.</p><p>The Department of Homeland Security (DHS) may release the individual to an appropriate authority for proceedings related to the arrest, but DHS must resume custody for any period that the individual is not in such authority''s custody.</p><p>If the individual is not convicted of crimes for which the individual was arrested, DHS must continue to detain the individual until removal proceedings are completed. DHS must complete such removal proceedings within 90 days.</p>', '2025-02-11T15:35:30Z', '00', 728);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (82, '2025-12-03', 'Introduced in House', '<p><strong>Chiricahua National Park Act</strong></p><p>This bill redesignates the Chiricahua National Monument in Arizona as the Chiricahua National Park.</p><p>The bill directs the National Park Service (NPS) to (1) ensure the protection of traditional cultural and religious sites in the park, and (2) provide access to those sites by members of Indian tribes for traditional cultural and customary uses. </p><p>Upon the request of an Indian tribe, the&nbsp;NPS may temporarily close to general public use one or more specific areas of the park to protect traditional cultural and customary uses in the area by members of the tribe. The closure must be limited to the smallest practicable area for the minimum period necessary for the traditional cultural and religious activities.</p>', '2026-03-12T13:35:01Z', '00', 729);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (83, '2025-09-26', 'Introduced in House', '<p><strong>Funding Small Businesses During Shutdown Act</strong></p><p>This bill provides FY2026 appropriations to continue servicing loans made under certain Small Business Administration (SBA) loan programs if there is a lapse in discretionary appropriations (i.e., government shutdown) in FY2026.</p><p>If there is a lapse in FY2026 appropriations for the SBA, the bill provides specified appropriations to pay for the salaries and expenses necessary to continue servicing any loans made under several loan programs authorized by the Small Business Act and the Small Business Investment Act of 1958.</p><p>The bill provides the appropriations for any 30-day period in which there is a lapse in SBA appropriations and on a pro-rated basis if the lapse is less than 30 days.</p>', '2025-10-09T15:31:48Z', '00', 741);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (84, '2025-08-08', 'Introduced in House', '<p><strong>DC Criminal Reforms to Immediately Make Everyone Safe Act or the DC CRIMES Act</strong></p><p>This bill limits the authority of the District of Columbia (DC) government over its criminal sentencing laws.&nbsp;</p><p>The bill eliminates the DC government’s authority to enact any act, resolution, or rule to change any criminal liability sentence in effect on the date of the bill''s enactment.</p><p>The bill also (1) reduces the maximum age of a youth offender from 24 years to 18 years, and (2) repeals a provision that allows a DC criminal court to issue a sentence to a youth offender that is less than the mandatory minimum term otherwise required by law. A DC criminal court currently has the discretion to reduce or modify certain criminal sentences for a youth offender under specified circumstances. For example, a DC court may sentence a youth offender to probation in lieu of confinement. (However, this discretion does not apply to several specified violent crimes.)&nbsp;</p><p>Additionally, the bill directs the Office of the Attorney General for DC to publish, and update monthly, certain youth offender crime data on a publicly accessible website.&nbsp;</p>', '2025-09-09T15:38:47Z', '00', 752);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (85, '2025-01-03', 'Introduced in House', '<p><strong>Equal Representation Act</strong></p><p>This bill requires that the statement sent by the President to Congress after the decennial census indicating the number of persons in each state&nbsp;exclude&nbsp;noncitizens. (This&nbsp;statement is the basis for reapportionment of U.S. Representatives.)</p><p>The bill also requires&nbsp;any questionnaire used in the&nbsp;decennial census to include a checkbox or other similar option for respondents to indicate whether the respondent and each household member is (1) a U.S. citizen, (2) a U.S. national but not a citizen, (3) a non-U.S. national (<em>alien </em>under federal law) lawfully residing in the United States, or (4) a non-U.S. national unlawfully residing in the United States.</p><p>The Department of Commerce must make public the number of persons in each state, disaggregated by each of these four categories.</p>', '2025-04-17T21:07:33Z', '00', 756);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (86, '2026-02-20', 'Introduced in House', 'This bill provides for the relief of Roberto Carlos Lopez.', '2026-02-21T09:19:54Z', '00', 759);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (87, '2025-05-21', 'Introduced in House', '<p>This bill prohibits the President from selling, transferring, or exporting certain defense articles or services to Israel, except in specified circumstances.&nbsp;</p><p>Defense articles covered by the prohibition include BLU-109 bunker busting bombs, Joint Direct Attack Munition (JDAM) assemblies, and 155mm artillery ammunition. Defense services directly related to such articles are also covered.&nbsp;</p><p>The President may sell, transfer, or export such defense articles or services to Israel if (1) a law is enacted specifying the purposes for which such articles or services may be used, and (2) Israel provides written assurances that the defense articles or services will be used for those specific statutory purposes and in a manner consistent with certain other laws, including international human rights laws.&nbsp;</p>', '2025-08-06T19:21:27Z', '00', 791);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (88, '2025-07-25', 'Introduced in House', '<p><strong>National Security, Department of State, and Related Programs Appropriations Act, 2026</strong></p><p>This bill provides FY2026 appropriations for national security, the Department of State, and related programs.</p><p>The bill provides appropriations to the State Department for</p><ul><li>Administration of Foreign Affairs,</li><li>International Organizations, and</li><li>International Commissions.</li></ul><p>The bill provides appropriations for related programs, including</p><ul><li>International Broadcasting Operations and Capital Improvements,</li><li>the Asia Foundation,</li><li>the U.S. Institute of Peace,</li><li>the Center for Middle Eastern-Western Dialogue Trust Fund,</li><li>the Eisenhower Exchange Fellowship Program,</li><li>the Israeli Arab Scholarship Program,</li><li>the East-West Center, and</li><li>the National Endowment for Democracy.</li></ul><p>The bill provides appropriations for other commissions, including</p><ul><li>the Commission for the Preservation of America''s Heritage Abroad,</li><li>the U.S. Commission on International Religious Freedom,</li><li>the Commission on Security and Cooperation in Europe,</li><li>the Congressional-Executive Commission on the People''s Republic of China, and&nbsp;</li><li>the U.S.-China Economic and Security Review Commission.</li></ul><p>The bill provides appropriations to</p><ul><li>the House Democracy Partnership,</li><li>the President for Administration of Assistance,</li><li>the State Department and the President for International Security Assistance, and</li><li>International Financial Institutions for Multilateral Assistance.</li></ul><p>The bill provides appropriations for bilateral economic assistance, including programs and activities conducted by</p><ul><li>the President;</li><li>Independent Agencies, including the Peace Corps, the Millennium Challenge Corporation, the Inter-American Foundation, and the U.S. African Development Foundation; and</li><li>the Department of the Treasury.</li></ul><p>The bill provides appropriations for export and investment assistance to</p><ul><li>the Export-Import Bank of the United States,</li><li>the U.S. International Development Finance Corporation, and</li><li>the U.S. Trade and Development Agency.</li></ul><p>The bill sets forth requirements and restrictions for using funds provided by this and other appropriations acts.</p>', '2025-10-03T13:52:59Z', '00', 804);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (89, '2025-07-25', 'Reported to House', '<p><strong>National Security, Department of State, and Related Programs Appropriations Act, 2026</strong></p><p>This bill provides FY2026 appropriations for national security, the Department of State, and related programs.</p><p>The bill provides appropriations to the State Department for</p><ul><li>Administration of Foreign Affairs,</li><li>International Organizations, and</li><li>International Commissions.</li></ul><p>The bill provides appropriations for related programs, including</p><ul><li>International Broadcasting Operations and Capital Improvements,</li><li>the Asia Foundation,</li><li>the U.S. Institute of Peace,</li><li>the Center for Middle Eastern-Western Dialogue Trust Fund,</li><li>the Eisenhower Exchange Fellowship Program,</li><li>the Israeli Arab Scholarship Program,</li><li>the East-West Center, and</li><li>the National Endowment for Democracy.</li></ul><p>The bill provides appropriations for other commissions, including</p><ul><li>the Commission for the Preservation of America''s Heritage Abroad,</li><li>the U.S. Commission on International Religious Freedom,</li><li>the Commission on Security and Cooperation in Europe,</li><li>the Congressional-Executive Commission on the People''s Republic of China, and&nbsp;</li><li>the U.S.-China Economic and Security Review Commission.</li></ul><p>The bill provides appropriations to</p><ul><li>the House Democracy Partnership,</li><li>the President for Administration of Assistance,</li><li>the State Department and the President for International Security Assistance, and</li><li>International Financial Institutions for Multilateral Assistance.</li></ul><p>The bill provides appropriations for bilateral economic assistance, including programs and activities conducted by</p><ul><li>the President;</li><li>Independent Agencies, including the Peace Corps, the Millennium Challenge Corporation, the Inter-American Foundation, and the U.S. African Development Foundation; and</li><li>the Department of the Treasury.</li></ul><p>The bill provides appropriations for export and investment assistance to</p><ul><li>the Export-Import Bank of the United States,</li><li>the U.S. International Development Finance Corporation, and</li><li>the U.S. Trade and Development Agency.</li></ul><p>The bill sets forth requirements and restrictions for using funds provided by this and other appropriations acts.</p>', '2025-10-03T14:12:44Z', '07', 804);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (90, '2023-04-17', 'Introduced in House', ' <p><b>Protecting Horses from Soring Act of 2023</b></p> <p>This bill revises requirements concerning the inspection of horse shows, exhibitions, sales, and actions for sored horses (e.g., horses suffering from pain when moving due to substances or devices placed on their limbs). Specifically, this bill replaces a requirement for the Department of Agriculture to prescribe regulations governing the appointment of inspectors with a requirement for the Horse Industry Organization, which is established by this bill, to appoint inspectors.</p>', '2023-06-05T15:26:48Z', '00', 814);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (91, '2023-02-27', 'Introduced in House', ' <p><strong>Stop Fentanyl Border Crossings Act</strong></p> <p>This bill authorizes the Department of Health and Human Services (HHS) to restrict migration and imports from foreign countries to prevent the introduction of illicit drugs into the United States.</p> <p>Current law authorizes HHS to restrict migration and imports from foreign countries to prevent the introduction of communicable diseases. Under this bill, HHS may also restrict migration and imports from a country if HHS determines that the existence of substantial illicit drug smuggling from that country poses a risk to public health.</p>', '2023-03-21T13:57:07Z', '00', 815);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (92, '2023-02-27', 'Introduced in House', ' <p><strong>Student Loan Accountability Act</strong></p> <p>This bill generally prohibits the Departments of Education, Justice, or the Treasury from taking any action to cancel or forgive the outstanding balances, or portion of balances, of covered loans. <em>Covered loans</em> refer to Federal Family Education Loans, Federal Direct Loans, Federal Perkins Loans, and loans under the Health Education Assistance Loan Program.</p> <p>The prohibition does not apply to targeted federal student loan forgiveness, cancellation, or repayment programs that are in effect by final regulation on March 12, 2020, and carried out under the Higher Education Act of 1965.</p>', '2023-04-06T17:05:51Z', '00', 816);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (93, '2023-02-21', 'Introduced in House', ' <p>This joint resolution proposes a constitutional amendment requiring individuals to demonstrate cognitive competence as a condition of holding the office of President or Vice President.</p>', '2023-03-15T18:03:45Z', '00', 817);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (94, '2025-12-18', 'Introduced in House', 'This bill designates the facility of the United States Postal Service located at 2121 Meridian Park Boulevard in Concord, California, as the "Carl Jefferson Post Office Building".', '2026-01-17T08:23:15Z', '00', 831);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (95, '2025-01-31', 'Introduced in House', '<p><strong>Stop Antiabortion Disinformation Act or the SAD Act </strong></p><p>This bill prohibits deceptive advertising for reproductive health services.</p><p>Specifically, the bill makes it unlawful for a person (i.e., individual, partnership, corporation, association, or organization) to deceptively advertise  the reproductive health services they offer, including by misrepresenting that the person (1) offers or provides contraception or abortion services (or referrals for such contraception or abortion services), or (2) employs or offers access to licensed medical personnel.</p><p>The bill provides for enforcement by the Federal Trade Commission.</p><p>In addition to any other penalty, violations are subject to a civil penalty that may not exceed the greater of $100,000 (adjusted annually for inflation)&nbsp;or 50%&nbsp;of the revenue earned during the preceding 12-month period by the ultimate parent entity of the person who violated the bill.&nbsp;</p>', '2025-05-28T18:54:47Z', '00', 832);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (96, '2025-06-05', 'Introduced in House', '<p><strong>Farmers Feeding America Act of 2025</strong></p><p>This&nbsp;bill reauthorizes The Emergency Food Assistance Program (TEFAP),&nbsp;increases funding for the program,&nbsp;and provides additional delivery options for geographically isolated states (i.e., Hawaii, Alaska, Puerto Rico, the Northern Mariana Islands, the U.S. Virgin Islands, and Guam).</p><p>TEFAP is a federal program that helps supplement the diets of people with low income by providing them with emergency food assistance at no cost. Through TEFAP, the Department of Agriculture (USDA) purchases a variety of commodities and makes those food products (e.g., canned, frozen, dried, and fresh fruits and vegetables, eggs, meat, dairy, and whole-grain and enriched grain products) available to state distributing agencies.</p><p>The bill increases funding for purchasing commodities under&nbsp;the program.</p><p>Further, the bill directs USDA to coordinate with geographically isolated states to (1) establish alternative delivery options for allocated commodities, and (2) allow for the states to order commodities through the&nbsp;USDA Department of Defense Fresh Fruit and Vegetable Program.&nbsp;</p><p>USDA may also provide geographically isolated states the ability to directly purchase domestically grown food in lieu of receiving a portion of the commodities. Under this option, USDA may distribute as cash&nbsp;to the state up to 20% of the cash value of the commodities that are allocated to the state under TEFAP.&nbsp;</p><p>Further, USDA may consider additional factors beyond lowest price&nbsp;in determining winning bids for contracts for fresh produce packages&nbsp;(including product variety and transportation distance).&nbsp;</p>', '2025-12-16T14:58:15Z', '00', 876);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (97, '2025-01-06', 'Introduced in House', '<p><b>Dental Care for Veterans Act</b></p> <p>This bill expands eligibility for veterans for dental care provided by the Department of Veterans Affairs (VA). Specifically, the bill makes all veterans who are enrolled in the VA health care system eligible for VA-provided dental services. Currently, only veterans who have a service-connected dental issue or meet other narrow criteria are eligible for certain dental services.</p> <p>The bill phases in eligibility over four years based upon existing eligibility, degree of service-connected disability or other disability, prisoner of war status, award of a Purple Heart, financial need, or VA health care eligibility.</p>', '2025-02-03T17:11:34Z', '00', 877);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (98, '2023-12-05', 'Introduced in House', ' <p><b>Encouraging Success Act</b></p> <p>This bill requires the Small Business Administration to periodically revise, based on economic changes, the maximum total assets and net worth an individual may have to qualify as an economically disadvantaged individual under the 8(a) Business Development program.</p>', '2024-02-26T20:58:28Z', '00', 882);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (99, '2024-02-09', 'Reported to House', ' <p><b>Encouraging Success Act</b></p> <p>This bill requires the Small Business Administration to periodically revise, based on economic changes, the maximum total assets and net worth an individual may have to qualify as an economically disadvantaged individual under the 8(a) Business Development program.</p>', '2024-02-27T15:53:35Z', '07', 882);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (100, '2024-02-28', 'Passed House', ' <p><b>Encouraging Success Act</b></p> <p>This bill requires the Small Business Administration to periodically revise, based on economic changes, the maximum total assets and net worth an individual may have to qualify as an economically disadvantaged individual under the 8(a) Business Development program.</p>', '2024-03-08T13:34:02Z', '53', 882);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (101, '2026-01-09', 'Introduced in House', 'This bill designates the facility of the United States Postal Service located at 825 Highway 198 in Beaumont, Mississippi, as the "Jeremy Malone Post Office".', '2026-01-22T05:02:02Z', '00', 885);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (102, '2026-03-03', 'Passed Senate', '<p><strong>Small Business Innovation and Economic Security Act</strong></p><p>This bill reauthorizes through FY2031 and modifies the Small Business Innovation Research (SBIR) program, the Small Business Technology Transfer (STTR) program, and related pilot programs.&nbsp;(The SBIR and STTR programs are administered by various federal agencies and provide competitive awards for domestic small businesses to conduct research and development projects that have the potential for commercialization.)</p><p>Specifically, the bill expands the requirements for federal agencies administering these programs to evaluate the security risks of the small businesses that apply for awards under the programs. If an agency denies an application for security reasons, the agency must provide the small business with&nbsp;the basis for such determination.</p><p>Further, each agency must set a maximum number of proposals per fiscal year that a small business concern may submit in response to Phase I and Phase II solicitations.</p><p>The bill expands the training requirements for agencies'' contracting officers and acquisition workforce with respect to Phase III (commercialization of technologies) awards under the&nbsp;SBIR and STTR programs.</p><p>The bill also establishes strategic breakthrough allocations for critical technology areas. These are additional Phase II SBIR and STTR awards to&nbsp;small businesses that demonstrate an effective technology and receive matching funds.</p>', '2026-03-16T14:46:55Z', '55', 906);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (103, '2026-02-12', 'Introduced in House', 'This bill designates the facility of the United States Postal Service located at 4431 Main Street in Philadelphia, Pennsylvania, as the "Dr. Constance ''Connie'' E. Clayton Post Office".', '2026-02-25T07:01:03Z', '00', 908);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (104, '2025-12-11', 'Introduced in House', '<p><strong>El Paso Air Traffic Control Tower Modernization Act</strong></p><p>This bill provides appropriations for the replacement of the El Paso Air Traffic Control Tower at the El Paso International Airport in El Paso, TX.</p>', '2026-01-23T19:51:43Z', '00', 925);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (105, '2025-01-09', 'Introduced in House', '<p><strong>Geothermal Energy Opportunity Act or the GEO Act</strong></p><p>This bill expands the Geothermal Steam Act of 1970 to establish a deadline for the Department of the Interior to process applications related to geothermal leases. Specifically, Interior must process each application for a geothermal drilling permit or other authorization under a valid existing geothermal lease within 60 days after completing all requirements under applicable federal laws and regulations (including the National Environmental Policy Act of 1969, the Endangered Species Act of 1973, and the National Historic Preservation Act) unless a U.S. federal court vacates or provides injunctive relief for the underlying lease. &nbsp;</p>', '2025-03-12T12:53:45Z', '00', 941);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (106, '2025-02-13', 'Introduced in House', '<p>This concurrent resolution declares that Congress should not impose any new performance fee, tax, royalty, or other charge relating to the public performance of sound recordings on a local radio station for broadcasting sound recordings over the air, or on any business for such public performance of sound recordings.</p>', '2025-02-25T18:54:38Z', '00', 948);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (107, '2025-10-31', 'Reported to House', '<p>This bill specifies that all federally acquired lands are eligible to be considered for&nbsp;hardrock mineral leasing under the Mineral Leasing Act for Acquired Lands (MLAAL). The bill defines the term&nbsp;<em>hardrock mineral</em> to (1) include deposits of minerals found in sedimentary or other rocks, base metals, precious metals,&nbsp;industrial minerals, and precious and semi-precious gemstones; and (2) exclude deposits of coal, oil, oil shale, gas, sodium, potassium, sulfur, or mineral materials subject to disposition under the Materials Act of 1947.</p><p>By way of background, hardrock minerals are not currently listed under the MLAAL as deposits subject to a lease, while mineral resources such as coal, phosphate, oil, gas, gilsonite, and sulfur are listed. As a result, federal lands may be leased for mining&nbsp;hardrock minerals only if the federal lands were acquired under a statute, such as the Weeks Act, that specifically authorizes the land to be used for hardrock mineral leasing.</p>', '2025-12-12T15:45:00Z', '07', 949);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (108, '2025-09-08', 'Introduced in House', '<p><strong>District of Columbia Attorney General Appointment Reform Act</strong></p><p>This bill vests the President with the authority to appoint the Attorney General for the District of Columbia (DC) for a term that coincides with the term of office of the President. The bill provides that the appointment is not subject to confirmation in the Senate.</p><p>Under current DC law, the Attorney General is elected by DC voters for a four-year term that coincides with the term of office of the DC Mayor.</p><p>The bill additionally provides that the term of the current Attorney General&nbsp;ends on the date of the bill''s enactment.</p>', '2025-09-19T15:40:51Z', '00', 952);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (109, '2025-02-13', 'Introduced in House', '<p>This bill specifies a legal standard for determining whether an individual is considered an <em>independent contractor </em>rather than an <em>employee</em> for the purposes of federal labor laws that address issues such as the federal minimum wage, overtime compensation, and collective bargaining. The rights and protections provided by these laws exclusively apply to employees.</p><p>Under the bill, an individual is considered an independent contractor if (1) another individual or entity does not exercise significant control over the details of how the individual''s work is performed, without regard to any control the other individual or entity may exercise over the final result of the work performed; and (2) while performing such work, the individual has opportunities and risks inherent with entrepreneurship (for example, the discretion to exercise professional judgment).</p><p>The bill also sets forth factors that may not be used to determine whether an individual is an employee. Specifically, factors such as whether another individual or entity requires the individual to meet certain legal, health and safety, insurance, or performance requirements may not be used to make such a determination.</p>', '2025-07-29T15:15:23Z', '00', 969);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (110, '2025-07-21', 'Reported to House', '<p><strong>Energy and Water Development and Related Agencies Appropriations Act, 2026</strong></p><p>This bill provides FY2026 appropriations for U.S. Army Corps of Engineers civil works projects, the Department of the Interior''s Bureau of Reclamation, the Department of Energy (DOE), and several independent agencies.</p><p>The bill provides appropriations for U.S. Army Corps of Engineers civil works projects, including for</p><ul><li>Investigations,</li><li>Construction,</li><li>Mississippi River and Tributaries,</li><li>Operation and Maintenance,</li><li>the Regulatory Program,</li><li>Flood Control and Coastal Emergencies,</li><li>Expenses,</li><li>the Office of the Assistant Secretary of the Army for Civil Works, and</li><li>the Water Infrastructure Finance and Innovation Program.</li></ul><p>The bill provides appropriations to the Department of the Interior for the Central Utah Project and the Bureau of Reclamation.</p><p>The bill provides appropriations to DOE for energy programs, including</p><ul><li>Energy Efficiency and Renewable Energy;</li><li>Cybersecurity, Energy Security, and Emergency Response;</li><li>Electricity;</li><li>Grid Deployment;</li><li>Nuclear Energy;</li><li>Fossil Energy;</li><li>Naval Petroleum and Oil Shale Reserves;</li><li>the Strategic Petroleum Reserve;</li><li>the Northeast Home Heating Oil Reserve;</li><li>the Energy Information Administration;</li><li>Non-Defense Environmental Cleanup;</li><li>the Uranium Enrichment Decontamination and Decommissioning Fund;</li><li>Science;</li><li>Nuclear Waste Disposal;</li><li>the Advanced Research Projects Agency—Energy;</li><li>the Title 17 Innovative Technology Loan Guarantee Program;</li><li>the Advanced Technology Vehicles Manufacturing Loan Program;</li><li>the Tribal Energy Loan Guarantee Program;</li><li>Indian Energy Policy and Programs;</li><li>Departmental Administration; and</li><li>the Office of the Inspector General.</li></ul><p>The bill also provides appropriations to DOE for</p><ul><li>Atomic Energy Defense Activities of the National Nuclear Security Administration,</li><li>Environmental and Other Defense Activities, and</li><li>the Power Marketing Administrations.</li></ul><p>The bill provides appropriations to several independent agencies, including the Federal Energy Regulatory Commission and the Nuclear Regulatory Commission.</p><p>The bill also sets forth requirements and restrictions for using funds provided by this and other appropriations acts.</p>', '2025-08-22T13:19:51Z', '07', 978);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (111, '2025-10-31', 'Introduced in House', '<p><strong>Prevent Government Shutdowns Act</strong></p><p>This bill provides continuing appropriations to prevent a government shutdown if the appropriations bills for a fiscal year have not been enacted before the fiscal year begins and continuing appropriations are not in effect.</p><p>Specifically, the bill provides appropriations at the rate of operations that was provided for the prior fiscal year to continue programs, projects, and activities that were funded in the preceding fiscal year.</p><p>The bill also limits official travel, congressional recesses or adjournments, and the consideration of legislation that is unrelated to appropriations after the beginning of a fiscal year if the appropriations process has not been completed.</p>', '2025-11-05T17:28:01Z', '00', 979);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (112, '2025-01-13', 'Introduced in House', '<p><strong>Head start Education And Development Workforce Advancement and Yield Act or the HEADWAY Act</strong></p><p>This bill allows some teachers in Early Head Start programs to teach while in the process of earning their Child Development Associate (CDA) credential and completing training.</p><p>Currently, the Department of Health and Human Services (HHS) must ensure that all teachers providing direct services to children and families in Early Head Start centers (1) have a minimum of a CDA credential and have been trained in early childhood development, and (2) have been trained in early childhood development with a focus on infant and toddler development.</p><p>The bill revises this requirement by requiring at least one teacher per classroom (instead of all teachers) to have a CDA credential and training. In particular, the bill requires HHS to ensure that (1) each additional teacher providing direct services to children and families is in the process of earning a CDA credential and completing training, and (2) the Early Head Start agency provides a mentor to oversee the progress and guide the work of a teacher who is in the process of earning a CDA credential and completing training.</p>', '2025-03-03T16:59:33Z', '00', 992);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (113, '2026-01-06', 'Introduced in House', '<p><strong>Supporting Pregnant and Parenting Women and Families Act</strong></p><p>This bill provides statutory authority for&nbsp;states to use Temporary Assistance for Needy Families (TANF) funds for pregnancy centers that (1) support protecting the life of the mother and the unborn child; and (2) offer resources and services to mothers, fathers, and families, including relationship counseling, prenatal and pregnancy education, pregnancy testing, diapers, baby clothes, and material supports.</p>', '2026-01-20T16:56:36Z', '00', 1008);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (114, '2025-11-12', 'Reported to House', '<p>This resolution provides for House consideration of S.Amdt. 3937, a Senate amendment&nbsp;to H.R. 5371,<em> Continuing Appropriations, Agriculture, Legislative Branch, Military Construction and Veterans Affairs, and Extensions Act, 2026.</em></p>', '2025-12-18T16:58:05Z', '07', 1010);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (115, '2025-02-13', 'Introduced in House', '<p><strong>More Homes on the Market Act </strong></p><p>This bill increases the amount of gain from the sale of a principal residence that an individual may exclude from gross income (for federal tax purposes). </p><p>Under the bill, an individual may exclude from gross income gain from the sale of a principal residence of up to $500,000 (currently $250,000), and taxpayers who are married and file a joint federal income tax return may exclude up to $1 million (currently $500.000).&nbsp;The bill also requires these amounts to be adjusted annually for inflation.</p>', '2025-09-09T18:52:28Z', '00', 1013);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (116, '2025-03-05', 'Introduced in House', '<p><strong>TAP Promotion Act</strong></p><p>This bill requires that pre-separation counseling under the Transition Assistance Program include a presentation that promotes the benefits available to veterans from the Department of Veterans Affairs&nbsp;(VA). The bill also requires the VA to annually report on the presentation to (1) identify veterans service organizations that participate, (2) provide the number of members of the Armed Forces who attend, and (3) provide any recommendations for changes to the presentation.</p>', '2025-05-13T14:33:41Z', '00', 1021);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (117, '2025-11-04', 'Introduced in House', '<p><strong>Non-Essential Workers Transparency Act</strong></p><p>This bill requires federal agencies to submit reports to Congress&nbsp;regarding employees who were furloughed during a lapse in appropriations (i.e, government shutdown), the total number of employees, and the cost of salaries.&nbsp;</p><p>Specifically, each federal agency must submit a report to specified congressional committees&nbsp;within 30 days of the end of a lapse in appropriations. The report must include specified details regarding</p><ul><li>the total number of employees (including contract employees) employed by the agency before the lapse began,</li><li>the total number of employees who were furloughed during the lapse,</li><li>the total number of employees who were not furloughed during the lapse, and&nbsp;</li><li>the total annual cost of the salaries for each group of employees.&nbsp;</li></ul><p>The report must be submitted in an unclassified form, but it may include a classified annex. Each congressional committee that receives a report must publish the report on its website within 30 days.&nbsp;</p><p>The bill also requires the Congressional Budget Office (CBO) to submit a report to Congress&nbsp;regarding the economic effects of each lapse in appropriations.&nbsp;CBO must submit the report within 30 days of the end of a lapse in appropriations and make the report available on its website.&nbsp;</p>', '2025-11-06T14:51:14Z', '00', 1024);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (118, '2025-11-07', 'Introduced in House', 'This bill designates the facility of the United States Postal Service located at 1201 Calvert Street in Lincoln, Nebraska, as the "Commodore Dixie Kiefer Memorial Post Office Building".', '2025-11-11T07:08:33Z', '00', 1031);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (119, '2025-11-10', 'Introduced in House', 'This bill designates the facility of the United States Postal Service located at 401 North Elm Street in Tuskegee, Alabama, as the "Tuskegee Airmen Memorial Post Office".', '2025-11-14T06:34:29Z', '00', 1068);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (120, '2025-10-31', 'Introduced in House', '<p><strong>Keep America Building Act</strong></p><p>This bill prohibits federal funds from being used to (1) to suspend, delay, or interrupt all or part of the work of a project under a contract during any lapse in appropriations (i.e., government shutdown); or (2) stop all or any part of the work agreed to in the contract.&nbsp;</p>', '2025-11-06T15:00:21Z', '00', 1069);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (121, '2025-04-10', 'Introduced in House', '<p><strong>Supplemental Oxygen Access Reform Act of 2025&nbsp;or the SOAR Act of 2025</strong></p><p>This bill establishes certain requirements with respect to the payment and provision of supplemental oxygen and related services under Medicare.</p><p>For example, the bill provides for separate payments, indexed to inflation, of oxygen and related equipment, supplies, and services under Medicare (rather than under the competitive acquisition program). It also specifically covers services that are provided by respiratory therapists under Medicare and provides for an additional payment adjustment for these services.</p><p>Additionally, the bill (1) requires the Centers for Medicare &amp; Medicaid Services to develop an electronic template for providers to use when prescribing oxygen and related equipment, supplies, and services; and (2) establishes certain rights for beneficiaries receiving these items and services, such as the right to choose their suppliers and to receive clear communications and be informed about the services provided.</p>', '2025-05-21T20:36:22Z', '00', 1070);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (122, '2025-07-10', 'Introduced in House', '<p>This joint resolution nullifies the rule submitted by the Bureau of Land Management (BLM) relating to the Record of Decision and Approved Resource Management Plan (RMP) for the North Dakota Field Office and issued on January 8, 2025.&nbsp;</p><p>By way of background, an RMP guides the management of lands administered by BLM. The 2025 North Dakota&nbsp;RMP modified the 1988&nbsp;RMP, including by limiting development of oil and gas in low-potential areas and new coal leasing to areas within four miles of existing mines.</p>', '2025-07-18T21:25:55Z', '00', 1072);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (123, '2025-05-05', 'Introduced in House', '<p>This resolution expresses support for the designation of a National Day of Awareness for Missing and Murdered Indigenous Women and Girls.</p>', '2025-08-04T14:03:33Z', '00', 1077);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (124, '2025-07-23', 'Introduced in House', 'This bill designates the facility of the United States Postal Service located at 6444 San Fernando Road in Glendale, California, as the "Paul Ignatius Post Office".', '2025-08-06T04:53:08Z', '00', 1083);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (125, '2025-02-26', 'Introduced in House', '<p><strong>Securing Our Lands and Resources Act or the SOLAR Act</strong></p><p>This bill prohibits the Department of Agriculture from providing financial assistance for certain projects that would result in the conversion of covered farmland for solar energy production.</p><p>Under the bill, <em>covered farmland</em> generally refers to prime farmland, unique farmland, and farmland that is of statewide or local importance. <em>Conversion</em> means any activity that results in the covered farmland no longer meeting certain requirements for agricultural production, activity, or use.</p><p>The bill includes an exception for certain smaller projects that&nbsp;result in&nbsp;the conversion of (1) less than 5 acres of covered farmland, or (2)&nbsp;less than 50 acres of covered farmland if the majority of the energy produced by the project is for on-farm use.</p><p>The bill also includes an exception for projects that have the approval or support from the local county and municipality. For these projects, the applicant must (1) develop a farmland conservation plan for the project (e.g., implementing best practices to protect future soil health and productivity), and (2) ensure that sufficient funds are provided for the decommissioning of the solar energy production system and the remediation and restoration of the farmland.</p>', '2025-04-23T14:24:11Z', '00', 1097);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (126, '2025-06-26', 'Introduced in House', '<p><strong>Bridge Corrosion Prevention and Repair Act of 2025<strong></strong></strong></p><p>This bill establishes certain requirements to address corrosion control in bridge and railroad-bridge projects that receive federal assistance.</p><p>Specifically, certified contractors must employ a substantial number of individuals who are certified by a qualified training program in corrosion control, mitigation, and prevention in order to work on certain aspects of bridge project activities. A certified contractor must also provide training for any non-certified coating applicators employed by the contractor to work on certain aspects of a project.</p><p>The bill further requires bridge projects to implement a corrosion management system that utilizes industry-recognized standards and corrosion mitigation and prevention methods for construction, repair, and maintenance projects.</p><p>In addition, the bill expands the scope of the Railroad Rehabilitation and Improvement Financing Program to include corrosion control work on rail bridges. (This program provides direct loans and loan guarantees for the development of railroad infrastructure.)</p><p>The bill also requires the Department of Transportation to study and report on best practices for inspecting and addressing corrosion on weathering steel bridges. This report must be made available to state and local governments, metropolitan planning organizations, and regional organizations.</p>', '2025-12-16T14:45:07Z', '00', 1113);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (127, '2026-02-04', 'Introduced in House', 'This bill designates the facility of the United States Postal Service located at 1225 Kempsville Road in Virginia Beach, Virginia, as the "Colonel Edward Shames Post Office Building".', '2026-02-19T05:20:29Z', '00', 1125);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (128, '2025-09-15', 'Introduced in House', '<p><strong>Fair and Accountable IRS Reviews Act</strong></p><p>This bill provides that an Internal Revenue Service (IRS) employee’s immediate supervisor&nbsp;for purposes of approving certain federal tax penalties is the person to whom such employee reports. The bill also provides that an immediate supervisor’s approval of certain federal tax penalties must be obtained (in writing) before any written communication related to such penalties is sent to the taxpayer.</p><p>As background, current law requires that the initial determination by an IRS employee to assess certain federal tax penalties be approved (in writing) by such employee’s immediate supervisor (or a designated higher-level official). Under IRS regulations, an immediate supervisor is any individual with responsibility to review another individual’s proposed federal tax penalties (without such proposal being subject to an intermediary’s approval). The IRS regulations also establish requirements for when such approval must be obtained based on whether the federal tax penalty is subject to pre-assessment review or raised in Tax Court proceedings.</p>', '2025-12-01T16:29:16Z', '00', 1136);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (129, '2025-03-14', 'Introduced in House', '<p><strong>Safe Routes Act of 2025</strong></p><p>This bill directs the Department of Transportation to waive vehicle weight limits for covered logging vehicles, thus allowing logging vehicles to travel on interstate highways&nbsp;in certain circumstances.</p><p>The term <em>covered logging vehicle</em> means a vehicle that (1) is transporting raw or unfinished forest products, including logs, pulpwood, biomass, or wood chips; (2) is traveling a distance&nbsp;not greater than 150 air miles on interstate highways&nbsp;from origin to a storage or processing facility; and (3) meets state legal weight tolerances and vehicle configurations for transporting raw or unfinished forest products within the state boundaries in which the vehicle is operating.</p>', '2025-04-07T12:56:24Z', '00', 1137);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (130, '2025-10-03', 'Reported to House', '<p><strong>Combatting International Drug Trafficking and Human Smuggling Partnership Act of 2025</strong></p><p>This bill expands permitted U.S. Customs and Border Protection (CBP) activities in foreign countries and provides for tort claims against the United States for certain CBP operations in foreign countries.</p><p>The bill allows officers and agents of the Air and Marine Operations of CBP to provide specified support to the government of foreign countries. In particular, officers and agents may provide support for</p><ul><li>monitoring, locating, and deterring the smuggling of illegal drugs, persons, or goods into the United States;</li><li>tracking terrorist or other threats to the United States;</li><li>emergency humanitarian efforts; and</li><li>law enforcement capacity-building efforts.</li></ul><p>The bill also allows CBP to expend appropriated funds to pay claims for&nbsp;money damages made against the United&nbsp;States&nbsp;that arise in a foreign country in connection with CBP operations. This includes money damages for injury, loss of property, personal injury, or death caused by certain acts or omissions of an employee of the agency while acting within the scope of his or her office or employment. Under current law, acts occurring in foreign countries are excepted from the Federal Tort Claims Act.</p><p>Claims made under the bill must be made no more than two years after the date of the incident. The authority to expend funds for such damages expires five years after the date of enactment of the bill.&nbsp;</p>', '2025-11-13T21:45:25Z', '07', 1175);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (131, '2025-02-10', 'Introduced in House', '<p><strong>Blind Americans Return to Work Act of 2025</strong></p><p>This bill requires the Social Security Administration to carry out a demonstration project during which blind Social Security Disability Insurance (SSDI)&nbsp;beneficiaries receive reduced benefits commensurate with income above certain thresholds.</p><p>Under current law, only individuals who earn under a specified monthly income, known as the <em>substantial gainful activity</em> (SGA) threshold, are considered disabled and thereby eligible for SSDI benefits. For blind workers, this limit is $2,700 per month in 2025. SSDI beneficiaries may earn beyond the SGA threshold for a limited period of time, known as the <em>trial work period</em>, before their benefits are suspended and ultimately terminate.</p><p>The bill establishes a 20-year demonstration project during which individuals who are entitled to SSDI benefits by reason of blindness and who earn above the SGA threshold  continue to receive benefits at an amount gradually reduced commensurate with their earnings beyond a specified amount.</p><p>During this period, blind workers’ SSDI benefits must be reduced by $1 for every $2 that a worker earns above the sum of (1) the SGA threshold, and (2) the worker’s expenses reasonably attributable to their work. The SGA threshold may not be used to determine whether an individual is disabled during this period, and blind workers’ SSDI benefits may not be terminated due to work-related earnings. The trial work period also must not apply.&nbsp;</p><p>After 10 years, affected beneficiaries may opt out of the modified benefits structure.&nbsp;</p>', '2025-08-04T18:29:30Z', '00', 1181);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (132, '2025-05-20', 'Introduced in House', '<p>This resolution provides for immediate consideration by the House of Representatives of H.R. 2550, the <em>Protect America''s Workforce Act</em>, a bill nullifying <a href="https://www.federalregister.gov/d/2025-05836">Executive Order 14251</a>, entitled <em>Exclusions from Federal Labor-Management Relations Programs</em> (issued on March 27, 2025).</p><p>The Executive Order excludes specified federal agencies from substantive and procedural requirements that generally apply to federal employees'' labor organizing and collective bargaining, as well as respective management obligations.</p>', '2025-11-21T21:40:57Z', '00', 1182);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (133, '2025-02-26', 'Introduced in House', '<p><strong>Department of Homeland Security Vehicular Terrorism Prevention and Mitigation Act of 2025</strong></p><p>This bill directs the Department of Homeland Security (DHS) to submit a report to Congress on the department''s efforts to prevent, deter, and respond to vehicular terrorism (i.e., an action that utilizes automotive transportation to commit terrorism). DHS must submit the report in coordination with the Transportation Security Administration and the Cybersecurity and Infrastructure Security Agency.</p><p>Among other things, the report on vehicular terrorism must include</p><ul><li>an assessment of the current and emerging threats;</li><li>a review of higher-risk locations and events that may be vulnerable, including critical infrastructure sites&nbsp;(e.g., airports and government facilities);</li><li>a description of DHS’s coordination efforts with federal, state, local, tribal, and territorial law enforcement agencies related to prevention; and</li><li>recommendations for the research, development, and deployment of technologies to detect, deter, and mitigate vehicular terrorism.</li></ul><p>DHS must submit a classified report to Congress, but may include an unclassified executive summary. DHS must publish the executive summary on the department''s&nbsp;website.</p><p>In addition,&nbsp;DHS must&nbsp;brief Congress on the report''s findings, conclusions, and recommendations.</p>', '2025-04-22T12:51:11Z', '00', 1187);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (134, '2025-02-10', 'Introduced in House', '<p><strong>Port Crane Security and Inspection Act of 2025 </strong></p><p>This bill limits the operation of foreign cranes at U.S. ports. In general,<em>&nbsp;foreign cranes </em>are those that&nbsp;have information technology and operational technology components that (1) were manufactured by companies that are subject to the ownership, control, or influence of a country designated as a foreign adversary; and (2) connect to ports'' cyber infrastructure.</p><p>Foreign cranes that are contracted for on or after the date of the bill''s enactment may not operate at a U.S. port. Also, beginning five years after this bill is enacted, foreign cranes operating at U.S. ports may not use software or other technology manufactured by a company owned by a country designated as a foreign adversary.</p><p>Additionally, the Cybersecurity and Infrastructure Security Agency (CISA) must (1) inspect foreign cranes&nbsp;for potential security risks or threats before they are placed into operation, (2) assess the threat posed by security risks or threats of existing or newly constructed foreign cranes, and (3) take any crane that poses a security risk or threat offline until the crane can be certified as no longer being a risk or threat.</p><p>CISA must also report to Congress about security risks or threats posed by foreign cranes at U.S. ports.</p>', '2025-04-08T13:46:03Z', '00', 1190);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (135, '2026-02-05', 'Introduced in House', 'This bill designates the facility of the United States Postal Service located at 15422 NY 104 in Martville, New York, as the "Sergeant Staret J. Engleston Memorial Post Office Building".', '2026-02-20T11:19:46Z', '00', 1203);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (136, '2025-02-12', 'Introduced in House', '<p><strong>Alternatives to Prevent Addiction In the Nation Act or the Alternatives to PAIN Act</strong></p><p>This bill reduces&nbsp;cost-sharing and prohibits the imposition of certain utilization requirements under the Medicare prescription drug benefit for certain non-opioid pain management drugs.</p><p>Specifically, the bill requires such drugs to be covered without a deductible and to be placed on the lowest cost-sharing tier (if any). The bill also prohibits the imposition of prior authorization requirements (i.e., requiring prior approval from a plan) or step therapy requirements (i.e., requiring the use of alternative drugs before a drug is covered under a plan) with respect to such drugs.</p>', '2025-05-21T20:34:14Z', '00', 1205);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (137, '2025-11-17', 'Introduced in House', '<p>This resolution expresses that the House of Representatives disapproves of the behavior of Representative Jesús G. “Chuy” García of Illinois.</p>', '2025-11-19T16:07:22Z', '00', 1219);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (138, '2026-02-04', 'Reported to House', '<p><strong>Homeowner Energy Freedom Act </strong></p><p>This bill repeals the Department of Energy''s (1) high-efficiency electric home rebate program for certain electrification projects in low- or moderate-income households, (2) state-based home energy efficiency contractor training grants, and (3) assistance for states and local governments to adopt specified building energy codes. It also rescinds any unobligated balances available for the rebates or adopting the building energy codes. (The unobligated balances for the contractor training grants&nbsp;were previously rescinded by the 2025 reconciliation act.)</p>', '2026-02-23T13:36:28Z', '07', 1224);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (139, '2026-01-22', 'Introduced in House', '<p>This joint resolution nullifies legislation enacted by the Council of the District of Columbia (DC) on December 20, 2025, titled DC Income and Franchise Tax Conformity and Revision Temporary Amendment Act of 2025. The nullification reinstates certain DC tax code provisions that were in place before the enactment of the DC legislation and that address, among other things, the standard tax deduction, taxation of tipped wages, and depreciation of qualified property.</p><p>As background, DC automatically adopts, as DC law, changes to federal tax law (known as rolling conformity). Upon enactment of <a href="https://www.congress.gov/bill/119th-congress/house-bill/1?s=7&amp;r=1">H.R.1</a> (commonly known as the&nbsp;One Big Beautiful Bill Act),&nbsp;its tax provisions became DC law, including provisions that increase the standard tax deduction,&nbsp;exempt tips from taxable income, and provide for an elective 100% depreciation allowance for nonresidential real property. The DC legislation subsequently decoupled the DC tax code from&nbsp;these and other tax provisions that originated in H.R.1, and it amended several other provisions in the DC tax code, including restoring the DC child tax credit.</p>', '2026-02-03T17:30:16Z', '00', 1235);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (140, '2025-11-19', 'Introduced in House', '<p><strong>Congressional Budget Office Scheduling Reform Act</strong></p><p>This bill requires the Congressional Budget Office (CBO) to annually publish a schedule of the expected publication dates of its major recurring reports.</p><p>The schedule must&nbsp;must include, at a minimum, the expected publication dates for</p><ul><li>the baseline for the budget year and subsequent updates,</li><li>the report on options to reduce the deficit,</li><li>the report on the accuracy of budgetary projections for the most recently completed fiscal year, and</li><li>the report on programs or activities with unauthorized appropriations.</li></ul><p>CBO must (1) publish the schedule on its public website no later than December 31 of each year, and (2) update the schedule during the following calendar year as necessary. &nbsp;</p>', '2026-01-05T16:54:38Z', '00', 1238);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (141, '2025-10-03', 'Introduced in House', '<p><strong>Pay Our Public Shipyard Workers Act</strong></p><p>This bill provides continuing appropriations to pay public shipyard workers during any period in which interim or full-year appropriations for FY2026 or FY2027 are not in effect (i.e., a government shutdown).</p><p>Specifically, the bill provides continuing appropriations to provide pay and allowances to civilian and military public shipyard workers who work during the government&nbsp;shutdown.</p><p>If a government shutdown occurs, the bill provides the continuing appropriations until the earlier of (1) the enactment into law of specified appropriations legislation, or (2) January 1, 2027.&nbsp;</p>', '2025-10-07T13:44:04Z', '00', 1245);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (142, '2025-02-06', 'Introduced in House', '<p><strong>Protect Our Letter Carriers Act of 2025</strong><br/><br/>This bill requires or authorizes certain actions related to the U.S. Postal Service (USPS).<br/><br/>The bill requires the Department of Justice to appoint an assistant U.S. attorney in each judicial district to coordinate and supervise the investigation and prosecution of various crimes related to postal services (for example, assault on a postal service employee, breaking into a post office, or obstruction of mails). <br/><br/>The bill also requires the U.S. Sentencing Commission to amend sentencing guidelines to provide that the assault or robbery of a postal employee shall be treated the same as the assault of a law enforcement officer.</p><p>Additionally, the bill authorizes appropriations for the USPS to install high security collection boxes and replace older versions of the universal mailbox key with electronic versions.</p>', '2025-04-10T14:09:27Z', '00', 1248);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (143, '2025-08-01', 'Introduced in House', '<p><strong>Protecting Health Care and Lowering Costs Act 2025</strong></p><p>This bill makes permanent temporary provisions that generally expand eligibility for and increase the amount of the premium tax credit.&nbsp;This bill also repeals multiple Medicaid, Medicare, and health-related tax provisions enacted by the One Big Beautiful Bill Act (OBBBA).</p><p>Currently, eligible taxpayers may claim the premium tax credit, which applies toward the cost of obtaining health insurance through health insurance exchanges. To qualify, a taxpayer’s household income must meet or exceed 100% of the federal poverty level (FPL) and, after 2025, may not exceed 400% of the FPL (maximum income limit). For 2021-2025, the maximum income limit is eliminated, which generally expands eligibility for the premium tax credit.</p><p>Further, under current law, the amount of the premium tax credit is partially based on the taxpayer’s household income multiplied by the applicable percentage. The applicable percentage varies depending on which of six income ranges (adjusted for inflation after 2025) the taxpayer’s household income falls within. For 2021-2025, the applicable percentages are lowered and the adjustment of the applicable percentages for inflation is eliminated, which generally increases the amount of the premium tax credit.</p><p>The bill permanently eliminates the 400% maximum income limit, lowers the applicable percentages, and eliminates the inflation adjustment for the applicable percentages.</p><p>Finally, the bill repeals multiple Medicaid, Medicare, and health-related tax provisions enacted by the OBBBA, including</p><ul><li>certain Medicare and Medicare eligibility and verification requirements,</li><li>the reduced window for retroactive Medicaid coverage, and</li><li>premium tax credit verification requirements.</li></ul>', '2026-01-23T16:05:02Z', '00', 1252);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (144, '2025-12-01', 'Introduced in Senate', '<p><strong>Financial Services and General Government Appropriations Act, 2026</strong></p><p>This bill provides FY2026 appropriations for several federal departments and agencies, including</p><ul><li>the Department of the Treasury,</li><li>the Executive Office of the President,</li><li>the judiciary,</li><li>the District of Columbia, and</li><li>several independent agencies.</li></ul><p>The independent agencies funded in the bill include</p><ul><li>the Administrative Conference of the United States,</li><li>the Commodity Futures Trading Commission,</li><li>the Consumer Product Safety Commission,</li><li>the Council of the Inspectors General on Integrity and Efficiency,</li><li>the Election Assistance Commission,</li><li>the Federal Communications Commission,</li><li>the Federal Deposit Insurance Corporation,</li><li>the Federal Election Commission,</li><li>the Federal Labor Relations Authority,</li><li>the Federal Permitting Improvement Steering Council,</li><li>the Federal Trade Commission,</li><li>the General Services Administration,</li><li>the Harry S. Truman Scholarship Foundation,</li><li>the Merit Systems Protection Board,</li><li>the Morris K. Udall and Stewart L. Udall Foundation,</li><li>the National Archives and Records Administration,</li><li>the National Credit Union Administration,</li><li>the Office of Government Ethics,</li><li>the Office of Personnel Management,</li><li>the Office of Special Counsel,</li><li>the Privacy and Civil Liberties Oversight Board,</li><li>the Public Buildings Reform Board,</li><li>the Securities and Exchange Commission,</li><li>the Selective Service System,</li><li>the Small Business Administration,</li><li>the U.S. Postal Service, and</li><li>the U.S. Tax Court.</li></ul><p>The bill also sets forth requirements and restrictions for using funds provided by this and other appropriations acts.</p>', '2025-12-10T15:05:04Z', '00', 1264);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (145, '2025-03-11', 'Introduced in Senate', '<p>This bill revises Chapter 22 of the Harmonized Tariff Schedule of the United States to provide a uniform rate of duty for all whiskies.</p>', '2025-06-25T13:01:18Z', '00', 1268);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (146, '2023-05-17', 'Introduced in House', ' <p>This concurrent resolution permits the Greater Washington Soap Box Derby Association to sponsor soap box derby races on the Capitol grounds on June 17, 2023.</p>', '2023-06-09T13:08:28Z', '00', 1270);
