INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (150, '2022-12-02', 'Introduced in House', ' <p>This resolution requires the printing of a revised edition of the Rules and Manual of the House of Representatives for the 118th Congress.</p>', '2022-12-21T20:21:22Z', '00', 1271);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (151, '2022-12-02', 'Passed House', ' <p>This resolution requires the printing of a revised edition of the Rules and Manual of the House of Representatives for the 118th Congress.</p>', '2023-08-15T15:57:41Z', '53', 1271);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (152, '2022-07-26', 'Introduced in House', ' <p> <p>This resolution (1) recognizes the importance of the Americans with Disabilities Act of 1990 in advancing independent living for individuals with disabilities; (2) pledges continued efforts to address remaining barriers for individuals with disabilities; and (3) calls on federal agencies to provide additional resources for individuals with disabilities with respect to economic self-sufficiency, community-based services, housing, and transportation. <p>', '2022-11-15T19:25:48Z', '00', 1272);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (153, '2022-05-10', 'Introduced in House', ' <p>This concurrent resolution permits the Greater Washington Soap Box Derby Association to sponsor soap box derby races on the Capitol grounds on June 18, 2022.</p>', '2022-10-31T16:33:46Z', '00', 1273);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (154, '2022-06-07', 'Passed House', ' <p>This concurrent resolution permits the Greater Washington Soap Box Derby Association to sponsor soap box derby races on the Capitol grounds on June 18, 2022.</p>', '2022-11-16T22:23:09Z', '53', 1273);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (155, '2022-06-16', 'Passed Senate', ' <p>This concurrent resolution permits the Greater Washington Soap Box Derby Association to sponsor soap box derby races on the Capitol grounds on June 18, 2022.</p>', '2022-11-18T19:59:10Z', '55', 1273);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (156, '2025-05-14', 'Introduced in House', '<p><strong>Middle Market IPO Cost Act </strong></p><p>This bill requires the Government Accountability Office to study and report on the costs encountered by small- and medium-sized companies when undertaking initial public offerings.</p>', '2025-07-18T19:51:58Z', '00', 1280);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (157, '2025-06-27', 'Introduced in House', '<p><strong>Treat and Reduce Obesity Act of </strong><strong>2025</strong></p><p>This bill expands Medicare coverage of intensive behavioral therapy for obesity. Specifically, the bill allows coverage for therapy that is provided by (1) a physician who is not a primary care physician; or&nbsp;(2) other health care providers (e.g., physician assistants and nurse practitioners) and approved counseling programs, if provided upon a referral from, and in coordination with, a physician or primary care practitioner. Currently, such therapy is covered only if provided by a primary care practitioner.</p><p>The bill also allows coverage under Medicare''s prescription drug benefit of drugs used for the treatment of obesity or for weight loss management for individuals who are overweight.</p>', '2025-08-05T21:33:15Z', '00', 1284);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (158, '2026-02-03', 'Introduced in House', 'This bill provides for the relief of Dr. Yue-Cheng Yang.', '2026-02-04T09:19:16Z', '00', 1285);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (159, '2025-06-27', 'Introduced in House', '<p>This bill prohibits the Government Accountability Office (GAO) from bringing a civil action under the Impoundment Control Act of 1974 (ICA) to compel the release of appropriated funds&nbsp;unless Congress has enacted a concurrent resolution authorizing GAO to bring the action.</p><p>The ICA generally limits the authority of the President to impound (i.e., withhold from obligation or expenditure) funds that have been appropriated by Congress and establishes related procedures. Under current law, GAO is authorized to bring a civil action to compel a federal agency to release budget authority for obligation if the budget authority is required to be released under the ICA, and the agency has not released the funds. This bill prohibits GAO from bringing such an action without prior congressional approval.&nbsp;</p>', '2025-09-26T16:14:56Z', '00', 1286);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (160, '2025-06-25', 'Introduced in House', '<p><strong>Agriculture, Rural Development, Food and Drug Administration, and Related Agencies Appropriations Act, 2026</strong></p><p>This bill provides FY2026 appropriations for the Department of Agriculture (USDA), the Food and Drug Administration, and related agencies.</p><p>The bill provides appropriations to USDA for agricultural programs, including</p><ul><li>the Office of the Secretary,</li><li>Executive Operations,</li><li>the Economic Research Service,</li><li>the National Agricultural Statistics Service,</li><li>the Agricultural Research Service,</li><li>the National Institute of Food and Agriculture,</li><li>the Animal and Plant Health Inspection Service,</li><li>the Agricultural Marketing Service, and</li><li>the Food Safety and Inspection Service.</li></ul><p>The bill also provides appropriations to USDA for farm production and conservation programs, including</p><ul><li>the Farm Production and Conservation Business Center,</li><li>the Farm Service Agency,</li><li>the Risk Management Agency, and</li><li>the Natural Resources Conservation Service.</li></ul><p>The bill provides appropriations to the Federal Crop Insurance Corporation Fund and the Commodity Credit Corporation Fund.</p><p>For USDA rural development programs, the bill includes appropriations for</p><ul><li>Salaries and Expenses,</li><li>the Rural Housing Service,</li><li>the Rural Business-Cooperative Service, and</li><li>the Rural Utilities Service.</li></ul><p>The bill provides appropriations to the Food and Nutrition Service for</p><ul><li>Child Nutrition Programs;</li><li>the Special Supplemental Nutrition Program for Women, Infants, and Children (WIC);</li><li>the Supplemental Nutrition Assistance Program (SNAP);</li><li>the Commodity Assistance Program; and</li><li>Nutrition Programs Administration.</li></ul><p>The bill provides appropriations to the Foreign Agricultural Service for (1) Food for Peace Title II Grants, and (2) McGovern-Dole International Food for Education and Child Nutrition Program Grants.</p><p>The bill also provides appropriations for</p><ul><li>the Food and Drug Administration,</li><li>the Commodity Futures Trading Commission, and</li><li>the Farm Credit Administration.</li></ul><p>Additionally, the bill sets forth requirements and restrictions for using funds provided by this and other appropriations acts.</p>', '2025-07-11T18:09:27Z', '00', 1287);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (161, '2025-02-27', 'Introduced in House', '<p><strong>United States Commission on International Religious Freedom Reauthorization Act of 2025</strong></p><p>This bill reauthorizes the U.S. Commission on International Religious Freedom through FY2028. The commission is an independent federal commission tasked with monitoring international religious freedom conditions, reviewing U.S. government policy, and making policy recommendations.&nbsp;</p>', '2025-05-22T13:56:09Z', '00', 1293);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (162, '2025-12-09', 'Introduced in House', '<p><strong>Next Generation 9–1–1 Act</strong></p><p>This bill establishes a grant program to support implementation of next generation 9-1-1 (NG9-1-1) systems by state, territorial, and tribal governments and requires other related activities. <em>NG9-1-1</em> means a secure, interoperable, Internet Protocol-based (IP-based) system for receiving 9-1-1 requests for emergency assistance. (IP-based 9-1-1 systems have capabilities that legacy telephone systems do not, including enhanced location-finding and the ability to receive text and multimedia messages.)</p><p>Under the bill, the National Telecommunications and Information Administration (NTIA) must provide grants to state, territorial, and tribal governments (and entities established by those governments) to support the implementation and maintenance of NG9-1-1 systems. Grant funds may also be used for public outreach on NG9-1-1, implementation of cybersecurity measures, and, subject to certain limits, training and administrative costs.</p><p>Entities applying for grants must submit a plan for NG9-1-1 coordination and implementation that ensures interoperability and reliability, incorporates cybersecurity tools, and meets other requirements related to technology and procurement. Applicants must also certify that they have established, or will establish within a specified time frame, a sustainable funding mechanism to support NG9-1-1 and effective cybersecurity resources.</p><p>The NTIA must advise applicants on the preparation of implementation plans and provide technical assistance to grant recipients.</p><p>Further, the NTIA must establish (1) an advisory board to provide recommendations with respect to the grant program and other topics related to NG9-1-1; and (2) a cybersecurity center to coordinate with state, local, and regional governments on the sharing of cybersecurity information related to NG9-1-1.</p>', '2026-02-23T18:42:46Z', '00', 1301);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (163, '2026-01-15', 'Reported to House', '<p><strong>Housing for the 21st Century Act<br/><br/></strong>This bill revises federal housing programs, including by expanding available financing for affordable housing and providing grants for planning and community development activities.<br/><br/>For example, the bill increases the statutory maximum loan limits for mortgage insurance programs administered by the&nbsp;Federal Housing Administration&nbsp;for multifamily homes and requires the use of a more specific inflation index for such loans.<br/><br/>The bill also increases the maximum&nbsp;eligible income for the Department of Housing and Urban Development''s (HUD''s) HOME Investment Partnerships Program (grants to states and localities to support housing for low-income households) and&nbsp;establishes a grant program to assist regional, state, and local entities with&nbsp;strategies to support affordable housing.<br/><br/>In addition, the bill</p><ul><li>exempts certain housing-related activities from the environmental review process, including certain construction, improvement, or rehabilitation of residential buildings;</li><li>excludes veterans'' disability benefits from being considered as income for purposes of determining eligibility for the Veterans Affairs Supportive Housing (VASH) program;</li><li>establishes a pilot program to provide grants to public housing agencies (PHAs) and other owners of federally assisted housing to  test the efficacy of temperature sensors to support compliance with temperature requirements;</li><li>eliminates the requirement that manufactured homes must be constructed with a permanent chassis; and</li><li>authorizes HUD to conduct performance reviews of organizations that&nbsp;provide&nbsp;housing counseling services.</li></ul><p>The bill also expands oversight of HUD and PHAs, such as by requiring PHAs to post information about contracts on their websites.</p><p>For more information about this bill, see <a href="https://www.congress.gov/crs-product/R48849#_Toc221206484">CRS Report&nbsp;</a><a href="https://www.congress.gov/crs-product/R48849#_Toc221206484">R48849</a>.&nbsp;</p>', '2026-02-09T18:39:35Z', '07', 1311);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (164, '2025-07-15', 'Introduced in House', '<p><strong>Farmers First Act of 2025</strong></p><p>This bill extends through FY2030 and revises the Farm and Ranch Stress Assistance Network (FRSAN). This Department of Agriculture program provides competitive grants to states, Indian tribes, and qualified nonprofit organizations to provide stress assistance programs (i.e., professional agricultural behavioral health counseling, helplines, and resources) to individuals engaged in farming, ranching, and agriculture-related occupations.</p><p>The bill specifies that the grant funding for farm telephone helplines and websites may also be used for crisis lines.</p><p>Further, FRSAN grant recipients may establish referral relationships with providers, including Certified Community Behavioral Health Clinics, health centers, rural health clinics, and critical access hospitals.</p>', '2025-08-07T10:42:28Z', '00', 1315);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (165, '2025-09-04', 'Introduced in House', '<p><strong>District of Columbia Policing Protection Act</strong></p><p>This bill&nbsp;repeals restrictions on the circumstances under which law enforcement officers in the District of Columbia (DC) may engage in vehicular pursuits (i.e., police chases) of suspects fleeing in motor vehicles, and instead generally requires such pursuits in the absence&nbsp;of other means of apprehension.</p><p>Currently, pursuant to DC''s Comprehensive Policing and Justice Reform Amendment Act of 2022, law enforcement officers generally may not engage in vehicular pursuits of suspects fleeing in motor vehicles unless the officer reasonably believes (1) the suspect was involved in a crime of violence or poses an immediate and serious threat to another person, (2) the pursuit is necessary to prevent that threat and is not likely to result in death or serious injury to any person, and (3) all other options have been exhausted or are unreasonable given the circumstances.</p><p>The bill repeals these restrictions and instead&nbsp;requires law enforcement officers&nbsp;to engage in vehicular pursuits of suspects fleeing in motor vehicles&nbsp;unless the officer or a higher-ranking officer reasonably believes that (1) such pursuit would be futile, (2) the pursuit would entail an unacceptable risk of harm to a person other than the suspect, or (3)&nbsp;the suspect can be apprehended more effectively or expeditiously by other means.</p><p>The bill also requires the Department of Justice to report to Congress on the costs and benefits of DC’s Metropolitan Police Department adopting technology that alerts the public of an active police pursuit in their immediate vicinity.&nbsp;</p>', '2025-09-12T21:12:06Z', '00', 1323);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (166, '2025-07-31', 'Reported to Senate', '<p><strong>She Develops Regulations In Vehicle Equality and Safety Act or the She DRIVES Act</strong></p><p>This bill directs the Department of Transportation (DOT) to revise motor vehicle&nbsp;safety standards to require the use of certain anthropomorphic test devices (i.e., crash test dummies) and testing on female crash test dummies.</p><p>Specifically, DOT must issue final rules to revise the current testing regulations to include specific adult male and adult female frontal impact and side impact crash test dummies. </p><p>The final rules must establish or update the testing injury criteria based on real-world injuries and the greatest potential to increase safety. The injury criteria must include head, neck, chest, abdomen, pelvis,&nbsp;upper leg, and lower leg criteria for the crash test dummies.</p><p>The final rules must also establish crashworthiness frontal and side impact tests for adult female occupants in all front seating positions that are currently tested for adult male occupants (as of the date of the bill''s enactment).</p><p>Further, DOT must promulgate a final decision notice to update the testing procedures for the &nbsp;New Car Assessment Program of the National Highway Traffic Safety Administration to require the use of these crash test dummies&nbsp;for frontal and side impact&nbsp;crashworthiness testing.</p><p>Finally, DOT must submit reports to Congress that, among other things, identify timelines for DOT to incorporate additional types of crash test dummies into the regulations and identify testing devices used in other countries for similar&nbsp;crashworthiness standards.</p>', '2026-03-12T16:01:48Z', '25', 1331);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (167, '2025-11-07', 'Introduced in House', '<p><strong>Keep SNAP and WIC Funded Act of 2025</strong></p><p>This bill provides FY2026 appropriations for the Department of Agriculture (USDA) to continue operating the Supplemental Nutrition Assistance Program (SNAP); the Special Supplemental Nutrition Program for Women, Infants, and Children (WIC); and a related block grant program if there is a lapse in FY2026 appropriations for USDA.</p><p>Specifically, the bill provides appropriations to USDA for any period in which legislation to provide FY2026 interim continuing appropriations or full-year appropriations for USDA has not been enacted. If such a lapse in appropriations occurs, the bill provides the appropriations that are necessary to continue</p><ul><li>providing uninterrupted SNAP benefits,</li><li>providing consolidated block grants to Puerto Rico and American Samoa for nutrition assistance programs, and</li><li>carrying out&nbsp;WIC without interruption.</li></ul><p>In addition, the bill provides appropriations to pay any benefits under these programs that were missed on or after September 30, 2025, and before this bill is enacted.</p><p>The appropriations for these purposes are available until the earlier of (1) the&nbsp;enactment into law of legislation to provide FY2026 appropriations for USDA (including continuing appropriations), or (2) September 30, 2026.&nbsp;</p><p>The bill also requires USDA to use the funds provided by this bill to reimburse state agencies for costs that were incurred to carry out these programs during a lapse in appropriations, to the extent that the programs were carried out in accordance with federal law (including regulations) during the lapse.&nbsp;</p>', '2025-11-10T14:45:49Z', '00', 1336);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (168, '2026-03-04', 'Introduced in House', '<p>This resolution states that the House of Representatives declares it is the policy of the United States that Iran continues to be the largest state sponsor of terrorism.</p>', '2026-03-05T15:31:13Z', '00', 1373);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (169, '2025-02-13', 'Introduced in House', '<p><strong>Nationwide Consumer and Fuel Retailer Choice Act of 2025</strong></p><p>This bill amends the Clean Air Act to address the limitations on Reid Vapor Pressure (a measure of gasoline''s volatility) that are placed on gasoline during the summer ozone season. Specifically, the bill applies the waiver for Reid Vapor Pressure requirements that is applicable to gasoline blended with 10% ethanol (E10) to gasoline blended with up to 15% ethanol (E15). This change allows gasoline that is blended with 10% to 15% ethanol to be sold year-round.</p><p>Currently, states may be excluded from the waiver for Reid Vapor Pressure requirements by submitting documentation supporting that the waiver would increase air pollution. The bill nullifies existing state exclusions, but states may submit documentation after enactment of the bill to be excluded going forward.</p><p>The bill also modifies the Renewable Fuel Standard Program, which requires transportation fuel sold or introduced into commerce in the United States to contain minimum volumes of renewable fuel. Under the existing program, obligated parties, such as small refineries, must satisfy the volume obligations by either blending renewable fuels into their gasoline or diesel fuel products or by acquiring credits that represent the required renewable fuel volume. The bill directs the Environmental Protection Agency to return compliance credits to small refineries under certain circumstances.</p>', '2025-05-06T19:39:32Z', '00', 1375);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (170, '2025-12-18', 'Introduced in House', '<p><strong>Consolidating Veteran Employment Services for Improved Performance Act</strong></p><p>This bill transfers specified programs from the jurisdiction of the Department of Labor to the Department of Veterans Affairs (VA) and establishes the Office of the Deputy Under Secretary for Veterans Economic Opportunity and Transition to implement such programs.</p><p>Specifically, the bill transfers to the VA (1) job counseling, training, and placement services for veterans, (2) federal government employment services for veterans, (3) administration of employment and reemployment rights of members of the uniformed services, and (4) homeless veterans reintegration programs. The VA must include funding requests for such programs in its budget request for FY2028 and each subsequent year.</p><p>The transfer of such programs does not affect any suits, proceedings or applications for benefits, services, licenses, permits, certificates, or financial assistance that are pending on the date of the enactment of this bill.</p><p>The Office of Management and Budget is authorized to determine the functions (e.g., duties) that are transferred under this bill, and may make additional incidental dispositions of personnel, assets, liabilities, grants, contracts, property, records, and unexpended balances as may be necessary to implement this bill.</p><p>The bill also (1) modifies state responsibilities regarding the employment of full or part-time veterans’ employment specialists (currently known as veteran employment representatives), and (2) expands the purpose and responsibilities of such specialists.</p><p>The VA and Labor must jointly conduct a study and report on the implementation of the transfer of programs and functions and amendments made by this bill.</p>', '2026-02-24T23:49:06Z', '00', 1395);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (171, '2025-02-06', 'Introduced in House', '<p>This bill allows a national of the Czech Republic to qualify for E-1 nonimmigrant status if the Czech Republic provides similar nonimmigrant status to U.S. nationals. E-1 classification allows nationals of certain countries (i.e., those with a treaty of commerce and navigation with the United States, those under a qualifying international agreement, or those deemed to qualify through statute) to be admitted solely to engage in international trade, along with their families and employees.</p>', '2026-02-26T15:27:01Z', '00', 1399);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (172, '2025-05-13', 'Introduced in House', '<p><strong>Greenlighting Growth Act</strong></p><p>This bill limits the financial information an emerging growth company (EGC) must submit to the Securities and Exchange Commission. An EGC is a type of issuer that qualifies for reduced disclosures after its initial public offering (IPO) if its annual gross revenues are below a specific dollar amount. For example, an EGC must currently provide two years of financial statements after its IPO, rather than the three required for other companies.&nbsp;</p><p>Under the bill, an emerging growth company is not required to present certain financial statements from acquired companies. This applies to statements from the time period prior to the earliest audited period presented in connection with the EGC’s IPO. In addition, the bill provides that no issuer that was formerly an EGC is required to present financial statements older than its earliest audit performed in connection with its IPO.&nbsp;</p>', '2025-07-18T19:31:36Z', '00', 1400);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (173, '2025-06-24', 'Introduced in House', '<p><strong>Locating Every Disbursement in Government Expenditure Records Act or the LEDGER Act</strong></p><p>This bill requires the Department of the Treasury to implement a system that tracks all outlays from each appropriation, receipt, or other fund account in the Treasury by each department, agency, office, or other establishment in the executive, legislative, or judicial branches of the federal government. The system must also track the period of availability of the amounts in the applicable appropriation, receipt, or other fund account.</p>', '2025-07-23T10:24:57Z', '00', 1401);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (174, '2025-06-12', 'Introduced in House', '<p><strong>Patient Access to Higher Quality Health Care Act of </strong><strong>2025</strong></p><p>This bill repeals provisions under the Stark law (i.e., the Physician Self-Referral Law) that limit,&nbsp;for purposes of&nbsp;Medicare participation,&nbsp;self-referrals by newly constructed or expanded&nbsp;physician-owned hospitals.</p>', '2025-07-25T16:14:13Z', '00', 1409);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (175, '2026-02-10', 'Reported to House', '<p><strong>Home School Graduation Recognition Act</strong></p><p>This bill clarifies that students who complete their secondary education in a home school setting recognized under state law are&nbsp;high school graduates for purposes of eligibility for federal student aid.</p>', '2026-02-26T19:18:48Z', '07', 1418);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (176, '2025-12-15', 'Introduced in House', '<p><strong>Child Predators Accountability Act of 2025</strong></p><p>This bill broadens the scope of prohibited conduct under two federal criminal statutes related to the production of child pornography.&nbsp;</p><p>Under current law, both statutes prohibit employing, using, persuading, inducing, enticing, or coercing a minor to engage in sexually explicit conduct for the purpose of producing a visual depiction or transmitting a live visual depiction of the conduct.&nbsp;</p><p>This bill expands prohibited conduct to include employing, using, persuading, inducing, enticing, or coercing a minor to be depicted engaging in sexually explicit conduct. The bill also defines the term&nbsp;<em>engage in</em> to include a minor''s presence in a such a depiction regardless of whether or not the minor is participating in the sexually explicit conduct.&nbsp;</p>', '2026-01-12T19:43:38Z', '00', 1419);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (177, '2025-05-13', 'Introduced in House', 'This bill designates the facility of the United States Postal Service located at 340 East 1st Street in Tustin, California, as the "Ursula Ellen Kennedy Post Office Building".', '2025-08-01T21:32:45Z', '00', 1440);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (178, '2025-01-31', 'Introduced in House', '<p>This resolution provides amounts for the expenses of the House Committee on the Judiciary for the 119th&nbsp;Congress.</p>', '2025-04-11T13:33:10Z', '00', 1454);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (179, '2024-06-12', 'Passed House', '<p>This resolution finds Attorney General Merrick Brian Garland in contempt of Congress for failing to comply with a congressional subpoena. It also directs the Speaker of the House to (1) certify the related report from the House Judiciary Committee to the United States Attorney''s Office for the District of Columbia for criminal proceedings, and (2) take all other appropriate action to enforce the subpoena.</p>', '2025-08-20T18:41:41Z', '53', 1455);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (180, '2023-02-24', 'Introduced in House', ' <p>This resolution provides amounts for the expenses of the House Committee on the Judiciary for the 118th Congress.</p>', '2023-03-16T22:08:26Z', '00', 1457);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (181, '2023-01-09', 'Introduced in House', ' <p>This resolution temporarily establishes in the House of Representatives the Select Subcommittee on the Weaponization of the Federal Government, which is comprised of not more than 13 Members appointed by the Speaker (5 of whom shall be appointed in consultation with the minority leader).</p> <p>The subcommittee must investigate matters related to the collection, analysis, dissemination, and use of information on U.S. citizens by executive branch agencies, including whether such efforts are illegal, unconstitutional, or otherwise unethical. The subcommittee must make a final report of its findings by January 2, 2025, and terminates 30 days after filing that report.</p>', '2023-01-11T19:15:51Z', '00', 1458);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (182, '2023-01-10', 'Passed House', ' <p>This resolution temporarily establishes in the House of Representatives the Select Subcommittee on the Weaponization of the Federal Government, which is comprised of not more than 13 Members appointed by the Speaker (5 of whom shall be appointed in consultation with the minority leader).</p> <p>The subcommittee must investigate matters related to the collection, analysis, dissemination, and use of information on U.S. citizens by executive branch agencies, including whether such efforts are illegal, unconstitutional, or otherwise unethical. The subcommittee must make a final report of its findings by January 2, 2025, and terminates 30 days after filing that report.</p>', '2023-01-12T16:06:25Z', '53', 1458);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (183, '2025-07-23', 'Introduced in House', 'This bill designates the facility of the United States Postal Service located at 890 East 152nd Street in Cleveland, Ohio, as the "Technical Sergeant Alma Gladys Minter Post Office Building".', '2025-08-07T10:09:10Z', '00', 1459);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (184, '2025-09-16', 'Introduced in House', '<p>This resolution (1) condemns the assassination of Charles "Charlie" James Kirk and all forms of political violence; and (2) honors the life, leadership, and legacy of Charlie Kirk.</p>', '2025-09-17T18:32:02Z', '00', 1460);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (185, '2025-09-05', 'Reported to House', '<p><strong>Financial Services and General Government Appropriations Act, 2026</strong></p><p>This bill provides FY2026 appropriations for several federal departments and agencies, including</p><ul><li>the Department of the Treasury,</li><li>the Executive Office of the President,</li><li>the judiciary,</li><li>the District of Columbia, and</li><li>several independent agencies.</li></ul><p>The independent agencies funded in the bill include</p><ul><li>the Administrative Conference of the United States,</li><li>the Consumer Product Safety Commission,</li><li>the Election Assistance Commission,</li><li>the Federal Communications Commission,</li><li>the Federal Deposit Insurance Corporation,</li><li>the Federal Election Commission,</li><li>the Federal Labor Relations Authority,</li><li>the Federal Permitting Improvement Steering Council,</li><li>the Federal Trade Commission,</li><li>the General Services Administration,</li><li>the Harry S. Truman Scholarship Foundation,</li><li>the Merit Systems Protection Board,</li><li>the Morris K. Udall and Stewart L. Udall Foundation,</li><li>the National Archives and Records Administration,</li><li>the National Credit Union Administration,</li><li>the Office of Government Ethics,</li><li>the Office of Personnel Management,</li><li>the Office of Special Counsel,</li><li>the Privacy and Civil Liberties Oversight Board,</li><li>the Public Buildings Reform Board,</li><li>the Securities and Exchange Commission,</li><li>the Selective Service System,</li><li>the Small Business Administration,</li><li>the U.S. Postal Service, and</li><li>the U.S. Tax Court.</li></ul><p>The bill also sets forth requirements and restrictions for using funds provided by this and other appropriations acts.</p>', '2025-09-17T15:40:11Z', '07', 1469);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (186, '2025-02-05', 'Introduced in House', '<p><strong>Love Lives On Act of 2025</strong></p><p>This bill extends entitlement for various benefit programs and services for surviving spouses of deceased members of the Armed Forces or veterans.</p><p>The bill provides that the remarriage of a surviving spouse must not bar the furnishing of dependency and indemnity compensation or special pension benefits to such spouse.</p><p>Additionally, the Department of Defense may not terminate the payment of an annuity for a surviving spouse under the Survivor Benefit Plan solely because the surviving spouse remarries.</p><p>The bill also expands the definition of a dependent under TRICARE to include a remarried widow or widower whose subsequent marriage has ended due to death, divorce, or annulment.</p>', '2025-04-29T21:14:56Z', '00', 1470);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (187, '2025-01-23', 'Introduced in House', '<p><strong>Combat Veterans Pre-Enrollment Act of 2025</strong></p><p>This bill requires the Department of Veterans Affairs (VA) to establish a program to carry out all activities necessary to permit certain members of the Armed Forces to elect to enroll in the VA health care system on the date of separation of such members from active service. Specifically, the program is for those who served on active duty in a theater of combat operations during a period of war after the Persian Gulf War or in combat against a hostile force during a period of hostilities after November 11, 1998.</p><p>The VA must, in conjunction with the Department of Defense (DOD) and Department of Homeland Security, establish a mechanism to permit a member of the Armed Forces to elect to pre-enroll in the VA health care system during the 180-day period preceding the date of separation of the member from active service.</p><p>The VA-DOD Joint Executive Committee must brief Congress on the efforts to implement such a mechanism under the program.</p><p>The Government Accountability Office must report on the program and include recommendations with respect to methods to improve the program.</p>', '2025-03-26T14:29:47Z', '00', 1471);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (188, '2025-01-06', 'Introduced in House', '<p>This joint resolution proposes an amendment to the Constitution establishing term limits for individuals serving in the Senate and the House of Representatives.</p><p>The proposed amendment makes an individual who has served two terms in the Senate ineligible for appointment or election to the Senate and an individual who has served three terms as a Member of the House of Representatives ineligible for election to the House of Representatives.</p><p>The joint resolution provides that the amendment shall be valid when ratified by the legislatures of three-fourths of the states within seven years after the date of its submission for ratification.</p><p>Under Article V of the Constitution, both chambers of Congress may propose an amendment by a vote of two-thirds of all Members present for such vote. A proposed amendment must be ratified by the states as prescribed in Article V and as specified by Congress.</p>', '2025-01-31T22:22:03Z', '00', 1482);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (189, '2024-02-20', 'Introduced in House', 'Designates the facility of the United States Postal Service located at 103 Benedette Street in Rayville, Louisiana, as the "Luke Letlow Post Office Building."', '2024-02-21T09:02:47Z', '00', 1483);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (190, '2024-11-25', 'Public Law', '<p>This act designates the facility of the U.S. Postal Service located at 103 Benedette Street in Rayville, Louisiana, as the Luke Letlow Post Office Building.</p>', '2024-12-05T18:08:06Z', '49', 1483);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (191, '2023-11-09', 'Introduced in House', '<p>This joint resolution nullifies the final rule issued by  the National Labor Relations Board titled <em>Standard for Determining Joint Employer Status</em> and published on October 27, 2023. The rule establishes  a new joint employer standard for determining whether two employers simultaneously employ a particular employee or employees.</p><p>Under the rule, an entity may be considered a joint employer of another employer''s employees if the two share or codetermine the employees'' essential terms and conditions of employment.</p><p></p><p>The rule is currently scheduled to take effect on  February 26, 2024.</p><p>&nbsp;</p>', '2025-04-21T13:24:35Z', '00', 1484);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (192, '2024-01-12', 'Passed House', '<p>This joint resolution nullifies the final rule issued by the National Labor Relations Board titled <em>Standard for Determining Joint Employer Status</em> and published on October 27, 2023. The rule establishes a new joint employer standard for determining whether two employers simultaneously employ a particular employee or employees.&nbsp;Under the rule, an entity may be considered a joint employer of another employer''s employees if the two share or codetermine the employees'' essential terms and conditions of employment.</p><p></p><p>The rule took&nbsp;effect on February 26, 2024.&nbsp;&nbsp;</p><p>&nbsp;</p>', '2025-04-21T13:22:10Z', '53', 1484);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (193, '2025-12-03', 'Introduced in House', '<p><strong>Reducing and Eliminating Duplicative Environmental Regulations Act or the RED Tape Act</strong></p><p>This bill removes the requirement under the Clean Air Act that the Environmental Protection Agency (EPA) review and comment on newly authorized federal construction projects and other major federal agency actions that already require review under the National Environmental Policy Act (NEPA) and proposed federal regulations.</p>', '2026-02-24T17:27:19Z', '00', 1490);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (194, '2025-11-17', 'Introduced in House', '<p><strong>Broadband and Telecommunications RAIL Act</strong></p><p>This bill establishes a framework for the placement or modification of broadband or telecommunications equipment in a railroad corridor.</p><p>Specifically, if a broadband or telecommunications provider is seeking to place or modify equipment within a railroad carrier’s right-of-way, the provider must submit an application to the carrier. A carrier must approve or deny an application within 60 days of receipt, and may only deny an application for safety reasons or if the placement or modification would substantially interfere with or damage railroad infrastructure. Once an application is approved, work must be scheduled in coordination with the carrier and generally must begin within 30 days. A provider must pay the railroad carrier for actual costs incurred with respect to the application.</p><p>However, if a provider has been authorized by a state or local government to place or modify equipment in a public right-of-way in an area that intersects with a railroad corridor, the provider need only notify the relevant railroad carrier and schedule the work in coordination with the carrier. Work must generally begin between 15 and 30 days after the notification is submitted. No fee is required.</p><p>A provider or carrier may petition the Federal Communications Commission (FCC) for relief if the other has failed to comply with these provisions.</p><p>The FCC must promulgate regulations to implement these provisions in a manner that ensures railroad safety, provides a timelier process for emergency situations, and prevents substantial interference with railroad infrastructure or operations, among other requirements.</p>', '2026-02-03T13:53:10Z', '00', 1492);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (195, '2025-01-16', 'Introduced in House', '<p>This bill increases the annual limit on the tax credit for qualified railroad track maintenance expenses (also referred to as the short line railroad tax credit) and expands eligibility for claiming the credit.</p><p>Under current law, the tax credit is limited each tax year to $3,500 multiplied by the sum of the number of miles of railroad track owned or leased by the taxpayer (miles owned or leased) and the number of railroad track miles assigned to the taxpayer by a Class II or III railroad (miles assigned). This bill increases the annual limit to $6,100 multiplied by the sum of miles owned or leased and miles assigned. The $6,100 amount used in the calculation of the tax credit limit is adjusted for inflation for tax years beginning after 2025.</p><p>The bill also expands eligibility for the tax credit to include gross expenses for maintaining railroad tracks owned or leased as of January 1, 2024. Under current law, the tax credit is limited to gross expenses for maintaining railroad tracks owned or leased as of January 1, 2015.</p>', '2025-02-20T15:38:20Z', '00', 1499);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (196, '2025-03-10', 'Introduced in House', '<p><strong>Sanction Sea Pirates Act of 2025</strong></p><p>This bill requires the President to impose visa- and property-blocking sanctions on any foreign person (individual or entity) that the President determines knowingly engages in piracy.&nbsp;</p><p>The bill also applies civil and criminal penalties to persons that violate, attempt to violate, conspire to violate, or cause a violation of&nbsp;the regulations promulgated to carry out such sanctions.</p>', '2025-06-23T12:11:04Z', '00', 1510);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (197, '2026-02-20', 'Introduced in House', '<p>This bill provides appropriations to the Department of Homeland Security (DHS) for the administrative expenses necessary to operate the department for the duration of a lapse in appropriations. This includes appropriations for the DHS Office of Legislative Affairs and U.S. Immigration and Customs Enforcement''s Office of Congressional Relations.</p><p>With respect to any lapse in appropriations during FY2026, DHS must use the funding provided by this bill to ensure that it&nbsp;performs all functions that would be performed in the absence of such a lapse, including responding to communications transmitted to DHS during the lapse by congressional offices. (There is currently a partial government shutdown in effect for DHS agencies and programs due to a lapse in FY2026 appropriations for DHS.)</p>', '2026-03-12T13:26:07Z', '00', 1515);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (198, '2025-09-02', 'Introduced in House', '<p>This resolution directs the Committee on Oversight and Government Reform&nbsp;to continue its investigation into the federal government''s investigation of Jeffrey Epstein and Ghislaine Maxwell and to release to the public committee records relating to the committee''s investigation, subject to limited exceptions.</p><p>Under the resolution, the committee&nbsp;records to be publicly disclosed include unclassified records referring or relating to&nbsp;Epstein''s detention and death; flight logs of aircraft owned or used by Epstein;&nbsp;individuals named in connection with&nbsp;Epstein’s criminal activities, civil settlements, or immunity or plea agreements; immunity deals, sealed settlements, or plea bargains of Epstein or his associates; entities with ties to Epstein’s trafficking or financial networks; and internal Department of Justice communications concerning decisions to investigate or charge Epstein or his associates.</p><p>The resolution&nbsp;provides that the committee may withhold or redact portions of records with written justification that such portions contain (1) victims'' personally identifiable information; (2) child sexual abuse materials; (3) images of death, physical abuse, or injury; (4) information which would jeopardize an active federal investigation or prosecution; or (5) classified information. The committee may not withhold or redact&nbsp;records on the basis of embarrassment, reputational harm, or political sensitivity.</p><p>The resolution states support for the committee''s subpoenas and investigatory actions and encourages timely compliance with them. Additionally, the committee shall issue investigative reports as it deems&nbsp;necessary.</p>', '2025-09-03T20:51:14Z', '00', 1525);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (199, '2025-07-31', 'Introduced in Senate', '<p><strong>Stopping Addiction and Falls for the Elderly Act or the SAFE Act</strong></p><p>This bill incorporates risk assessments and prevention services for falls into annual wellness visits and initial preventive physical exams under Medicare, as well as associated services provided by physical therapists and occupational therapists.<br/></p>', '2025-12-02T16:48:34Z', '00', 1529);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (200, '2025-02-06', 'Introduced in House', '<p><strong>Protecting Sensitive Locations Act</strong></p><p>This bill prohibits immigration enforcement actions within 1,000 feet of a sensitive location except in exigent circumstances, such as the&nbsp;imminent risk of death, violence, or physical harm to any person.</p><p>Sensitive locations include&nbsp;</p><ul><li>health care facilities;</li><li>schools and school bus stops;</li><li>places that provide assistance for people such as children, pregnant women, and abuse victims;</li><li>child care facilities;</li><li>places that provide disaster or emergency services;</li><li>places of worship;</li><li>courthouses and lawyers’ offices;</li><li>facilities&nbsp;used as polling&nbsp;places;</li><li>certain labor union facilities; and</li><li>public assistance offices.</li></ul><p>The prohibition shall apply to Department of Homeland Security officers and agents, as well as state employees pursuing immigration enforcement actions.</p><p>If an enforcement action is carried out in violation of this prohibition (1) no information resulting from the action may be entered into the record in a resulting removal proceeding, and (2) the affected individual may move to immediately terminate such a proceeding.</p><p>U.S. Immigration and Customs Enforcement and U.S. Customs and Border Protection shall annually report to Congress about enforcement actions taken at sensitive locations in the preceding year.&nbsp;</p>', '2026-02-25T21:00:22Z', '00', 1547);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (201, '2025-01-28', 'Introduced in House', '<p><b>Sustainable Cardiopulmonary Rehabilitation Services in the Home Act</b></p> <p>This bill permanently allows services relating to cardiac rehabilitation programs, intensive cardiac rehabilitation programs, and pulmonary rehabilitation programs to be furnished via telehealth at a beneficiary''s home under Medicare. </p>', '2025-03-18T16:27:33Z', '00', 1548);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (202, '2025-12-09', 'Introduced in Senate', '<p><strong>Stop Sextortion Act</strong></p><p>This bill criminalizes threats to distribute child sexual abuse material to intimidate, coerce, extort, or cause substantial emotional distress. This practice is commonly referred to as <em>sextortion</em>. The bill also increases criminal penalties for related offenses that involve the use of child sexual abuse material to intimidate, coerce, extort, or cause substantial emotional distress.</p><p>Specifically, the bill establishes new federal criminal offenses for threatening to distribute child pornography or a visual depiction of a minor engaging in sexually explicit conduct with intent to intimidate, coerce, extort, or cause substantial emotional distress. An offense, or an attempt or conspiracy to commit the offense, is subject to criminal penalties.</p><p>Additionally, the bill increases the maximum prison term for various offenses involving the sexual exploitation of children if those offenses involve the use of child pornography or a visual depiction of a minor engaged in sexually explicit conduct with intent to intimidate, coerce, extort, or cause substantial emotional distress.</p>', '2026-03-02T17:14:42Z', '00', 1560);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (203, '2025-02-11', 'Introduced in Senate', '<p><b>Credit Union Board Modernization Act </b></p> <p>This bill revises the required frequency of meetings held by a credit union''s board of directors. Specifically, new credit unions and credit unions with a low soundness rating must meet monthly. All other credit unions must hold at least six meetings annually, with at least one meeting held during each fiscal quarter. Currently, all credit union boards must meet at least once a month.</p>', '2025-09-26T18:38:39Z', '00', 1561);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (204, '2025-01-16', 'Introduced in House', '<p><strong>Chiropractic Medicare Coverage Modernization Act of 2025</strong><strong></strong></p><p>This bill expands Medicare coverage of chiropractic services to include all services provided by chiropractors, rather than only subluxation corrections through manual manipulation of the spine.</p>', '2025-03-10T16:32:09Z', '00', 1572);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (205, '2025-09-15', 'Introduced in House', '<p><strong>Improving Social Security''s Service to Victims of Identity Theft Act</strong></p><p>This bill requires the Social Security Administration to provide a single point of contact for any individual whose Social Security account number has been misused. The single point of contact must consist of a team or subset of specially trained employees, and must track the individual''s case to completion and coordinate with other specialized units to resolve issues as quickly as possible.</p>', '2025-11-26T20:26:35Z', '00', 1586);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (206, '2025-04-03', 'Introduced in Senate', '<p><strong>Defending Education Transparency and Ending Rogue Regimes Engaging in Nefarious Transactions Act or the DETERRENT Act</strong></p><p>This bill expands oversight and disclosure requirements related to foreign sources and institutions of higher education (IHEs).</p><p>Specifically, the bill requires an IHE to annually disclose to the Department of Education (ED) any year in which the IHE</p><ul><li>receives a gift from a foreign country of concern (e.g., China or Russia) or foreign entity of concern of any dollar amount;</li><li>receives a gift or contract from a foreign source (other than a foreign country of concern or foreign entity of concern) that is valued at $50,000 or more, considered alone or in combination with all other gifts or contracts within a calendar year (current disclosure threshold is $250,000 or more), or which has an undetermined monetary value;</li><li>enters into a contract with a foreign country of concern or foreign entity of concern after receiving a waiver for such contract; or</li><li>is substantially controlled by a foreign source.</li></ul><p>Additionally, the bill</p><ul><li>prohibits IHEs from entering into contracts with a foreign country of concern or with a foreign entity of concern without obtaining a waiver, and</li><li>requires certain IHEs to disclose gifts or contracts between covered individuals (e.g., researchers) and foreign sources.</li></ul><p>The bill requires ED to investigate possible violations of this bill and outlines the various penalties for each violation. Penalties may include losing eligibility for federal student financial aid.</p>', '2025-12-12T20:25:06Z', '00', 1595);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (207, '2025-08-15', 'Introduced in House', 'This bill designates the facility of the United States Postal Service located at 1444 Main Street in Ramona, California, as the "Archie Moore Post Office Building".', '2025-08-19T06:34:21Z', '00', 1605);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (208, '2025-03-11', 'Introduced in House', '<p><strong>Resident Education Deferred Interest Act or the REDI Act</strong><strong></strong></p> <p>This bill allows borrowers in medical or dental internships or residency programs to defer student loan payments until the completion of their programs. </p>', '2025-05-14T20:21:39Z', '00', 1639);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (209, '2025-12-12', 'Introduced in House', '<p><strong>Northern Mariana Islands Medicaid Advancement&nbsp;Act</strong></p><p>This bill requires the Medicaid funding cap for the Northern Mariana Islands to be the same as that for American Samoa in FY2026.</p>', '2026-01-26T16:44:38Z', '00', 1643);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (210, '2025-11-20', 'Introduced in House', '<p><strong>Rural Hospital Closure Relief Act of </strong><strong>2025</strong></p><p>This bill temporarily allows additional hospitals to qualify as critical access hospitals (CAHs) that receive special payment under Medicare.</p><p>Currently, in order to qualify as a CAH under Medicare, a hospital must either (1) be located more than 35 miles (or 15 miles in mountainous regions or areas with only secondary roads) from another hospital, or (2) have been certified prior to January 1, 2006, by the state as a necessary provider of services in the area.</p><p>The bill allows&nbsp;a hospital to also qualify if the hospital is a small, rural hospital that (1) serves a health professional shortage area, or a high number of low-income individuals or Medicare beneficiaries; (2) has experienced financial losses for two consecutive years; and (3) attests to having a strategic plan to address financial solvency and to committing to provide a service that is in high demand in the hospital''s service area. This authority expires nine years after the bill''s enactment.</p><p>The Government Accountability Office must study the effects of the bill''s implementation. In addition, the Medicare Payment Advisory Commission must study and recommend payment systems for rural hospitals under Medicare.&nbsp;The Centers for Medicare &amp; Medicaid Services must subsequently establish a mechanism and issue guidance on how newly designated CAHs may transition to different payment models under Medicare, including any new payment models recommended by the commission.</p>', '2026-01-23T16:03:55Z', '00', 1647);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (211, '2025-06-23', 'Introduced in House', '<p><strong>Tren de Aragua Border Security Threat Assessment Act</strong></p><p>This bill requires the Department of Homeland Security (DHS) to submit a border threat assessment and strategic plan regarding Tren de Aragua and other transnational criminal organizations. (Tren de Aragua is a gang that originated in Venezuela.)</p><p>The threat assessment must include current and potential criminal threats from&nbsp;Tren de Aragua and a description of its origins, strategic aims, funding sources, and U.S. growth and presence.</p><p>DHS must submit a strategic plan not later than one year after submission of the threat assessment. The plan must include, for example, a consideration of the threat assessment and mitigation efforts regarding Tren de Aragua and other transnational criminal organizations and efforts to disseminate information between DHS and other departments, agencies, and law enforcement entities with missions associated with the border.</p>', '2025-11-14T15:13:45Z', '00', 1649);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (212, '2026-01-30', 'Introduced in House', '<p>This resolution supports the designation of  the International Year of the Woman Farmer and recognizes the critical role of women in agriculture.</p><p>The resolution also encourages citizens to celebrate the impact these women have on the&nbsp;food systems and agricultural workforce of the United States by encouraging and empowering women to pursue careers in agriculture and cultivate leadership opportunities.</p>', '2026-03-12T12:31:39Z', '00', 1667);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (213, '2025-01-28', 'Introduced in Senate', '<p><strong>Veterans'' Assuring Critical Care Expansions to Support&nbsp;Servicemembers (ACCESS) Act of 2025</strong></p><p>This bill addresses the administration of the Veterans Community Care Program (VCCP) and other Department of Veterans Affairs (VA) health care matters.</p><p>Among other provisions regarding the VCCP, the bill</p><ul><li>establishes in statute access standards that determine when a veteran is eligible to receive non-VA care through the VCCP,</li><li>requires the VA to notify veterans regarding their eligibility for care within two business days after the VA is aware the veteran is seeking care, and</li><li>extends the deadline for the submittal of claims under the&nbsp;VCCP by health care entities and providers.</li></ul><p>The VA must address its mental health treatment programs by</p><ul><li>establishing a standardized screening process to determine whether a veteran satisfies criteria for priority or routine admission to a mental health residential rehabilitation treatment program or a program for residential care for mental health and substance abuse disorders,</li><li>tracking the performance of medical facilities and Veterans Integrated Service Networks in meeting the requirements for mental health treatment screenings and timely admission to treatment programs under such screenings, and</li><li>establishing an appeal process for when a veteran is denied admission to a covered treatment program or is accepted into a program but not offered bed placement in a timely manner.</li></ul><p>Additionally, the VA must establish an online self-service module for veterans to request and manage appointments, track referrals, and appeal and track decisions related to requests for care.</p>', '2025-12-31T16:33:30Z', '00', 1698);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (214, '2025-01-03', 'Introduced in House', '<p><strong>Freedom from Mandates Act</strong></p><p>This bill nullifies certain executive orders regarding COVID-19 safety and prohibits the Departments of Labor and Health and Human Services (HHS) from taking specified actions with respect to vaccination against COVID-19.</p><p>Specifically, the bill nullifies Executive Order 14042 (relating to ensuring adequate COVID-19 safety protocols for federal contractors) and Executive Order 14043 (requiring COVID-19 vaccination for federal employees).</p><p>Labor may not issue any rule requiring employers to mandate vaccination of employees against COVID-19 or requiring testing of employees who are unvaccinated.</p><p>HHS may not (1) require a health care provider, as a condition of participation in the Medicare or Medicaid program, to mandate vaccination of employees against COVID-19 or require testing of employees who are unvaccinated; or (2) otherwise penalize such a provider for failure to mandate such vaccination or require such testing.</p>', '2025-02-06T15:25:49Z', '00', 1732);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (215, '2025-12-15', 'Introduced in House', '<p><strong>Combating Online Predators Act of 2025 or the COP Act of 2025</strong></p><p>This bill establishes new federal criminal offenses for threatening to distribute a visual depiction of a minor (or person believed to be a minor) engaging in sexually explicit conduct with the intent that the minor (or person believed to be a minor) create or transmit a visual depiction of sexually explicit conduct. (This practice is commonly referred to as <em>sextortion</em>.)&nbsp;The bill also prohibits attempts and conspiracies to commit the offenses.&nbsp;</p>', '2026-01-09T17:18:04Z', '00', 1739);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (216, '2025-09-30', 'Introduced in House', 'This bill designates the facility of the United States Postal Service located at 240 Main Street in Northport, New York, as the "Coast Guard Petty Officer 3rd Class Nate Bruckenthal Post Office Building".', '2025-10-04T10:20:32Z', '00', 1744);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (217, '2025-09-30', 'Introduced in House', 'This bill designates the facility of the United States Postal Service located at 47 Echo Avenue in Miller Place, New York, as the "Christopher Pendergast Post Office Building".', '2025-10-16T04:03:17Z', '00', 1745);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (218, '2025-09-26', 'Introduced in House', 'This bill designates the facility of the United States Postal Service located at 170 Main Street in Westhampton Beach, New York, as the "Jolly 51 Memorial Post Office Building".', '2025-10-03T07:34:21Z', '00', 1746);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (219, '2025-01-16', 'Introduced in House', '<p><strong>Saving the Civil Service Act</strong></p><p>This bill generally prohibits changes to the classification of positions in the competitive service and excepted service unless certain conditions are met.&nbsp;(Competitive service positions are subject to competitive examination&nbsp;while excepted service positions&nbsp;are appointed  under one of five schedules.&nbsp;Competitive service positions have notice and appeal requirements for adverse actions that are not applicable to most excepted positions, including those of a&nbsp;confidential, policy-determining, policy-making, or policy-advocating character under Schedule C.)</p><p>On October 21, 2020, President Donald Trump issued an executive order that placed executive agency positions that are of a confidential, policy-determining, policy-making, or policy-advocating character, and that are not normally subject to change as a result of a presidential transition, under a new Schedule F in the excepted service. The order was subsequently revoked by President Joe Biden.</p><p>The bill prohibits executive agency positions in the competitive service from being placed in the excepted service, unless such positions are placed in a schedule in the excepted service as in effect on September 30, 2020. The bill also prohibits positions in the excepted service from being placed in any schedule other than the aforementioned schedules.</p><p>Additionally, agencies may not (1) transfer occupied positions from the competitive or excepted service into Schedule C without the consent of the Office of Personnel Management, or (2) transfer employees in the excepted service to another schedule or transfer employees in the competitive service to the excepted service without employee consent.&nbsp;</p>', '2025-07-21T19:08:28Z', '00', 1762);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (220, '2025-03-10', 'Introduced in House', 'This bill designates the facility of the United States Postal Service located at 620 East Pecan Boulevard in McAllen, Texas, as the "Agent Raul H. Gonzalez Jr. Memorial Post Office Building".', '2025-08-01T21:32:45Z', '00', 1778);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (221, '2025-01-28', 'Introduced in House', '<p><strong>Transparency and Predictability in Small Business Opportunities Act</strong></p><p>This bill requires the Small Business Administration (SBA) to issue rules for disclosing information about federal contract solicitations for which small businesses were eligible and that were issued and cancelled.</p><p>Under the rules for&nbsp;such a solicitation, an agency must provide&nbsp;(1) a justification for the cancellation,&nbsp;(2) information about any plans to reissue the solicitation and any associated&nbsp;time frames,&nbsp;and (3) information about any plans to include the requirements of the solicitation in another contract or task order of the agency.</p><p>Additionally, for such solicitations that an agency does not intend to reissue, the SBA must provide procedures for the agency to refer a small business that prepared a bid for such covered solicitation to the&nbsp;Office of Small and Disadvantaged Business Utilization for assistance in identifying similar contracting opportunities.</p>', '2025-05-30T13:18:15Z', '00', 1783);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (222, '2025-01-22', 'Introduced in House', '<p><b>Neighbors Not Enemies Act</b></p> <p>This bill repeals provisions authorizing the President to apprehend and remove from the United States the citizens of a particular nation, if the United States has declared war against that nation or that nation has threatened an invasion against the United States. </p>', '2025-04-23T14:13:47Z', '00', 1792);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (223, '2026-03-04', 'Introduced in House', '<p>This resolution directs the House Committee on Ethics to preserve and publicly disclose records related to violations or alleged violations of the Code of Official Conduct involving acts of sexual harassment, unwelcome sexual advance, or sexual assault by a Member, Delegate, or Resident Commissioner. (The Code of Official Conduct is Rule XXIII of the Rules of the House of Representatives.)&nbsp;</p><p>Under the resolution, the committee must preserve all records (including investigative materials) of such a violation or alleged violation.</p><p>Further, within 60 days after the resolution is adopted, the committee must publicly release available reports, conclusions, recommendations, exhibits, and attachments related to such investigations. The personally identifiable information of victims, alleged victims, and witnesses must be redacted.</p>', '2026-03-10T14:51:33Z', '00', 1795);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (224, '2025-12-01', 'Introduced in House', '<p><strong>Information Quality Assurance Act of 2025</strong></p><p>This bill requires the Office of Management and Budget to revise the guidelines for federal agencies with respect to the dissemination or use of <em>influential information or evidence</em>, which&nbsp;means information or evidence&nbsp;about which an agency can reasonably determine that reliance on or dissemination of has, or will have, a clear and&nbsp;substantial impact on important public actions, policies or statements, or on important private sector decisions.</p><p>The guidelines must ensure that federal agencies rely on the best reasonably available influential&nbsp;information and evidence that is appropriate for the purpose when developing, issuing, or informing the public about the rules and guidance of the agency.</p><p>An agency also must publish&nbsp;(1) the critical factual material relied on as part of the rulemaking or guidance development process, and (2) a citation to any other source used to inform the rulemaking or guidance development process.</p><p>The guidelines must also require an agency to provide certain opportunities for the public to comment on the critical factual material upon which the agency relied.</p>', '2026-02-20T14:41:07Z', '00', 1822);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (225, '2026-02-17', 'Introduced in House', '<p>This joint resolution terminates the national emergency declared by President Donald J. Trump on April 2, 2025, which imposed a 10% tariff on most imports to the United States and additional duties on specified trading partners.</p>', '2026-02-19T20:07:05Z', '00', 1828);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (226, '2025-09-11', 'Introduced in House', '<p><strong>Indian Programs Advance Appropriations Act </strong><strong>of 2025</strong></p><p>This bill authorizes advance appropriations for several covered appropriations accounts of (1) the Bureau of Indian Affairs and the Bureau of Indian Education within the Department of the Interior, and (2) the Indian Health Service within the Department of Health and Human Services. The advance appropriations provide new budget authority that first becomes available for the first fiscal year after the budget year.</p><p>The covered accounts within the Bureau of Indian Affairs are (1) Operation of Indian Programs, (2) Contract Support Costs, (3) the Indian Guaranteed Loan Program, (4) Construction, and (5) Payments for Tribal Leases.</p><p>The covered accounts within the Bureau of Indian Education are (1) Operation of Indian Education Programs, and (2) Education Construction.</p><p>The covered accounts within the Indian Health Service are (1) Indian Health Services, (2) Contract Support Costs, (3) Payments for Tribal Leases, and (4) Indian Health Facilities.</p><p>The bill also requires the President''s budget and the supporting documents submitted to Congress to include detailed estimates related to the advance appropriations.</p>', '2025-09-26T18:37:19Z', '00', 1835);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (227, '2025-02-12', 'Introduced in House', '<p><strong>Give Kids a Chance Act of 2025</strong></p><p>This bill expands the Food and Drug Administration’s (FDA’s) authority with respect to research on rare pediatric diseases, including by permitting the FDA to take enforcement action against drug sponsors that fail to satisfy pediatric study requirements and by reauthorizing programs that support pediatric research.&nbsp;</p><p>Specifically, the bill</p><ul><li>modifies requirements relating to molecularly targeted pediatric cancer investigations to permit research on new drugs in combination with active ingredients that have already been approved, provided certain conditions are met;</li><li>permits the FDA to take enforcement action against drug sponsors that fail to comply with pediatric study requirements, if such sponsors demonstrated a lack of due diligence in satisfying the requirement;</li><li>renews the FDA’s authority to award priority review vouchers to sponsors of new products intended to treat rare pediatric diseases through September 30, 2029; and</li><li>reauthorizes through FY2027 certain funding for the National Institutes of Health to support priority pediatric research.&nbsp;</li></ul><p>The bill also provides statutory authority for the FDA’s interpretation of the orphan drug exclusivity period. The bill specifies, consistent with FDA regulations, that the seven-year market exclusivity period for drugs for rare diseases or conditions (i.e., orphan drugs) prohibits the approval of the same drug for the same approved use or indication with respect to the disease or condition. (In <em>Catalyst Pharmaceuticals, Inc. v. Becerra</em>, a court rejected the FDA’s interpretation and held that orphan drug exclusivity extends to all uses or indications for the disease or condition.)</p>', '2025-08-05T16:11:54Z', '00', 1840);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (228, '2025-02-21', 'Introduced in House', '<p><strong>More Options to Develop and Enhance Remote Nutrition in WIC Act of 2025 or the MODERN&nbsp;WIC Act of 2025</strong></p><p>This bill permanently allows individuals to remotely certify their eligibility for, and receive benefits through, the Special Supplemental Nutrition Program for Women, Infants, and Children (WIC).</p><p>Specifically, the bill requires that a state agency allow&nbsp;an individual seeking a WIC certification, recertification, or a nutritional risk evaluation to do so by phone or through video teleconference, in addition to the in-person option.</p><p>A state agency has 90 days to collect data for a nutritional risk evaluation&nbsp;for a remotely certified individual. Further, a&nbsp;state agency may consider an applicant who meets the income eligibility standards to be&nbsp;temporarily eligible on an interim basis&nbsp;to participate in the program and may certify the individual for immediate participation without waiting for a nutritional risk evaluation.</p><p>The bill also allows states to provide benefits on WIC electronic benefit transfer cards through mail or remote issuance instead of requiring participants to pick up or reload benefits in person at a WIC office.</p><p>Further, the Department of Agriculture must report to Congress about the use of remote technologies and other digital tools in the WIC program.</p><p>Currently, individuals are generally required to be physically present to certify their WIC eligibility and receive benefits, with exceptions. The Food and Nutrition Service&nbsp; has temporarily waived these requirements and allowed remote certification and benefits using authorities that were provided by laws that were enacted to address&nbsp;COVID-19.</p>', '2025-07-02T14:02:20Z', '00', 1852);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (229, '2025-01-03', 'Introduced in House', '<p><strong>Law Enforcement Officer Recreation Pass Act</strong></p><p>This bill directs the Forest Service and the Department of the Interior to make the National Parks and Federal Recreational Lands Pass available, without charge and for the lifetime of the passholder, to law enforcement officers.</p>', '2025-03-06T15:02:29Z', '00', 1861);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (230, '2025-01-21', 'Introduced in House', '<p><strong>Birthright Citizenship Act of 2025 </strong></p><p>This bill limits birthright citizenship by redefining what it means to be <em>subject to the jurisdiction</em> of the United States.</p><p>Currently, a person born in the United States and subject to U.S. jurisdiction is entitled to citizenship. Under the bill, a person is subject to U.S. jurisdiction if he or she is born to a parent who is (1) a U.S. citizen or national, (2) a lawful permanent resident residing in the United States, or (3) a non-U.S. national (<em>alien </em>under federal law)&nbsp;with a lawful immigration status who is performing active service in the Armed Forces.</p><p>The bill does not affect the citizenship or nationality status of any person born before the bill''s enactment date.</p>', '2025-04-22T20:43:26Z', '00', 1864);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (231, '2025-10-24', 'Introduced in House', '<p><strong>Restoring America''s Leadership in Innovation Act of 2025</strong></p><p>This bill revises several aspects of patent law.</p><p>The bill changes the U.S. patent system back to a first-to-invent system, in which the first inventor to conceive of an invention is entitled to a patent. Currently, the first person to file an application that meets all the necessary requirements is entitled to the patent.</p><p>Several types of administrative patent challenge proceedings are abolished, as well as the U.S. Patent and Trademark Office (USPTO) body that decides those proceedings.</p><p>The bill relaxes the standard for what constitutes patent-eligible subject matter. The only ineligible inventions shall be those that exist in nature independent or prior to human activity or that exist solely in the human mind.</p><p>The bill also makes it easier for a patent owner that has won an infringement case in court to secure a permanent injunction against the infringing defendant. Specifically, there shall be a presumption that further infringement would cause irreparable harm to the prevailing patent owner, and the burden shall be on the infringer to prove otherwise. (Currently, a prevailing patent owner seeking a permanent injunction must prove, among other things, that further infringement would cause irreparable harm.)</p><p>The bill limits what types of publications shall be treated as prior art that could be used to make an invention be considered to be anticipated or obvious (and therefore not patentable).</p><p>The bill authorizes the USPTO to keep and spend all the fees that it collects.</p>', '2026-03-13T20:22:15Z', '00', 1866);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (232, '2025-01-16', 'Introduced in House', '<p><strong>Veterans Member Business Loan Act</strong></p><p>This bill excludes from credit union aggregate loan limitations member business loans made to veterans.&nbsp;</p>', '2025-04-16T15:35:37Z', '00', 1869);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (233, '2026-02-11', 'Introduced in Senate', '<p><strong>21st Century WIC Act of 2026</strong></p><p>This bill permanently allows individuals to remotely certify their eligibility for, and receive benefits through, the Special Supplemental Nutrition Program for Women, Infants, and Children (WIC).</p><p>Specifically, the bill requires that a state agency allow&nbsp;an individual seeking a WIC certification, recertification, or a nutritional risk evaluation to do so by phone or through video teleconference, in addition to the in-person option.</p><p>A state agency has 90 days to collect data for a nutritional risk evaluation&nbsp;for a remotely certified individual. Further, a&nbsp;state agency may consider an applicant who meets the income eligibility standards to be&nbsp;temporarily eligible on an interim basis&nbsp;to participate in the program and may certify the individual for immediate participation without waiting for a nutritional risk evaluation.</p><p>The bill also allows states to provide benefits on WIC electronic benefit transfer cards through mail or remote issuance instead of requiring participants to pick up or reload benefits in person at a WIC office.</p><p>Further, the Department of Agriculture must report to Congress about the use of remote technologies and other digital tools in the WIC program.</p><p>Currently, individuals are generally required to be physically present to certify their WIC eligibility and receive benefits, with exceptions. The Food and Nutrition Service has temporarily waived these requirements and allowed remote certification and benefits using authorities that were originally provided by laws that were enacted to address&nbsp;COVID-19.</p>', '2026-03-04T14:16:44Z', '00', 1890);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (234, '2025-07-15', 'Introduced in Senate', '<p><strong>Farmers First Act of 2025</strong></p><p>This bill extends through FY2030 and revises the Farm and Ranch Stress Assistance Network (FRSAN). This Department of Agriculture program provides competitive grants to states, Indian tribes, and qualified nonprofit organizations to provide stress assistance programs (i.e., professional agricultural behavioral health counseling, helplines, and resources) to individuals engaged in farming, ranching, and agriculture-related occupations.</p><p>The bill specifies that the grant funding for farm telephone helplines and websites may also be used for crisis lines.</p><p>Further, FRSAN grant recipients may establish referral relationships with providers, including Certified Community Behavioral Health Clinics, health centers, rural health clinics, and critical access hospitals.</p>', '2025-08-07T18:23:35Z', '00', 1896);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (235, '2025-01-15', 'Introduced in House', '<p><strong>Repealing Big Brother Overreach Act</strong></p><p>This bill repeals the Corporate Transparency Act. The act requires existing companies and newly created companies to report beneficial ownership information to the Department of the Treasury’s Financial Crimes Enforcement Network for purposes of addressing the financing of terrorism and money laundering.</p>', '2025-03-18T15:51:07Z', '00', 1901);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (236, '2025-02-10', 'Introduced in House', '<p><strong>Alpha-gal Allergen Inclusion Act</strong></p><p>This bill expands the definition of <em>major food allergen</em> to include galactose-alpha-1,3-galactose (commonly known as <em>alpha-gal</em>). Under current law, food labels generally must identify each major food allergen found in labeled food products.&nbsp;</p><p>(Certain tick bites cause an allergic condition known as alpha-gal syndrome that can result in an allergy to the alpha-gal molecule, which is found in red meat and other products made from mammals.)&nbsp;</p>', '2025-06-11T18:24:25Z', '00', 1911);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (237, '2026-01-08', 'Introduced in House', 'Sets forth the rule for consideration of the bill (H.R. 6039) to advance commonsense priorities.', '2026-01-09T10:49:54Z', '00', 1914);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (238, '2025-12-12', 'Introduced in House', 'This bill designates the facility of the United States Postal Service located at 130 North Winton Road in Rochester, New York, as the "Lieutenant James N. Lyons Post Office".', '2026-01-04T05:49:34Z', '00', 1915);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (239, '2025-01-31', 'Introduced in House', '<p><strong>Medicare Patient Access and Practice Stabilization Act of 2025</strong></p><p>This bill increases certain payment adjustments under the Medicare physician fee schedule for services furnished between April 1, 2025, and January 1, 2026.</p>', '2025-04-24T21:57:25Z', '00', 1922);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (240, '2025-12-11', 'Introduced in House', '<p><strong>Campus Free Speech Restoration Act</strong></p><p>This bill addresses expressive activities (e.g., peacefully assembling, distributing literature, or carrying signs) on college campuses.</p><p>First, the bill generally prohibits a public institution of higher education (IHE) that participates in federal student&nbsp;aid programs from restricting noncommercial expressive activities on campus.</p><p>Further, the bill prohibits a public IHE from receiving federal funds if the Department of Education determines that the public IHE (1) maintains a policy that infringes upon the expressive rights of students; or (2) maintains or enforces time, place, or manner restrictions on expressive activities, except in limited circumstances.</p><p>In addition, the bill prohibits retaliation against an individual because the individual reported or complained about restrictions on expressive activities or participated in an investigation or hearing.</p><p>The bill also requires a private IHE that receives federal funds to provide students with its policies related to expressive rights.</p><p>The bill also establishes a framework for investigating complaints and for IHEs to regain eligibility for federal funds.</p>', '2026-03-05T20:28:53Z', '00', 1926);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (241, '2025-03-14', 'Introduced in House', '<p><strong>Maintaining and Enhancing Hydroelectricity and River Restoration Act</strong></p><p>This bill establishes a new investment tax credit in the amount of 30% of the basis of any hydropower improvement property.</p><p>The bill defines <em>hydropower improvement property</em> as property that</p><ul><li>adds or improves fish passage at a qualified dam;</li><li>maintains or improves the quality of the water retained or released by a qualified dam;</li><li>promotes downstream sediment transport and habitat maintenance;</li><li>upgrades, repairs, or reconstructs a qualified dam to meet safety and security standards;</li><li>improves public uses of, and access to, public waterways impacted by a qualified dam;</li><li>removes an obsolete river obstruction; or</li><li>places into service an approved remote dam.</li></ul><p>Further, written approval for hydropower improvement property must be obtained from the Federal Energy Regulatory Commission or state or local officials prior to January 1, 2032.</p><p>The bill also allows an election to claim the investment tax credit for qualified progress expenses for some types of hydropower improvement property in advance of such property being placed into service. Any investment tax credit amount claimed for qualified progress expenses reduces the amount of the investment tax credit that may be claimed once the hydropower improvement property is placed into service.&nbsp;</p><p>The bill authorizes certain entities, including tax-exempt and governmental entities, to treat the investment tax credit for hydropower improvement property as a payment of tax and receive a refund of any overpayment (also known as elective pay).&nbsp;</p><p>Finally, the investment tax credit for hydropower improvement property may be transferred (i.e., sold).</p><p>&nbsp;</p>', '2025-05-14T14:16:33Z', '00', 1939);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (242, '2025-05-13', 'Introduced in House', '<p><strong>Veterans’ Security and Pay Transparency Act</strong></p><p>This bill requires the Department of Veterans Affairs (VA) to annually report to Congress on compensation paid to VA police officers.</p>', '2025-08-12T15:15:27Z', '00', 1947);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (243, '2025-02-13', 'Introduced in House', '<p><strong>Fighting Trade Cheats Act of 2025</strong></p><p>This bill increases penalties for, and establishes additional enforcement mechanisms related to, fraudulent and grossly negligent violations of U.S. customs laws.</p><p>Specifically, the bill increases the maximum civil penalty for a fraudulent violation to three times the domestic value of the merchandise. (Currently, the maximum penalty is the domestic value of the merchandise.) It prohibits a person who commits a fraudulent violation from importing merchandise into the United States for a five-year period.</p><p>Additionally, the bill increases the maximum civil penalty for a grossly negligent violation to the lesser of (1) 3 times the domestic value of the merchandise; or (2) 10 times the lawful duties, taxes, and fees. (Currently, the maximum penalty is the lesser of the domestic value of the merchandise or four times the lawful duties, taxes, and fees.) It prohibits a person who commits a grossly negligent violation from importing merchandise into the United States for a two-year period.</p><p>Further, the bill applies these importation bans to an affiliated person (e.g., a family member or employee) of the person who committed the fraudulent or grossly negligent violation.</p><p>The bill establishes a private right of action for an interested party (e.g., a manufacturer) affected by customs fraud or grossly negligent violations.</p><p>The bill prohibits any person (or an affiliated person) who commits a fraudulent or grossly negligent violation from participating in the U.S. Customs and Border Protection''s Importer of Record program, and further requires revocation of their importer of record numbers.</p>', '2025-09-10T14:28:45Z', '00', 1956);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (244, '2026-02-04', 'Introduced in House', '<p><strong>United States Capitol Police Reserve Fund Act of 2026</strong></p><p>This bill establishes the United States Capitol Police Reserve Fund for the payment of employee salaries and necessary expenses of the U.S. Capitol Police (USCP) during a lapse in appropriations for the USCP. The bill also provides appropriations for the fund.</p><p>The fund may only be used to make payments for employee salaries and necessary expenses of the USCP after the start, and before the end, of a lapse in appropriations with respect to the USCP.</p><p>Under the bill, any amounts that remain in the fund and have not been used as of December 31, 2026, must be transferred to the Department of the Treasury and rescinded. The unused funds must be transferred by January 31, 2027.&nbsp;</p>', '2026-02-24T14:12:31Z', '00', 1959);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (245, '2025-10-17', 'Introduced in House', '<p><strong>Federal Emergency Management Continuity Act of 2025</strong></p><p>This bill requires the Federal Emergency Management Agency (FEMA) to continue using certain funds in the Disaster Relief Fund (DRF) during a lapse in appropriations (i.e., government shutdown).</p><p>Specifically, FEMA must continue obligating and disbursing funds in the DRF that were appropriated before the lapse in appropriations and remain available to be expended. The funds may be used for any disaster relief, emergency assistance, and recovery program authorized under the Robert&nbsp;T. Stafford Disaster Relief and Emergency Assistance Act, including individual assistance, public assistance, and other disbursements and obligations&nbsp;for&nbsp;programs or activities necessary to protect life and property during a lapse in appropriations.</p><p>The bill also requires employees who are necessary to carry out these disbursements or related program activities to be treated as excepted employees under the Anti-Deficiency Act. (Excepted employees are required to work during a lapse in appropriations.) The bill also prohibits these employees from being subject to a furlough or a reduction in force due to a lapse in appropriations.&nbsp;</p>', '2025-10-23T18:56:18Z', '00', 1965);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (246, '2026-02-11', 'Reported to House', '<p><strong>Territorial Student Access to Higher Education Act</strong></p><p>This bill requires public institutions of higher education that participate in federal student aid programs to charge no more than in-state tuition and fee rates to students who&nbsp;are residents of Guam, the Northern Mariana Islands, American Samoa, or the U.S. Virgin Islands, provided they are also U.S. nationals.</p>', '2026-02-26T19:37:33Z', '07', 1970);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (247, '2025-02-12', 'Introduced in House', '<p><strong>Rural Obstetrics Readiness Act</strong></p><p>This bill creates and expands federal grant programs within the Health Resources and Services Administration (HRSA) to increase capacity to provide emergency obstetric health services in rural areas or areas without practitioners or facilities specializing in obstetric services.&nbsp;</p><p>Specifically,&nbsp;HRSA must establish a program for providing grants to certain hospitals or&nbsp;consortiums that include hospitals in rural areas or areas with maternal health care professional shortages for training, developing a workforce, and purchasing equipment relating to obstetric emergencies. In addition, the bill requires&nbsp;HRSA’s Alliance for Innovation on Maternal Health Capacity program to provide grants for training on emergency obstetric services for practitioners in rural health care facilities without dedicated obstetric units. HRSA must also establish a pilot program to provide grants to government entities for developing or improving telehealth access programs to support urgent maternal health care in rural facilities without a dedicated obstetric unit.&nbsp;</p>', '2025-04-30T15:49:26Z', '00', 1976);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (248, '2025-02-24', 'Introduced in House', '<p><strong>Pay Our Coast Guard Parity Act of 2025</strong></p><p>This bill provides continuing appropriations to the Coast Guard for pay and benefits when there is a Coast Guard-specific funding lapse.</p><p>Under the bill, a&nbsp;<em>Coast Guard-specific funding lapse</em> occurs when (1) a bill providing appropriations for the Coast Guard for a fiscal year has not been enacted before the beginning of that fiscal year, and no joint resolution providing continuing appropriations for the Coast Guard is in effect; and (2) a bill providing appropriations for the Department of Defense (DOD) for the fiscal year has been enacted before the beginning of the fiscal year, or a joint resolution providing continuing appropriation for DOD is in effect.&nbsp;</p><p>If a Coast Guard-specific funding lapse occurs, the bill provides appropriations to the Coast Guard for</p><ul><li>pay and allowances for military members of the Coast Guard who perform active service or inactive-duty training;</li><li>pay and benefits for certain civilian employees and contract employees;</li><li>the payment of a death gratuity;</li><li>payments for travel related to funerals, the dignified transfer of remains, and unit memorial services; and</li><li>the temporary continuation of the basic allowance for housing for dependents of members of the Coast Guard dying on active duty.</li></ul><p>The bill generally provides the appropriations to the Coast Guard until the earlier of</p><ul><li>the enactment of specified Coast Guard appropriations legislation,</li><li>the termination of the availability of appropriations for DOD, or</li><li>two weeks after the beginning of the Coast Guard-specific funding lapse.&nbsp;</li></ul>', '2025-05-15T15:28:42Z', '00', 1993);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (249, '2025-12-04', 'Introduced in House', 'This bill designates the facility of the United States Postal Service located at 35 South Main Street in Glendale, Utah, as the "Deputy Sheriff Brian Harris Post Office".', '2025-12-23T05:35:11Z', '00', 2019);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (250, '2025-01-31', 'Introduced in House', '<p><strong>Silencers Help Us Save Hearing Act or the SHUSH Act</strong></p><p>This bill removes  silencers from regulation under certain&nbsp;federal statutes governing the sale, transfer, and possession of firearms.</p><p>Specifically, it removes silencers from the list of firearms subject to regulation (i.e., registration and licensing requirements) under the National Firearms Act (NFA). Additionally, it excludes a muffler or silencer from the list of firearms subject to regulation (e.g., background check requirements) under the Gun Control Act of 1968 (GCA).</p><p>Finally, the bill does the following:</p><ul><li>preempts state or local laws that tax or regulate firearm silencers,</li><li>specifies that a person who lawfully acquires or possesses a silencer under provisions of the GCA meets the registration and licensing requirements of the NFA,</li><li>eliminates mandatory minimum prison terms for a crime of violence or drug trafficking offense in which a defendant uses or carries a firearm equipped with a silencer or muffler, and</li><li>permits active and retired law enforcement officers to carry a concealed silencer.</li></ul>', '2025-06-16T21:37:14Z', '00', 2022);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (251, '2025-10-08', 'Introduced in House', 'This bill designates the facility of the United States Postal Service located at 514 Frelinghuysen Avenue in Newark, New Jersey, as the "Mildred Joyce Coleman Crump Post Office Building".', '2025-10-16T04:03:50Z', '00', 2027);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (252, '2025-11-18', 'Introduced in House', 'This bill designates the facility of the United States Postal Service located at 2200 South Salina Street in Syracuse, New York, as the "Wallie Howard Jr. Post Office Building".', '2025-11-27T02:19:19Z', '00', 2038);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (253, '2025-04-10', 'Introduced in House', '<p><strong>Supporting Avian Virus Eradication Act or the SAVE Our Poultry Act</strong></p><p>This bill includes research on highly pathogenic avian influenza (HPAI) as a Department of Agriculture (USDA) high-priority research and extension area.</p><p>Under the bill, USDA may award grants to land-grant colleges and universities to study HPAI for the purposes of (1) developing and improving the efficacy of vaccines for poultry, and (2) enhancing biosecurity procedures for poultry producers.</p>', '2025-08-26T12:40:40Z', '00', 2071);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (254, '2025-01-03', 'Introduced in House', '<p><b>New Source Review Permitting Improvement Act</b> </p> <p>This bill modifies terminology for purposes of the New Source Review (NSR) permitting program of the Environmental Protection Agency (EPA).</p> <p>In order for a change to a stationary source to be a <i>modification</i> (a change to a stationary source that increases the air pollutant emissions or results in new pollutants) for purposes of the NSR permitting program, the maximum hourly emission rate achievable by such source must be higher than the maximum hourly rate achievable by such source during any hour in the 10-year period preceding the change.</p> <p>A change at a stationary source is not considered to be a <i>modification</i> under the bill if it is designed to (1) reduce the amount of any air pollutant emitted; or (2) restore, maintain, or improve the reliability of operations at, or safety of, the source. However, such changes are not excepted if the EPA determines the increase in the maximum achievable hourly emission rate from such change would cause an adverse effect on human health or the environment.</p> <p><i>Construction</i>, in connection with a major emitting facility (a type of stationary source), does not include a change at such a facility that does not result in a significant emissions increase or a significant net emissions increase.</p> <p>In relation to major emitting facilities in nonattainment areas, the terms <i>modifications </i>and <i>modified</i> do not include changes at such facilities that do not result in a significant emissions increase or a significant net emissions increase.</p>', '2025-02-06T18:28:15Z', '00', 2076);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (255, '2025-09-30', 'Introduced in House', '<p><strong>Fair Pay for Federal Contractors Act of 2025</strong></p><p>This bill provides back pay to employees of federal contractors who lost pay due to a lapse in appropriations (i.e., government shutdown) in FY2026.</p><p>Specifically, the bill provides appropriations for federal agencies that are subject to a lapse in appropriations in FY2026 to adjust the price of contracts to compensate federal contractors for&nbsp;providing back pay to employees who were affected by the lapse in appropriations.&nbsp;</p><p>The agencies must adjust the price of any contract for which the contractor stopped, suspended, delayed, or interrupted all or part of the work under the contract due to the lapse in appropriations. The price adjustment must compensate the contractor for reasonable costs incurred to (1) compensate employees who were furloughed or laid off, were not working, or experienced a reduction of hours or compensation due to the lapse in appropriations; or (2) restore paid leave taken by employees during the lapse in appropriations if the contractor required or permitted employees to use paid leave as a result of the lapse in appropriations.</p><p>The maximum amount of weekly compensation of an employee for which an adjustment may be made under this bill may not exceed the lesser of (1) the employee''s actual weekly compensation, or (2) $1,442 (or a lesser amount pro-rated for an employee who works less than 40 hours per week).</p><p>The bill also requires the Office of Federal Procurement Policy to submit a report to Congress on the adjustments made under this bill.</p>', '2025-10-15T14:18:11Z', '00', 2082);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (256, '2026-01-29', 'Introduced in Senate', '<p><strong>Safeguard American Voter Eligibility Act or the SAVE America Act</strong></p><p>This bill requires individuals to provide documentary proof of U.S. citizenship when registering to vote, and requires photo identification to vote,&nbsp;in federal elections.</p><p>Specifically, the bill prohibits states from accepting and processing an application to register to vote in a federal election unless the applicant presents documentary proof of U.S. citizenship.&nbsp;The bill specifies what documents are considered acceptable proof of U.S. citizenship, such as&nbsp;identification that complies with the REAL ID Act of 2005 that indicates U.S. citizenship.</p><p>Further, the bill (1) prohibits states from registering an individual to vote in a federal election unless, at the time the individual applies to register to vote, the individual provides documentary proof of U.S. citizenship; and (2) requires states to establish an alternative process to demonstrate U.S. citizenship.</p><p>Each state must take affirmative steps on an ongoing basis to ensure that only U.S. citizens are registered to vote, which shall include establishing a program to identify individuals who are not U.S. citizens using information supplied by certain sources.</p><p>Additionally, states must remove noncitizens from their official lists of eligible voters.</p><p>The bill (1) provides&nbsp;for a private right of action for certain violations, and (2) establishes criminal penalties for certain offenses.</p><p>Individuals voting in federal elections must present an eligible photo identification document. An individual who votes by absentee ballot must submit a copy of their identification document with both the request for, and the submission of, the absentee ballot.</p>', '2026-02-24T15:34:54Z', '00', 2092);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (257, '2026-02-11', 'Introduced in Senate', 'This bill designates the facility of the United States Postal Service located at 10 East Main Street in Mahaffey, Pennsylvania, as the "Robert Allen Bishop, Sr., Post Office Building".', '2026-02-25T05:04:49Z', '00', 2094);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (258, '2025-01-03', 'Introduced in House', '<p><strong>Washington, D.C. Admission Act</strong></p><p>This bill provides for the establishment of the State of Washington, Douglass Commonwealth, and its admission into the United States.</p><p>The state is composed of most of the territory of the District of Columbia (DC), excluding a specified area that encompasses the U.S. Capitol, the White House, the U.S. Supreme Court building, federal monuments,&nbsp;and federal office&nbsp;buildings adjacent to the National Mall and the U.S. Capitol. The excluded territory shall be known as the Capital and serve as the seat of the government of the United States, as provided for in Article I of the Constitution. The state may not impose taxes on federal property except as Congress permits.</p><p>The bill provides for the DC Mayor to issue a proclamation for the first elections to Congress of two Senators and one Representative of the state.&nbsp;The bill eliminates the office of Delegate to the House of Representatives.</p><p>The bill applies current DC laws to the state. DC judicial proceedings and contractual&nbsp;obligations shall continue under the state’s authority. The bill also provides for specified federal obligations to transfer to the state upon its certification that it has funds and laws in place to assume the obligations. These include maintaining a retirement fund for judges and operating public defender services.&nbsp;</p><p>The bill establishes a commission that is generally&nbsp;comprised of members who are appointed by&nbsp;DC and federal government officials to advise on an orderly transition to statehood.</p>', '2025-03-04T19:54:20Z', '00', 2103);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (259, '2025-02-13', 'Introduced in House', '<p>This bill expands the E-3 visa program to cover Irish nationals. The E-3 visa is a nonimmigrant visa currently only available to Australian nationals coming to the United States for employment in a specialty occupation. For Irish E-3 initial applications, the Department of State may approve each fiscal year no more than 10,500 minus the number of Australian initial applications approved the previous fiscal year.</p>', '2026-03-04T02:20:11Z', '00', 2110);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (260, '2025-03-14', 'Introduced in House', '<p><strong>Safe Vehicle Access for Survivors Act</strong></p><p>This bill requires providers of connected vehicle services, upon the request of a domestic violence survivor, to terminate or disable an identified domestic abuser’s access to a vehicle’s connected capabilities and data.</p><p>Specifically, within two business days of receiving a request from a survivor, a covered provider must, if technically feasible (1) terminate or disable the connected vehicle account associated with the identified abuser or the relevant vehicle, or the vehicle’s connected capabilities; or (2) instruct the survivor on how to terminate or disable connected services directly.</p><p>Covered providers may not make the termination of connected vehicle services or accounts contingent on any requirement other than the provision of specified information by the survivor. For example, a provider may not require a survivor to pay a fee or extend their contract with the provider.</p><p>Under the bill, an <em>abuser</em> is an individual identified by a survivor who committed or allegedly committed certain acts against the survivor, including domestic violence, sexual assault, stalking, and sex trafficking. A <em>survivor</em> is an adult against whom such an act was committed. Further, a <em>covered provider</em> is a vehicle manufacturer, affiliate, or entity acting on behalf of a manufacturer that provides a connected vehicle service. <em>Connected vehicle service</em> is any capability that enables a person to remotely access data from or send commands to a vehicle.</p><p>Finally, the Federal Communications Commission must prescribe regulations governing how covered providers address survivors’ requests related to connected vehicles.</p>', '2026-01-23T15:01:27Z', '00', 2128);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (261, '2025-04-01', 'Introduced in House', '<p><strong>Sanctioning Russia Act of 2025</strong><br/>&nbsp;<br/>This bill imposes penalties on certain persons (individuals and entities) if the President determines that the Russian government or a person acting at Russia''s direction is involved with (1) refusing to negotiate a peace agreement with Ukraine; (2) violating a negotiated peace agreement; (3) initiating another invasion of Ukraine; or (4) overthrowing, dismantling, or seeking to subvert the Ukrainian government.<br/>&nbsp;<br/>If the President makes such a determination, the bill requires certain actions including</p><ul><li>the President must impose visa- and property-blocking sanctions on specified persons such as the Russian president, certain Russian military commanders, and any foreign person that knowingly provides defense items to the Russian armed forces;</li><li>the President must increase the rate of duty on all goods and services imported from Russia into the United States to at least 500% relative to the value of such goods and services;</li><li>the President must increase the rate of duty on all goods and services imported into the United States from countries that knowingly engage in the exchange of Russian-origin uranium and petroleum products to at least 500% relative to the value of such goods and services;</li><li>the Department of the Treasury must impose property-blocking sanctions on any financial institution organized under Russian law and owned wholly or partly by Russia, and any financial institution that engages in transactions with those entities; and</li><li>the Department of Commerce must prohibit the export, reexport, or in-country transfer to or in Russia of any U.S.-produced energy or energy product.</li></ul>', '2025-06-10T16:25:26Z', '00', 2134);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (262, '2025-07-16', 'Introduced in House', '<p><strong>Preventive Health Savings Act</strong></p><p>This bill requires the Congressional Budget Office (CBO), upon receiving a request from Congress, to determine if proposed legislation would reduce spending outside of the 10-year budget window through the use of preventive health care.</p><p>Under the bill, the term <em>preventive health care</em> generally refers to an action that focuses on the health of the public, individuals, and defined populations in order to protect, promote, and maintain health and wellness and prevent disease, disability, and premature death.</p><p>If CBO determines that the proposed legislation would result in net reductions in budget outlays from the use of preventive health care, any CBO projection regarding the legislation must include (1) a description and estimate of the reductions in outlays, and (2) a description of the basis for these conclusions.&nbsp;</p><p>Any estimate provided by CBO pursuant to this bill must be used as a supplementary estimate and may not be used to determine compliance with the Congressional Budget Act of 1974 or any other budgetary enforcement controls.</p>', '2025-09-24T18:49:03Z', '00', 2150);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (263, '2025-10-08', 'Introduced in House', '<p><strong>Federal Worker Childcare Protection Act of 2025</strong></p><p>This bill authorizes certain federal employees to be reimbursed for childcare expenses paid during the government shutdown that began on October 1, 2025.</p><p>Under the bill, any federal employee who was furloughed or worked without receiving a paycheck during the lapse in appropriations (i.e., government shutdown)&nbsp;that began on October 1, 2025, and paid for childcare during the lapse is eligible to be reimbursed for the childcare expenses if (1) appropriations are provided for this purpose, and (2) the employee submits a receipt from a childcare provider to the General Services Administration.&nbsp;</p>', '2025-10-20T14:56:29Z', '00', 2159);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (264, '2025-12-17', 'Introduced in House', 'This bill designates the facility of the United States Postal Service located at 417 West 7th Street in Columbia, Tennessee, as the "Pharmacist''s Mate First Class John Harlan Willis Post Office Building".', '2026-01-21T05:20:45Z', '00', 2173);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (265, '2025-09-26', 'Introduced in House', '<p>This bill prohibits the removal of federal employees from the civil service during a government shutdown due to a lapse in discretionary appropriations. If an employee is removed from the civil service in violation of this bill, the employee may elect to be reinstated with back pay on the&nbsp;date on which the lapse in appropriations ends.&nbsp;</p>', '2025-10-07T13:20:10Z', '00', 2178);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (266, '2023-09-29', 'Passed House', '<p>This resolution expresses the sorrow of the House of Representatives regarding the death of the Honorable Dianne Feinstein, a Senator from California.</p>', '2025-08-11T17:51:07Z', '53', 2197);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (267, '2023-07-27', 'Introduced in House', ' <p>This resolution supports the designation of Tony Bennett Day in honor of his contributions to the arts and to society.</p>', '2023-10-12T20:21:55Z', '00', 2198);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (268, '2022-11-29', 'Introduced in House', ' <p>This concurrent resolution authorizes the use of the rotunda of the Capitol on December 6, 2022, for a ceremony to present Congressional Gold Medals to the U.S. Capitol Police and others who protected the Capitol on January 6, 2021.</p>', '2023-07-31T19:15:48Z', '00', 2199);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (269, '2022-11-30', 'Passed Senate', ' <p>This concurrent resolution authorizes the use of the rotunda of the Capitol on December 6, 2022, for a ceremony to present Congressional Gold Medals to the U.S. Capitol Police and others who protected the Capitol on January 6, 2021.</p>', '2023-07-31T20:26:25Z', '55', 2199);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (270, '2022-11-30', 'Passed House', ' <p>This concurrent resolution authorizes the use of the rotunda of the Capitol on December 6, 2022, for a ceremony to present Congressional Gold Medals to the U.S. Capitol Police and others who protected the Capitol on January 6, 2021.</p>', '2023-07-31T20:26:04Z', '53', 2199);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (271, '2021-09-10', 'Introduced in House', ' <p>This resolution recognizes September 11 as a day of solemn commemoration and extends deepest sympathies to the thousands of innocent victims of the September 11, 2001, terrorist attacks, and to their families, friends, and loved ones.</p> <p>The resolution further</p> <ul> <li> honors the heroism and sacrifices of U.S. military and civil personnel and their families,</li> <li>credits the heroism of those who aided the victims of the attacks, </li> <li>commends the military and intelligence personnel involved in the removal of Osama bin Laden, and</li> <li>reasserts the commitment to opposing violent extremism and vows to disrupt terrorists and their activities.</li> </ul>', '2021-09-24T20:39:54Z', '00', 2200);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (272, '2021-09-10', 'Passed House', ' <p>This resolution recognizes September 11 as a day of solemn commemoration and extends deepest sympathies to the thousands of innocent victims of the September 11, 2001, terrorist attacks, and to their families, friends, and loved ones.</p> <p>The resolution further</p> <ul> <li> honors the heroism and sacrifices of U.S. military and civil personnel and their families,</li> <li>credits the heroism of those who aided the victims of the attacks, </li> <li>commends the military and intelligence personnel involved in the removal of Osama bin Laden, and</li> <li>reasserts the commitment to opposing violent extremism and vows to disrupt terrorists and their activities.</li> </ul>', '2021-10-01T21:49:51Z', '53', 2200);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (273, '2021-06-28', 'Introduced in House', ' <p> This resolution establishes in the House of Representatives the Select Committee to Investigate the January 6th Attack on the United States Capitol.</p> <p> The select committee must (1) conduct an investigation of the relevant facts and circumstances relating to the attack on the Capitol; (2) identify, review, and evaluate the causes of and the lessons learned from this attack; and (3) submit a report containing findings, conclusions, and recommendations to prevent future acts of violence, domestic terrorism, and domestic violent extremism, and to improve the security of the U.S. Capitol Complex and other American democratic institutions. </p> <p> The select committee consists of 13 Members of the House appointed by the Speaker; 5 must be appointed after consultation with the minority leader. The resolution gives the select committee specified powers, including the authority to hold hearings, receive evidence, and issue subpoenas. It also requires other House committees to share relevant records with the select committee within 14 days of the resolution''s adoption or receipt of such records. </p>', '2021-07-01T11:24:20Z', '00', 2201);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (274, '2021-06-30', 'Passed House', ' <p>This resolution establishes in the House of Representatives the Select Committee to Investigate the January 6th Attack on the United States Capitol.</p> <p> The select committee must (1) conduct an investigation of the relevant facts and circumstances relating to the attack on the Capitol; (2) identify, review, and evaluate the causes of and the lessons learned from this attack; and (3) submit a report containing findings, conclusions, and recommendations to prevent future acts of violence, domestic terrorism, and domestic violent extremism, and to improve the security of the U.S. Capitol Complex and other American democratic institutions. </p> <p> The select committee consists of 13 Members of the House appointed by the Speaker; 5 must be appointed after consultation with the minority leader. The resolution gives the select committee specified powers, including the authority to hold hearings, receive evidence, and issue subpoenas. It also requires other House committees to share relevant records with the select committee within 14 days of the resolution''s adoption or receipt of such records. </p>', '2021-07-06T15:55:06Z', '53', 2201);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (275, '2025-12-05', 'Introduced in House', '<p><strong>Territories Health Equity Act of 2025</strong></p><p>This bill alters provisions relating to the treatment of U.S. territories under Medicaid, Medicare, and Medicare Advantage.</p><p>For example, the bill</p><ul><li>eliminates Medicaid funding limitations for U.S. territories beginning in FY2026,</li><li>exempts an individual from late-enrollment penalties for Medicare medical services if the individual resided in Puerto Rico as of the date of eligibility and the individual enrolls within five years of such date, and</li><li>establishes minimum criteria for certain elements used in Medicare Advantage payment calculations for areas within U.S. territories.</li></ul><p>The bill also allows residents of U.S. territories who are unable to obtain health insurance through their employer or a health insurance exchange to instead obtain coverage that is at least as broad as the coverage available to Members of Congress and their staff through the District of Columbia exchange.</p>', '2026-01-26T16:42:20Z', '00', 2222);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (276, '2025-09-12', 'Introduced in House', '<p><strong>Commerce, Justice, Science, and Related Agencies Appropriations Act, 2026</strong></p><p>This bill provides FY2026 appropriations to the Department of Commerce, the Department of Justice (DOJ), the science agencies, and several related agencies.</p><p>The bill provides appropriations to the Department of Commerce for</p><ul><li>the International Trade Administration,</li><li>the Bureau of Industry and Security,</li><li>the Economic Development Administration,</li><li>the Minority Business Development Agency,</li><li>Economic and Statistical Analysis,</li><li>the Bureau of the Census,</li><li>the National Telecommunications and Information Administration,</li><li>the U.S. Patent and Trademark Office,</li><li>the National Institute of Standards and Technology,</li><li>the National Oceanic and Atmospheric Administration, and</li><li>Departmental Management.</li></ul><p>The bill provides appropriations to DOJ for</p><ul><li>Justice Operations, Management, and Accountability;</li><li>the Executive Office for Immigration Review;</li><li>the Office of Inspector General;</li><li>the U.S. Parole Commission;</li><li>Legal Activities;</li><li>the U.S. Marshals Service;</li><li>the National Security Division;</li><li>Interagency Law Enforcement;</li><li>the Federal Bureau of Investigation;</li><li>the Drug Enforcement Administration;</li><li>the Bureau of Alcohol, Tobacco, Firearms and Explosives; and</li><li>the Federal Prison System.</li></ul><p>The bill also provides appropriations to DOJ for state and local law enforcement activities, including</p><ul><li>the Office on Violence Against Women,</li><li>the Office of Justice Programs, and</li><li>Community Oriented Policing Services (COPS).</li></ul><p>The bill provides appropriations for science agencies, including</p><ul><li>the Office of Science and Technology Policy,</li><li>the National Space Council,</li><li>National Aeronautics and Space Administration (NASA), and</li><li>the National Science Foundation.</li></ul><p>The bill provides appropriations to related agencies, including</p><ul><li>the Commission on Civil Rights,</li><li>the Equal Employment Opportunity Commission,</li><li>the U.S. International Trade Commission,</li><li>the Legal Services Corporation,</li><li>the Marine Mammal Commission,</li><li>the Office of the U.S. Trade Representative, and</li><li>the State Justice Institute.</li></ul><p>The bill also sets forth requirements and restrictions for using funds provided by this and other appropriations acts.</p>', '2025-09-22T15:01:49Z', '00', 2262);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (277, '2025-09-12', 'Reported to House', '<p><strong>Commerce, Justice, Science, and Related Agencies Appropriations Act, 2026</strong></p><p>This bill provides FY2026 appropriations to the Department of Commerce, the Department of Justice (DOJ), the science agencies, and several related agencies.</p><p>The bill provides appropriations to the Department of Commerce for</p><ul><li>the International Trade Administration,</li><li>the Bureau of Industry and Security,</li><li>the Economic Development Administration,</li><li>the Minority Business Development Agency,</li><li>Economic and Statistical Analysis,</li><li>the Bureau of the Census,</li><li>the National Telecommunications and Information Administration,</li><li>the U.S. Patent and Trademark Office,</li><li>the National Institute of Standards and Technology,</li><li>the National Oceanic and Atmospheric Administration, and</li><li>Departmental Management.</li></ul><p>The bill provides appropriations to DOJ for</p><ul><li>Justice Operations, Management, and Accountability;</li><li>the Executive Office for Immigration Review;</li><li>the Office of Inspector General;</li><li>the U.S. Parole Commission;</li><li>Legal Activities;</li><li>the U.S. Marshals Service;</li><li>the National Security Division;</li><li>Interagency Law Enforcement;</li><li>the Federal Bureau of Investigation;</li><li>the Drug Enforcement Administration;</li><li>the Bureau of Alcohol, Tobacco, Firearms and Explosives; and</li><li>the Federal Prison System.</li></ul><p>The bill also provides appropriations to DOJ for state and local law enforcement activities, including</p><ul><li>the Office on Violence Against Women,</li><li>the Office of Justice Programs, and</li><li>Community Oriented Policing Services (COPS).</li></ul><p>The bill provides appropriations for science agencies, including</p><ul><li>the Office of Science and Technology Policy,</li><li>the National Space Council,</li><li>National Aeronautics and Space Administration (NASA), and</li><li>the National Science Foundation.</li></ul><p>The bill provides appropriations to related agencies, including</p><ul><li>the Commission on Civil Rights,</li><li>the Equal Employment Opportunity Commission,</li><li>the U.S. International Trade Commission,</li><li>the Legal Services Corporation,</li><li>the Marine Mammal Commission,</li><li>the Office of the U.S. Trade Representative, and</li><li>the State Justice Institute.</li></ul><p>The bill also sets forth requirements and restrictions for using funds provided by this and other appropriations acts.</p>', '2025-09-22T14:53:55Z', '07', 2262);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (278, '2025-01-03', 'Introduced in House', '<p>This resolution provides for the President to be informed that Rep. Mike Johnson of Louisiana has been elected as Speaker and Kevin McCumber has been elected as Clerk of the House of Representatives of the 119th Congress.</p>', '2025-01-14T16:40:53Z', '00', 2263);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (279, '2024-07-11', 'Introduced in House', '<p><strong>Commerce, Justice, Science, and Related Agencies Appropriations Act, 2025</strong></p><p>This bill provides FY2025 appropriations to the Department of Commerce, the Department of Justice (DOJ), the science agencies, and several related agencies.</p><p>The bill provides appropriations to the Department of Commerce for</p><ul><li>the International Trade Administration,</li><li>the Bureau of Industry and Security,</li><li>the Economic Development Administration,</li><li>the Minority Business Development Agency,</li><li>Economic and Statistical Analysis,</li><li>the Bureau of the Census,</li><li>the National Telecommunications and Information Administration,</li><li>the U.S. Patent and Trademark Office,</li><li>the National Institute of Standards and Technology,</li><li>the National Oceanic and Atmospheric Administration, and</li><li>Departmental Management.</li></ul><p>The bill provides appropriations to DOJ for</p><ul><li>Justice Operations, Management, and Accountability;</li><li>the Executive Office for Immigration Review;</li><li>the Office of Inspector General;</li><li>the U.S. Parole Commission;</li><li>Legal Activities;</li><li>the U.S. Marshals Service;</li><li>the National Security Division;</li><li>Interagency Law Enforcement;</li><li>the Federal Bureau of Investigation;</li><li>the Drug Enforcement Administration;</li><li>the Bureau of Alcohol, Tobacco, Firearms and Explosives; and</li><li>the Federal Prison System.</li></ul><p>The bill also provides appropriations to DOJ for state and local law enforcement activities, including</p><ul><li>the Office on Violence Against Women,</li><li>the Office of Justice Programs, and</li><li>Community Oriented Policing Services (COPS).</li></ul><p>The bill provides appropriations for science agencies, including</p><ul><li>the Office of Science and Technology Policy,</li><li>the National Space Council,</li><li>National Aeronautics and Space Administration (NASA), and</li><li>the National Science Foundation.</li></ul><p>The bill provides appropriations to related agencies, including</p><ul><li>the Commission on Civil Rights,</li><li>the Equal Employment Opportunity Commission,</li><li>the U.S. International Trade Commission,</li><li>the Legal Services Corporation,</li><li>the Marine Mammal Commission,</li><li>the Office of the U.S. Trade Representative, and</li><li>the State Justice Institute.</li></ul><p>The bill also sets forth requirements and restrictions for using funds provided by this and other appropriations acts.</p>', '2024-07-26T18:09:34Z', '00', 2265);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (280, '2024-07-11', 'Reported to House', '<p><strong>Commerce, Justice, Science, and Related Agencies Appropriations Act, 2025</strong></p><p>This bill provides FY2025 appropriations to the Department of Commerce, the Department of Justice (DOJ), the science agencies, and several related agencies.</p><p>The bill provides appropriations to the Department of Commerce for</p><ul><li>the International Trade Administration,</li><li>the Bureau of Industry and Security,</li><li>the Economic Development Administration,</li><li>the Minority Business Development Agency,</li><li>Economic and Statistical Analysis,</li><li>the Bureau of the Census,</li><li>the National Telecommunications and Information Administration,</li><li>the U.S. Patent and Trademark Office,</li><li>the National Institute of Standards and Technology,</li><li>the National Oceanic and Atmospheric Administration, and</li><li>Departmental Management.</li></ul><p>The bill provides appropriations to DOJ for</p><ul><li>Justice Operations, Management, and Accountability;</li><li>the Executive Office for Immigration Review;</li><li>the Office of Inspector General;</li><li>the U.S. Parole Commission;</li><li>Legal Activities;</li><li>the U.S. Marshals Service;</li><li>the National Security Division;</li><li>Interagency Law Enforcement;</li><li>the Federal Bureau of Investigation;</li><li>the Drug Enforcement Administration;</li><li>the Bureau of Alcohol, Tobacco, Firearms and Explosives; and</li><li>the Federal Prison System.</li></ul><p>The bill also provides appropriations to DOJ for state and local law enforcement activities, including</p><ul><li>the Office on Violence Against Women,</li><li>the Office of Justice Programs, and</li><li>Community Oriented Policing Services (COPS).</li></ul><p>The bill provides appropriations for science agencies, including</p><ul><li>the Office of Science and Technology Policy,</li><li>the National Space Council,</li><li>National Aeronautics and Space Administration (NASA), and</li><li>the National Science Foundation.</li></ul><p>The bill provides appropriations to related agencies, including</p><ul><li>the Commission on Civil Rights,</li><li>the Equal Employment Opportunity Commission,</li><li>the U.S. International Trade Commission,</li><li>the Legal Services Corporation,</li><li>the Marine Mammal Commission,</li><li>the Office of the U.S. Trade Representative, and</li><li>the State Justice Institute.</li></ul><p>The bill also sets forth requirements and restrictions for using funds provided by this and other appropriations acts.</p>', '2024-07-25T18:07:12Z', '07', 2265);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (281, '2025-11-19', 'Introduced in House', '<p><strong>Strengthening Medicare for Patients and Providers Act</strong></p><p>This bill modifies certain adjustments to payment amounts under the Medicare physician fee schedule.</p><p>Payment amounts under the Medicare physician fee schedule are based on a service''s relative value, a conversion factor, and a geographic adjustment factor. Current law provides for separate conversion factors for physicians that are qualifying participants in advanced alternative payment models (also known as qualifying APM participants) and for other physicians beginning in 2026, with an annual update of 0.75% and 0.25%, respectively.</p><p>The bill replaces the separate conversion factors for qualifying APM participants and other physicians with a single conversion factor and provides for an update that is equal to the annual percentage increase in the Medicare Economic Index, beginning in 2026. (The Medicare Economic Index is a specialized index that is generally used to determine allowed charges for physician services based on annual price changes.)</p>', '2026-01-23T15:51:08Z', '00', 2281);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (282, '2025-01-16', 'Introduced in House', '<p><strong>South Pacific Tuna Treaty Act of 2025</strong></p><p>This bill revises federal requirements for U.S. commercial fishing vessels operating in the South Pacific. The changes reflect amendments to the South Pacific Tuna Treaty that were agreed to at Nadi, Fiji, on December 3, 2016. The treaty details mutual obligations of the United States and 16 Pacific Island countries when U.S. fishing vessels operate in the region.&nbsp;</p><p></p><p></p><p></p>', '2025-05-13T13:19:21Z', '00', 2284);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (283, '2025-01-15', 'Introduced in House', '<p>This bill waives certain requirements for U.S. nationals applying for citizenship. </p> <p>Currently, individuals born in an outlying possession (i.e., American Samoa or Swains Island) are U.S. nationals but do not automatically acquire citizenship through birth in an outlying possession.</p> <p>Under this bill, a U.S. national who otherwise qualifies may become a citizen upon establishing residence and physical presence in a U.S. outlying possession. Currently, U.S. nationals must become a resident of a state to qualify for naturalization.</p> <p>The bill also waives certain naturalization requirements, including those related to English language proficiency and participation in a public ceremony, for individuals who have continuously resided in an outlying possession or state from birth to the approval of a naturalization application. </p> <p>Furthermore, upon meeting other requirements, this bill allows a child born abroad of a U.S. citizen parent to acquire citizenship by establishing presence and residency in an outlying possession, where currently such a child must be lawfully present in the United States to acquire citizenship through this method.</p>', '2025-03-28T16:57:18Z', '00', 2285);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (284, '2025-01-14', 'Introduced in House', '<p>This bill permanently extends the American Samoa economic development tax credit, effective for tax years beginning after December 31, 2021.</p><p>Under current law, certain qualified domestic corporations may be entitled to a tax credit for a percentage of qualified American Samoa wages, allocable employee fringe benefits, and depreciation allowances related to qualified American Samoa tangible property. However, under current law, the tax credit is only available for such corporations for tax years beginning&nbsp;on or before December 31, 2021.</p>', '2026-03-13T14:08:49Z', '00', 2286);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (285, '2025-11-25', 'Introduced in House', 'This bill designates the facility of the United States Postal Service located at 3570 Olney Laytonsville Road in Olney, Maryland, as the "Edward L. Ramsey Olney Post Office Building".', '2025-12-10T11:04:30Z', '00', 2295);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (286, '2025-03-03', 'Introduced in House', '<p><strong>Federal Firearms Licensee Protection Act of 2025</strong></p><p>This bill modifies criminal penalties for an offense involving the theft of a firearm from a licensed importer, manufacturer, or dealer, or from their business premises.</p><p>Specifically, the bill does the following:</p><ul><li>increases from 10 to 20 years the maximum prison term, and</li><li>creates a 3- or 5-year mandatory minimum prison term for an offense that occurs during the commission of a burglary or robbery.</li></ul><p>An attempt to commit an offense is subject to the same penalties as a substantive offense.</p>', '2025-05-27T15:25:31Z', '00', 2302);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (287, '2025-03-03', 'Introduced in House', '<p><strong>Safe Schools Improvement Act</strong></p><p>This bill requires states to direct their local educational agencies (LEAs) to establish policies that prevent and prohibit bullying and harassment of elementary and secondary school students. In particular, these policies must prohibit bullying and harassment based on race, color, national origin, disability, religion, or&nbsp;sex. <em>Sex </em>includes&nbsp;sexual orientation, gender identity, and sex characteristics (including intersex traits).</p><p>Further, LEAs must provide (1) students, parents, and educational professionals with annual notice of the conduct prohibited in their disciplinary policies; (2) students and parents with grievance procedures that target such conduct; and (3) the public with annual data on the incidence and frequency of that conduct at the school and LEA level.</p><p>The Department&nbsp;of Education must conduct and report on an independent biennial evaluation of programs and policies to combat bullying and harassment in elementary and secondary schools. The National Center for Education Statistics must collect state data to determine the incidence and frequency of the conduct prohibited by LEA disciplinary policies.</p>', '2025-05-09T20:41:24Z', '00', 2333);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (288, '2025-01-16', 'Introduced in Senate', '<p><strong>Saving the Civil Service Act</strong></p><p>This bill generally prohibits changes to the classification of positions in the competitive service and excepted service unless certain conditions are met. (Competitive service positions are subject to competitive examination while excepted service positions are appointed under one of five schedules. Competitive service positions have notice and appeal requirements for adverse actions that are not applicable to most excepted positions, including those of a confidential, policy-determining, policy-making, or policy-advocating character under Schedule C.)</p><p>On October 21, 2020, President Donald Trump issued an executive order that placed executive agency positions that are of a confidential, policy-determining, policy-making, or policy-advocating character, and that are not normally subject to change as a result of a presidential transition, under a new Schedule F in the excepted service. The order was subsequently revoked by President Joe Biden.</p><p>The bill prohibits executive agency positions in the competitive service from being placed in the excepted service, unless such positions are placed in a schedule in the excepted service as in effect on September 30, 2020. The bill also prohibits positions in the excepted service from being placed in any schedule other than the aforementioned schedules.</p><p>Additionally, agencies may not (1) transfer occupied positions from the competitive or excepted service into Schedule C without the consent of the Office of Personnel Management, or (2) transfer employees in the excepted service to another schedule or transfer employees in the competitive service to the excepted service without employee consent.&nbsp;</p>', '2025-07-21T19:12:20Z', '00', 2344);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (289, '2025-10-24', 'Introduced in House', '<p>This concurrent resolution denounces socialism and opposes the implementation of socialist policies in the United States.</p>', '2025-11-17T16:47:33Z', '00', 2349);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (290, '2025-09-04', 'Introduced in House', '<p><strong>District of Columbia Judicial Nominations Reform Act</strong></p><p>This bill terminates the District of Columbia (DC) Judicial Nomination Commission. </p><p>Currently, the commission recommends to the President nominees for judges for DC''s Superior Court and Court of Appeals, who must then be confirmed by the Senate. The commission also appoints the chief judges for these courts. The bill terminates the commission''s involvement&nbsp;in nominations and requires the President to appoint the chief judges.</p>', '2025-09-15T18:59:40Z', '00', 2356);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (291, '2025-01-31', 'Introduced in House', '<p><strong>Prison Staff Safety Enhancement Act</strong></p><p>This bill requires the Department of Justice to adopt national standards for the prevention, reduction, and punishment of sexual harassment and sexual assault by incarcerated individuals against correctional officers or other employees of the Bureau of Prisons.</p>', '2025-07-21T19:44:20Z', '00', 2373);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (292, '2026-01-27', 'Reported to House', '<p><strong>Medal of Sacrifice Act of 2025</strong></p><p>This bill directs the President to issue a medal of sacrifice for eligible law enforcement officers and first responders who are killed in the line of duty.</p><p>The bill also directs the President to establish a commission on the medal of sacrifice and appoint its members. The bill sets forth responsibilities of the commission, including to advise on the design of the medal and determine how the medal will be presented.</p><p>Under the bill, eligible law enforcement officers and first responders include federal, state, local, tribal, or territorial law enforcement officers or first responders who are not subject to an official act of wrongdoing (e.g., a determination that the officer or first responder acted outside the scope of their duties or in a manner that was not in accordance with official policies or procedures).</p><p>A law enforcement officer or first responder who is subject to an official act of wrongdoing is generally not eligible for the medal of sacrifice. However, in the case of such an officer or first responder, the bill requires the commission to investigate the circumstances surrounding the officer or first responder''s cause of death and issue a final determination on their eligibility.</p>', '2026-01-29T21:28:16Z', '07', 2379);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (293, '2026-01-06', 'Introduced in House', '<p><strong>Stop Unfair Medicaid Recoveries Act&nbsp;</strong></p><p>This bill prohibits state Medicaid programs from using estate recovery to recoup the costs of benefits. States must withdraw property liens within 90 days of the bill''s enactment and notify affected individuals of the&nbsp;withdrawals.</p>', '2026-01-26T16:49:01Z', '00', 2385);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (294, '2025-07-24', 'Reported to House', '<p><strong>Department of the Interior, Environment, and Related Agencies Appropriations Act, 2026</strong></p><p>This bill provides FY2026 appropriations for the Department of the Interior, the Environmental Protection Agency (EPA), and several related agencies.</p><p>The bill provides appropriations to Interior for</p><ul><li>the Bureau of Land Management,</li><li>the U.S. Fish and Wildlife Service,</li><li>the National Park Service,</li><li>the U.S. Geological Survey,</li><li>the Bureau of Ocean Energy Management,</li><li>the Bureau of Safety and Environmental Enforcement,</li><li>the Office of Surface Mining Reclamation and Enforcement,</li><li>the Bureau of Indian Affairs,</li><li>the Bureau of Indian Education,</li><li>the Bureau of Trust Funds Administration,</li><li>Departmental Offices, and</li><li>Department-Wide Programs.</li></ul><p>The bill also provides appropriations to the EPA and the Forest Service.</p><p>Within the Department of Health and Human Services, the bill provides appropriations for</p><ul><li>the Indian Health Service,</li><li>the National Institute of Environmental Health Sciences, and</li><li>the Agency for Toxic Substances and Disease Registry.</li></ul><p>The bill provides appropriations to several related agencies, including</p><ul><li>the Council on Environmental Quality and Office of Environmental Quality,</li><li>the Chemical Safety and Hazard Investigation Board,</li><li>the Institute of American Indian and Alaska Native Culture and Arts Development,</li><li>the Smithsonian Institution,</li><li>the National Gallery of Art,</li><li>the John F. Kennedy Center for the Performing Arts,</li><li>the Woodrow Wilson International Center for Scholars,</li><li>the National Endowment for the Arts,</li><li>the National Endowment for the Humanities,</li><li>the Commission of Fine Arts,</li><li>the Advisory Council on Historic Preservation.</li><li>the National Capital Planning Commission,</li><li>the U.S. Holocaust Memorial Museum, and</li><li>the U.S. Semiquincentennial Commission.</li></ul><p>Additionally, the bill sets forth requirements and restrictions for using funds provided by this and other appropriations acts.</p>', '2025-09-11T16:05:13Z', '07', 2388);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (295, '2025-01-22', 'Introduced in House', '<p><strong>Ninth Circuit Court of Appeals Judgeship and Reorganization Act of 2025&nbsp;</strong></p><p>This bill divides the U.S. Court of Appeals for the Ninth Circuit into two judicial circuits: (1) the Ninth Circuit, and (2) a new Twelfth Circuit.</p><p>The Ninth Circuit is composed of California, Guam, Hawaii, and Northern Mariana Islands. The new Twelfth Circuit is composed of Alaska, Arizona, Idaho, Montana, Nevada, Oregon, and Washington.</p>', '2025-07-23T18:30:59Z', '00', 2389);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (296, '2025-01-09', 'Introduced in House', '<p>This bill increases from two to three the total number of U.S. district court judgeships for the District of Idaho. The President must appoint, with the advice and consent of the Senate, one additional judge for that judicial district.</p>', '2025-03-07T21:47:42Z', '00', 2390);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (297, '2025-01-13', 'Introduced in House', '<p><strong>Goldie''s Act</strong></p><p>This bill expands enforcement provisions under the Animal Welfare Act (AWA).</p><p>Specifically, the bill directs the Department of Agriculture (USDA) to document and record detailed descriptions of violations of the act observed during inspections and investigations. USDA must provide a copy of all records documenting violations to state, local, and municipal animal control or law enforcement officials within 24 hours of such inspections or investigations.</p><p>Inspections must be held at least once a year of each research facility, the premises of each animal dealer, and each exhibitor of animals. If violations are found during inspections, then USDA must conduct any necessary follow-up inspections until all the violations are corrected. Inspectors must confiscate or destroy in a humane manner animals found to be suffering physical or psychological harm as a result of failure to comply with the AWA.</p><p>Violators are subject to civil penalties as outlined in the bill.</p>', '2025-03-31T14:57:09Z', '00', 2397);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (298, '2025-03-24', 'Introduced in House', '<p>This bill establishes the Commission on National Agricultural Statistics Service (NASS) Modernization to study and provide recommendations on modernizing and streamlining data collection at NASS. As background, NASS conducts the Census of Agriculture and provides official statistics on agricultural production and other farm sector indicators.</p><p>The 11-member commission must include 4 specified members from the Department of Agriculture, 1 member from the Bureau of Labor Statistics, and 6 members appointed by the House and Senate Agriculture Committees.</p><p>At the request of the commission chair, federal agencies must provide the commission information related to the study.</p><p>The commission must submit a report to the President and Congress on the results of the study within two years of the bill''s enactment. The report must include (1) an inventory of surveys conducted by NASS and their frequency; and (2) recommendations for administrative, regulatory, and legislative changes.</p>', '2025-05-30T10:45:54Z', '00', 2412);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (299, '2025-06-06', 'Introduced in House', '<p><strong>Rescissions Act of 2025</strong></p><p>This bill rescinds $9.4 billion in&nbsp;unobligated funds that were provided to the Department of State, the U.S. Agency for International Development (USAID), various independent and related agencies, and the Corporation for Public Broadcasting.&nbsp;</p><p>The rescissions were proposed by the President under procedures included in the Congressional Budget and Impoundment Control Act of 1974. Under current law, the President may propose rescissions to Congress using specified procedures, and the rescissions must be enacted into law to take effect.&nbsp;</p><p>Specifically, the bill rescinds funds that were provided to the State Department or the President for</p><ul><li>Contributions to International Organizations;</li><li>Contributions for International Peacekeeping Activities;</li><li>Global Health Programs;</li><li>Migration and Refugee Assistance;</li><li>the Complex Crises Fund;</li><li>the Democracy Fund;</li><li>the Economic Support Fund;</li><li>Contributions to the Clean Technology Fund;</li><li>International Organization and Programs;</li><li>Development Assistance;</li><li>Assistance for Europe, Eurasia, and Central Asia;</li><li>International Disaster Assistance; and</li><li>Transition Initiatives.</li></ul><p>The bill also rescinds funds that were provided for&nbsp;</p><ul><li>USAID Operating Expenses,</li><li>the Inter-American Foundation,</li><li>the&nbsp;U.S. African Development Foundation,</li><li>the U.S. Institute of Peace, and</li><li>the Corporation for Public Broadcasting.</li></ul>', '2025-06-13T14:03:58Z', '00', 2413);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (300, '2025-06-12', 'Passed House', '<p><strong>Rescissions Act of 2025</strong></p><p>This bill rescinds $9.4 billion in&nbsp;unobligated funds that were provided to the Department of State, the U.S. Agency for International Development (USAID), various independent and related agencies, and the Corporation for Public Broadcasting.&nbsp;</p><p>The rescissions were proposed by the President under procedures included in the Congressional Budget and Impoundment Control Act of 1974. Under current law, the President may propose rescissions to Congress using specified procedures, and the rescissions must be enacted into law to take effect.&nbsp;</p><p>Specifically, the bill rescinds funds that were provided to the State Department or the President for</p><ul><li>Contributions to International Organizations;</li><li>Contributions for International Peacekeeping Activities;</li><li>Global Health Programs;</li><li>Migration and Refugee Assistance;</li><li>the Complex Crises Fund;</li><li>the Democracy Fund;</li><li>the Economic Support Fund;</li><li>Contributions to the Clean Technology Fund;</li><li>International Organization and Programs;</li><li>Development Assistance;</li><li>Assistance for Europe, Eurasia, and Central Asia;</li><li>International Disaster Assistance; and</li><li>Transition Initiatives.</li></ul><p>The bill also rescinds funds that were provided for&nbsp;</p><ul><li>USAID Operating Expenses,</li><li>the Inter-American Foundation,</li><li>the&nbsp;U.S. African Development Foundation,</li><li>the U.S. Institute of Peace, and</li><li>the Corporation for Public Broadcasting.</li></ul>', '2025-06-13T18:27:57Z', '53', 2413);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (301, '2025-01-03', 'Introduced in House', '<p>This resolution informs the Senate that a quorum of the House of Representatives has assembled, that Rep. Mike Johnson of Louisiana has been elected Speaker, and that Kevin McCumber has been elected Clerk of the House of Representatives of the 119th Congress.</p>', '2025-01-14T14:57:14Z', '00', 2414);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (302, '2025-01-03', 'Introduced in House', '<p>This resolution provides for the House of Representatives (together with the Senate) to notify the President that a quorum of each chamber of Congress has assembled.</p>', '2025-01-14T14:55:04Z', '00', 2415);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (303, '2024-03-05', 'Introduced in House', '<p>This concurrent resolution provides for a joint session of Congress on March 7, 2024, to receive a message from the President.</p>', '2025-08-11T19:07:16Z', '00', 2417);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (304, '2024-03-05', 'Passed House', '<p>This concurrent resolution provides for a joint session of Congress on March 7, 2024, to receive a message from the President.</p>', '2025-08-11T19:13:09Z', '53', 2417);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (305, '2025-01-03', 'Introduced in House', '<p><b>Born-Alive Abortion Survivors Protection Act</b> </p> <p>This bill establishes requirements for the degree of care a health care practitioner must provide in the case of a child born alive following an abortion or attempted abortion.</p> <p> Specifically, a health care practitioner who is present must (1) exercise the same degree of care as would reasonably be provided to any other child born alive at the same gestational age, and (2) ensure the child is immediately admitted to a hospital. Additionally, a health care practitioner or other employee who has knowledge of a failure to comply with the degree-of-care requirements must immediately report such failure to law enforcement.</p> <p>A health care practitioner who fails to provide the required degree of care, or a health care practitioner or other employee who fails to report such failure, is subject to criminal penalties—a fine, up to five years in prison, or both. </p> <p> An individual who intentionally kills or attempts to kill a child born alive is subject to prosecution for murder.</p> <p>The bill bars the criminal prosecution of a mother of a child born alive under this bill and allows her to bring a civil action against a health care practitioner or other employee for violations. </p>', '2025-01-30T15:49:28Z', '00', 2418);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (306, '2025-12-18', 'Introduced in House', '<p><strong>Increasing Access to Quality Cardiac Rehabilitation Care Act of 2025</strong><strong></strong></p><p>This bill expands  coverage of cardiac, intensive cardiac, and pulmonary rehabilitation programs under Medicare.</p><p>Specifically,&nbsp;the bill allows&nbsp;physician assistants, nurse practitioners, and clinical nurse specialists to administer these&nbsp;programs in their offices, prepare and sign treatment plans, and prescribe exercise.</p>', '2026-01-26T16:48:11Z', '00', 2430);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (307, '2025-02-25', 'Introduced in House', '<p><b>World Language Education Assistance Program Act or the World LEAP Act</b></p> <p>This bill requires the Department of Education to award competitive grants to local educational agencies to establish and carry out new, or improve existing, world language or dual language programs.</p>', '2025-05-07T19:48:51Z', '00', 2433);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (308, '2026-01-20', 'Reported to House', 'Sets forth the rule for consideration of the bill (H.R. 6945) to amend part A of title IV of the Social Security Act to clarify the authority of States to use funds for pregnancy centers, and for other purposes; providing for consideration of the bill (H.R. 6359) to require institutions of higher education to disseminate information on the rights of, and accommodations and resources for, pregnant students, and for other purposes; and providing for consideration of the joint resolution (H.J. Res. 140) providing for congressional disapproval under chapter 8 of title 5, United States Code, of the rule submitted by the Bureau of Land Management relating to Public Land Order No. 7917 for Withdrawal of Federal Lands; Cook, Lake, and Saint Louis Counties, MN.', '2026-01-21T11:20:12Z', '07', 2441);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (309, '2026-01-07', 'Introduced in House', '<p><strong>Barcode Automation for Revenue Collection to Organize Disbursement and Enhance Efficiency Act or the BARCODE Efficiency Act</strong></p><p>This bill requires the Internal Revenue Service (IRS) to use barcodes, barcode scanning technology, and optical character recognition (or similar) technology to digitize certain federal tax return information and correspondence, unless the technology is&nbsp;slower or less reliable than other IRS processes (subject to conditions).&nbsp;</p><p>Specifically, the bill requires a scannable barcode on electronically-prepared federal tax returns that are printed and filed in paper format with the IRS. The bill also requires the IRS to use barcode scanning technology to convert data included on such returns into an electronic format.</p><p>Further, the bill requires the IRS to use optical character recognition (or similar) technology to transcribe federal tax returns and correspondence received by the IRS that are not prepared electronically and are received in paper format.</p><p>However, under the bill, the use of barcodes, barcode scanning technology, and optical character recognition (or similar) technology is not required if (1) such technology is slower or less reliable than manual transcription or any other IRS process, and (2) the IRS provides a report to Congress regarding the determination to not use such technology.</p>', '2026-01-14T20:13:31Z', '00', 2443);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (310, '2025-09-10', 'Introduced in House', 'This bill provides for the relief of Miguel Lopez Luvian.', '2025-09-12T02:19:19Z', '00', 2449);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (311, '2025-12-30', 'Reported to House', '<p><strong>AGOA Extension Act</strong></p><p>This bill extends through December 31, 2028, trade preferences that provide duty-free access to the U.S. market for most exports from eligible countries in sub-Saharan Africa (SSA). The bill also extends through December 31, 2031, customs user fees and merchandise processing fees.</p><p>Specifically, the bill extends through 2028 the duty-free treatment of the products of beneficiary&nbsp;SSA&nbsp;countries under the Trade Act of 1974 (specifically, the Generalized System of Preferences) and the African Growth and Opportunity Act (AGOA). (Currently, there are 32&nbsp;countries eligible for AGOA.)</p><p>Additionally, the extended period applies to the following provisions of AGOA: (1) the duty-free treatment of certain apparel articles from beneficiary SSA countries; and (2) the third-country fabric provision, which allows limited amounts of apparel articles from lesser developed beneficiary&nbsp;SSA countries to qualify for duty-free treatment, even if the yarns and fabrics used in their production are imported from non-AGOA countries (e.g., apparel assembled in Kenya with Chinese fabrics).</p><p>The bill also provides for the refund of duties (i.e., liquidation or reliquidation of entries) on articles from eligible&nbsp;SSA countries that entered into the United States after September 30, 2025, and before the date of this bill''s enactment. A refund request must be filed with U.S. Customs and Border Protection (CBP) and must contain sufficient information for CBP to locate the entry or, if the entry cannot be located, reconstruct the entry. CBP must refund any duties previously paid with respect to the entry within 90 days.</p>', '2026-01-12T20:05:17Z', '07', 2453);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (312, '2025-02-10', 'Introduced in House', '<p><strong>Pandemic Unemployment Fraud Enforcement Act</strong></p><p>This bill extends from 5 to 10 years the statute of limitations for federal criminal charges or civil enforcement actions for fraud&nbsp;related to several&nbsp;unemployment insurance programs that were established during the COVID-19 pandemic.&nbsp; </p><p>The extension applies to Pandemic Unemployment Assistance, Federal Pandemic Unemployment&nbsp;Compensation, Mixed Earners Unemployment Compensation, and Pandemic Emergency Unemployment Compensation.&nbsp;The bill extends the statute of limitations for (1) criminal charges related to fraud, including aggravated identity theft, wire fraud, and conspiracy to commit fraud; and (2) civil actions involving&nbsp;false claims. However, the bill does not apply to a criminal prosecution or civil enforcement action if the applicable statute of limitations expired before the date of the bill''s enactment.</p><p>Additionally, the bill rescinds specified unobligated funds that were provided in the American Rescue Plan Act of 2021&nbsp;to the Department of Labor  for anti-fraud and program integrity activities. &nbsp;</p>', '2025-03-14T15:47:18Z', '00', 2455);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (313, '2025-02-05', 'Introduced in House', '<p>This resolution provides amounts for the expenses of the House Committee on Ways and Means for the 119th Congress.</p>', '2025-04-30T20:11:27Z', '00', 2457);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (314, '2025-10-14', 'Introduced in House', '<p><strong>Promoting Agriculture Safeguards and Security Act of 2025 or the PASS Act of 2025</strong></p><p>This bill establishes requirements to address the national security risk to the agricultural sector of the United States.</p><p>Specifically, the bill prohibits a foreign person (i.e., an individual or entity) who is a citizen of or acting on behalf of China, Russia, Iran, or North Korea from purchasing or investing in U.S. agricultural land and companies. The prohibition also applies to an entity that is registered or organized in, or has a principal place of business in, any of these countries.&nbsp;The President may waive this prohibition, on a case-by-case basis, if the President determines that the waiver is vital to U.S. national security interests.</p><p>The bill also places the Secretary of Agriculture on the Committee on Foreign Investment in the United States (CFIUS) and requires CFIUS to review certain transactions involving investments by foreign persons in the U.S. agricultural sector.</p><p>Additionally, the Department of Agriculture must report on the risks that foreign purchases of U.S. businesses engaged in agriculture pose to the U.S. agricultural sector.</p>', '2026-01-22T16:08:44Z', '00', 2464);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (315, '2026-01-30', 'Introduced in House', 'This bill designates the facility of the United States Postal Service located at 2600 Michigan Avenue in Kissimmee, Florida, as the "Robert Guevara Post Office Building".', '2026-02-18T09:49:22Z', '00', 2472);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (316, '2025-02-03', 'Introduced in Senate', '<p><strong>Secure Rural Schools Reauthorization Act of 2025</strong></p><p>This bill extends and modifies the Secure Rural Schools and Community Self-Determination Act of 2000, including by</p><ul><li>extending payments made to states and counties containing federal land through FY2026,</li><li>providing for payments for FY2024 and FY2025,</li><li>extending the authority of counties to initiate projects using such funds through FY2028, and</li><li>extending the authority to initiate projects proposed by resource advisory committees through FY2028.</li></ul>', '2025-12-08T16:57:09Z', '00', 2493);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (317, '2025-12-16', 'Introduced in Senate', '<p><strong>Essential Caregivers Act of 2025</strong>&nbsp;</p><p>This bill prohibits certain health care facilities from limiting the access of essential caregivers to residents of those facilities, including during designated emergency periods. <em></em>&nbsp;</p><p>Specifically, the bill generally prohibits Medicare skilled nursing facilities, Medicaid nursing facilities, Medicaid intermediate care facilities, and associated inpatient rehabilitation facilities from restricting the access of essential caregivers to residents of the facilities, including during emergency periods in which visitation rights are otherwise restricted. During emergency periods, facilities may restrict access for an initial period of up to seven days and for one additional maximum seven-day period (if the additional period is approved by the state health department). Facilities may restrict access for a total of 7 days (or 14 days with the approval of the state health department) during an emergency period.</p><p>Essential caregivers must agree to comply with any safety protocols set by the facility, which may be no more stringent for caregivers compared to those for staff. Caregivers who fail to comply with these requirements may be denied access, subject to an appeals process.</p>', '2026-01-26T16:46:52Z', '00', 2494);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (318, '2026-01-12', 'Introduced in House', '<p>This joint resolution nullifies Public Land Order 7917, which withdrew approximately 225,504 acres of National Forest System lands in Cook, Lake, and Saint Louis Counties, Minnesota, from mineral and geothermal leasing for 20 years. In 2023, the Bureau of Land Management issued the order to protect and preserve the Rainy River Watershed, the Boundary Waters Canoe Area Wilderness, the Boundary Waters Canoe Area Wilderness Mining Protection Area, and the 1854 Ceded Territory of the Lake Superior Chippewa from the potential adverse effects of mineral and geothermal exploration and development. The joint resolution removes such protections and allows such land to be leased for the exploration and development of minerals and geothermal energy.</p>', '2026-01-16T18:00:25Z', '00', 2503);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (319, '2025-11-04', 'Introduced in House', '<p><strong>Pay Our Capitol Police Act</strong></p><p>This bill provides FY2026 continuing appropriations for the U.S. Capitol Police (USCP) to pay and provide benefits for employees who are working during a government shutdown.</p><p>The bill provides the appropriations for any period during which interim or full-year appropriations for FY2026 are not in effect (i.e., a government shutdown). Specifically, the bill provides the appropriations to the USCP for salaries, overtime pay, hazardous duty pay, recruitment and retention bonuses, and employee benefits for (1) members of the&nbsp;USCP who are excepted employees (i.e., required to work) or are performing emergency work during the shutdown, and (2) civilian employees who are providing support to the members.</p><p>The bill also provides appropriations for payments to USCP contractors who are providing support to the members of the&nbsp;USCP who are working during the shutdown.&nbsp;</p><p>The appropriations provided by this bill may not be used during any period in which continuing appropriations are in effect for these purposes.&nbsp;</p><p>The appropriations are available until the earlier of (1) the enactment into law of legislation to provide FY2026 appropriations for the USCP or the legislative branch (including continuing appropriations), or (2) September 30, 2026.</p><p>The bill must take effect as if it had been enacted on October 1, 2025.</p>', '2025-11-06T22:24:15Z', '00', 2506);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (320, '2025-01-21', 'Introduced in House', '<p><strong>Beaches Environmental Assessment and Coastal Health Act of 2025 or the BEACH Act of 2025</strong></p><p>This bill reauthorizes through FY2029 and expands an existing program of the Environmental Protection Agency (EPA) that awards grants to states and local governments to (1) monitor the water quality of coastal recreational waters adjacent to beaches or similar points of access that are used by the public; and (2) notify the public, local governments, and the EPA when the water is not safe for recreational activities.</p><p>Specifically, the bill expands the program to allow the EPA to award grants for identifying sources of contamination (i.e., pathogens) for coastal recreation waters. It also allows grants to be used for monitoring and notification of contamination in (1) shallow waters upstream from recreational waters, and (2) recreational waters on beaches.</p>', '2025-07-28T13:48:40Z', '00', 2520);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (321, '2025-02-18', 'Introduced in House', '<p><strong>Protecting America''s Agricultural Land from Foreign Harm Act of 2025</strong></p><p>This bill prohibits persons associated with the governments of Iran, North Korea, China, or Russia from purchasing or leasing agricultural land in the United States.</p><p>Specifically, the President must prohibit any person (individual or entity) owned by, controlled by, or subject to the jurisdiction or direction of these foreign governments from purchasing or leasing (1) public agricultural land that is owned by the United States and administered by a federal department or agency, or (2) private agricultural land that is located in the United States.</p><p>A person that violates or attempts to violate this prohibition is subject to civil and criminal penalties. This prohibition does not require a person that owns or leases agricultural land as of the date of this bill''s enactment to sell that land.</p><p>Further, the President must prohibit a person associated with these foreign governments and who leases, or who has full or partial ownership of, agricultural land in the United States from participating in Department of Agriculture (USDA) programs. Exceptions are included to allow for participation in USDA programs related to food safety, the health and labor safety of individuals, or certain reporting and disclosure requirements.</p><p>The bill excludes U.S. citizens or lawful permanent residents from these restrictions.</p><p>The bill also amends the Agricultural Foreign Investment Disclosure Act of 1978 (AFIDA) to require reporting on security interests and leases.</p><p>Finally, the Government Accountability Office must submit a report to Congress on AFIDA.</p>', '2025-03-31T14:37:41Z', '00', 2531);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (322, '2025-02-06', 'Introduced in House', '<p><strong>Farm Credit Administration Independent Authority Act</strong></p><p>This bill specifies that the Farm Credit Administration (FCA) is the sole regulator of the Farm Credit System (FCS) and establishes reporting requirements for FCS institutions (i.e., lenders).</p><p>Specifically, the bill states that the FCA is the sole and independent regulator of the FCS and exempts entities that are supervised by the FCA from the Equal Credit Opportunity Act (ECOA).</p><p>As background, the bill addresses a rule issued by the Consumer Financial Protection Bureau (CFPB) that implements provisions of the ECOA by requiring covered financial institutions, including FCS institutions, to collect and report to the CFPB data on credit applications for small businesses, including the principal owner''s race, sex, and ethnicity. This 2023 rule has been challenged in court.</p><p>The bill also requires FCS institutions to (1) request that loan applicants and borrowers that are small farmers disclose information identifying their race, sex, and ethnicity; and (2) annually report the collected information to the FCA.&nbsp;The FCA must make the collected information available to the public on annual basis.&nbsp;If an FCS institution customer does not voluntarily report the requested information, the FCA may not require the institution to use other means to deduce the information.</p><p>In addition, the bill specifies that&nbsp;FCS institutions shall not be required to comply with the bill''s requirements if financial institutions are not required to comply with the CFPB rule due to a court invalidating the rule or a repeal of the rule.</p>', '2025-03-26T13:48:29Z', '00', 2564);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (323, '2025-04-08', 'Introduced in House', '<p><strong>Medicare Enrollment Protection Act of 2025</strong></p><p>This bill provides for a special enrollment period for Medicare medical benefits for individuals who are enrolled in COBRA continuation coverage at the time they qualify for Medicare. The special enrollment period applies during each month of COBRA coverage and the three-month period after coverage ends; individuals may enroll during the special enrollment period once during their lifetime.</p>', '2025-05-06T17:52:12Z', '00', 2569);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (324, '2025-01-03', 'Introduced in House', '<p><strong>Fentanyl is a WMD Act</strong></p><p>This bill requires the Countering Weapons of Mass Destruction Office of the Department of Homeland Security to treat illicit fentanyl as a weapon of mass destruction.</p>', '2025-03-06T21:34:41Z', '00', 2570);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (325, '2025-04-10', 'Introduced in Senate', '<p><strong>Continental Divide National Scenic Trail Completion Act</strong></p><p>This bill directs the Department of Agriculture (USDA) and the Department of the Interior to seek to complete the Continental Divide National Scenic Trail no later than 10 years after the enactment of this bill.</p><p>USDA and Interior must&nbsp;establish a joint Forest Service and Bureau of Land Management trail completion team to work in coordination with the administrator of the trail to facilitate its completion and optimization.</p><p>USDA must complete a comprehensive development plan for the trail within three years.</p><p>USDA and Interior must also seek to enter into agreements with volunteer and nonprofit organizations to facilitate the completion and administration of the trail.</p>', '2026-02-10T20:24:35Z', '00', 2584);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (326, '2025-11-18', 'Introduced in House', 'This bill designates the facility of the United States Postal Service located at 202 South Chestnut Avenue in Marshfield, Wisconsin, as the "Army Corporal Gordon ''Gordy'' Richard Schmoll Post Office Building".', '2025-11-29T05:50:19Z', '00', 2588);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (327, '2025-09-26', 'Introduced in House', '<p><strong>It''s About Time Act </strong></p><p>This bill changes the calendar period for the federal fiscal year (currently October 1-September 30) to January 1-December 31 beginning on January 1, 2027.</p>', '2026-01-30T20:00:12Z', '00', 2604);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (328, '2026-02-13', 'Introduced in House', '<p><strong>Farm, Food, and National Security Act of 2026</strong></p><p>This bill (commonly known as the farm bill) reauthorizes through FY2031 and modifies Department of Agriculture programs that address</p><ul><li>commodity support,</li><li>conservation,</li><li>trade and international food aid,</li><li>nutrition assistance,</li><li>farm credit,</li><li>rural development,</li><li>research and extension activities,</li><li>forestry,</li><li>energy,</li><li>horticulture,</li><li>crop insurance,</li><li>livestock and other animals, and</li><li>foreign investments in U.S. agricultural land.</li></ul>', '2026-03-03T15:47:49Z', '00', 2609);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (329, '2025-10-17', 'Introduced in House', '<p><strong>White House Building Activities Locked-out in Lapse Act or the BALL Act</strong></p><p>This bill prohibits federal funds from being&nbsp;used for construction or renovation in the White House, on White House grounds, or within any structure on White House grounds during a lapse in appropriations for a fiscal year (i.e., government shutdown) unless the&nbsp;construction or renovation is directly related to matters of health or safety.</p>', '2025-10-23T13:05:53Z', '00', 2623);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (330, '2025-10-21', 'Introduced in House', '<p><strong>Federal Supervisor Education Act of 2025</strong></p><p>This bill expands the training requirements for federal government supervisors.</p><p>Specifically, the head of each agency, in consultation with the Office of Personnel Management (OPM), must establish programs (1) for supervisors to have individual development plans that include training on how to foster performance goals and objectives for employees, (2) to train supervisors on employee rights and prohibited personnel practices, and (3) to provide guidance and advice to new or underperforming supervisors.</p><p>Supervisors must complete the training under this bill not later than one year after the individual is appointed to the position of supervisor and every three years thereafter.</p><p>The OPM must issue (1) regulations to implement these training requirements, and (2) guidance to agencies about the competencies supervisors are expected to meet to effectively manage the performance of employees. Agencies must assess supervisors in accordance with this guidance.&nbsp;</p>', '2025-12-15T20:08:58Z', '00', 2635);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (331, '2025-09-04', 'Introduced in House', '<p>This bill prohibits camping outdoors on public property in the District of Columbia. The penalty for a violation of the prohibition is a fine of up to $500, imprisonment for up to 30 days, or both.</p>', '2025-09-11T20:29:42Z', '00', 2636);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (332, '2025-01-13', 'Introduced in House', '<p><strong>Sea Turtle Rescue Assistance and Rehabilitation Act of 2025</strong></p><p>This bill expands the John H. Prescott Marine Mammal Rescue and Response Grant Program to include separate grants to rescue sea turtles for the next seven years. The grants must be used for</p><ul><li>the recovery, care, or treatment of sick, injured, or entangled sea turtles;</li><li>responses to rescue stranded sea turtles;</li><li>the collection of data and samples from living or dead stranded sea turtles for scientific research or health assessments;</li><li>facility operating costs that are directly related to activities to assist sea turtles; or&nbsp;</li><li>development of stranding network capacity where facilities do not exist or are sparse.</li></ul><p>In addition, the bill establishes the Sea Turtle Rescue, Rehabilitation, and Rapid Response Fund.</p>', '2025-04-01T20:34:03Z', '00', 2638);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (333, '2025-12-12', 'Reported to House', '<p><strong>504 Program Risk Oversight Act</strong></p><p>This bill requires the Small Business Administration (SBA) to annually conduct a risk analysis of all loans guaranteed under the 504 loan program.</p><p>The 504 loan program provides long-term, fixed-rate financing to qualifying small&nbsp;businesses for major fixed assets, such as land, buildings, equipment, and machinery.</p><p>The SBA must annually report the results of the risk analysis for each preceding fiscal year, including the steps taken by the SBA to mitigate the risks identified in the analysis.</p>', '2026-01-16T16:54:11Z', '07', 2663);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (334, '2025-02-27', 'Introduced in House', '<p><strong>Governing Unaccredited Representatives Defrauding VA Benefits Act or the GUARD VA Benefits Act</strong></p> <p>This bill imposes fines on individuals for soliciting, contracting for, charging, or receiving any unauthorized fee or compensation with respect to the preparation, presentation, or prosecution of any claim for Department of Veterans Affairs benefits. The attempted commission of such offenses is also punishable by fine.</p>', '2025-04-08T19:31:59Z', '00', 2675);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (335, '2025-02-18', 'Introduced in House', '<p>This bill establishes eligibility for certain disability compensation and benefits for individuals who served at the Nevada Test and Training Range (NTTR).</p><p>The bill establishes that onsite participation on or after January 1, 1972, and before January 1, 2005, at certain&nbsp;NTTR locations where there was a potential of toxic exposure is a radiation-risk activity, therefore providing a presumption of service-connection for specified conditions. The bill specifies the covered NTTR locations include a location at Indian Springs Auxiliary Airfield but do not include a location at Nellis Air Force Base or Creech Air Force Base.</p><p>The bill also establishes a presumption of toxic exposure for veterans who performed active service at such NTTR locations, including airspace above such locations. Additionally,&nbsp;lipomas and tumor related conditions must be considered as service-connected conditions for veterans who served at the NTTR locations.</p>', '2026-03-04T16:45:00Z', '00', 2701);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (336, '2025-10-03', 'Introduced in House', '<p>This joint resolution proposes a constitutional amendment that prohibits Members of Congress from receiving compensation for any period during which a government shutdown is in effect. Under the amendment, a government shutdown is considered to be in effect if there is a lapse in appropriations for any federal agency or department as a result of a failure to enact a regular appropriations bill or a continuing resolution.</p>', '2025-10-06T18:14:15Z', '00', 2710);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (337, '2025-01-16', 'Introduced in House', '<p><strong>Equal COLA Act</strong></p><p>This bill applies a&nbsp;cost-of-living adjustment (COLA)&nbsp;for annuities paid under the Federal Employees Retirement System that is equal to the increase in inflation, regardless of the amount of&nbsp;the increase.</p><p>Specifically, for any year in which the Consumer Price Index (CPI) has increased over the previous year, the COLA amount shall be increased by the change in the CPI&nbsp;from the previous year.&nbsp;</p><p>Current law applies an adjustment equal to the change in CPI only if the change is 2% or less. If the change is between 2% and 3%, the adjustment is limited to 2%. If the change is more than 3%, the adjustment is limited to 1% less than the change.</p><p></p>', '2025-06-30T16:19:36Z', '00', 2712);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (338, '2025-03-26', 'Introduced in Senate', '<p><strong>Accountability Through Electronic Verification Act</strong></p><p>This bill expands the E-Verify program by requiring all employers to use it and permanently reauthorizes the program. Currently, E-Verify use is voluntary for most employers, although some states mandate its use.</p><p>All employers must use E-Verify to confirm the identity and employment eligibility of all recruited, referred, or hired individuals, including current employees who were never verified under the program. Failure to use E-Verify shall create a rebuttable presumption that the employer is violating immigration law.</p><p>U.S. Citizenship and Immigration Services must generate weekly reports about individuals who have received a final nonconfirmation of employment eligibility. The Department of Homeland Security (DHS) must use the report to enforce immigration laws.</p><p>The bill increases civil and criminal penalties for hiring non-U.S. nationals (<em>aliens </em>under federal law) who are not authorized to work. DHS must bar repeat offenders and those criminally convicted from holding federal contracts, grants, or cooperative agreements.</p><p>The Social Security Administration, Internal Revenue Service, Department of the Treasury, and DHS must jointly establish a program to share information to help identify non-U.S. nationals who are not authorized to work.</p><p>The bill establishes the Employer Compliance Inspection Center within Homeland Security Investigations of U.S. Immigration and Customs Enforcement. The center''s duties include processing I-9 employment eligibility verification forms and ensuring compliance with employment eligibility laws.</p><p>DHS must report to Congress on ways to simplify procedures relating to I-9 forms and on whether the I-9 process should be eliminated.</p>', '2026-01-22T15:38:41Z', '00', 2726);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (339, '2025-03-13', 'Introduced in Senate', '<p><strong>Aviation Funding Stability Act of 2025</strong><strong></strong></p><p>This bill provides continuing appropriations to the Federal Aviation Administration (FAA) if (1) an appropriations bill for the FAA has not been enacted before a fiscal year begins, or (2) a joint resolution making continuing appropriations for the FAA is not in effect.</p><p>Specifically, the bill provides appropriations from the Airport and Airway Trust Fund at the rate of operations that was provided for the prior fiscal year to continue programs, projects, and activities for which funds were provided in the preceding fiscal year.</p>', '2025-08-04T13:53:49Z', '00', 2734);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (340, '2025-11-25', 'Introduced in House', 'This bill designates the facility of the United States Postal Service located at 12109 New Kent Highway in New Kent, Virginia, as the "Patricia Paige Post Office".', '2025-12-10T12:19:21Z', '00', 2759);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (341, '2025-02-06', 'Introduced in House', '<p><strong>Protecting Veteran Access to Telemedicine Services Act of 2025</strong></p><p>This bill permanently authorizes certain Department of Veterans Affairs (VA) health care professionals to use&nbsp;telemedicine to deliver, distribute, or dispense controlled substances that are prescription drugs to patients who are eligible for VA health care, regardless of whether the health care professional has conducted an in-person medical examination. The health care professional must be (1) authorized to prescribe the basic class of such controlled substance under an active, current, full, and unrestricted license or certification; (2) acting in the usual course of professional practice; and (3) delivering, distributing, or dispensing the substance for a legitimate medical purpose.</p>', '2025-05-01T20:37:54Z', '00', 2770);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (342, '2025-07-21', 'Reported to House', '<p><strong>Transportation, Housing and Urban Development, and Related Agencies Appropriations Act, 2026</strong></p><p>This bill provides FY2026 appropriations to the Department of Transportation (DOT), the Department of Housing and Urban Development (HUD), and several related agencies.</p><p>The bill provides appropriations to DOT for</p><ul><li>the Office of the Secretary,</li><li>the Federal Aviation Administration,</li><li>the Federal Highway Administration,</li><li>the Federal Motor Carrier Safety Administration,</li><li>the National Highway Traffic Safety Administration,</li><li>the Federal Railroad Administration,</li><li>the Federal Transit Administration,</li><li>the Great Lakes St. Lawrence Seaway Development Corporation,</li><li>the Maritime Administration,</li><li>the Pipeline and Hazardous Materials Safety Administration, and</li><li>the Office of Inspector General.</li></ul><p>The bill provides appropriations to HUD for</p><ul><li>Management and Administration,</li><li>Public and Indian Housing,</li><li>Community Planning and Development,</li><li>Housing Programs,</li><li>the Federal Housing Administration,</li><li>the Government National Mortgage Association (Ginnie Mae),</li><li>Policy Development and Research,</li><li>Fair Housing and Equal Opportunity,</li><li>the Office of Lead Hazard Control and Healthy Homes,</li><li>the Information Technology Fund, and</li><li>the Office of Inspector General.</li></ul><p>The bill also provides appropriations to several related agencies, including</p><ul><li>the Access Board,</li><li>the Federal Maritime Commission,</li><li>the National Railroad Passenger Corporation (Amtrak) Office of Inspector General,</li><li>the National Transportation Safety Board,</li><li>the Neighborhood Reinvestment Corporation, and</li><li>the Surface Transportation Board.</li></ul><p>Additionally, the bill sets forth requirements and restrictions for using funds provided by this and other appropriations acts.</p>', '2025-09-11T17:49:59Z', '07', 2771);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (343, '2025-06-25', 'Reported to House', '<p><strong>Increasing Investor Opportunities Act </strong></p><p>This bill allows a closed-end fund—a portfolio of pooled assets with a limited number of shares traded on an exchange—to increase its investment in private investment funds.&nbsp;Specifically, the Securities and Exchange Commission is prohibited from limiting the sale or listing of securities of a closed-end fund that invests in private investment funds. This bill also apples to a closed-end company treated as a business development company.&nbsp;&nbsp;</p>', '2025-09-02T21:04:40Z', '07', 2776);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (344, '2025-07-16', 'Introduced in House', '<p><strong>Developing and Empowering our Aspiring Leaders Act of 2025 </strong></p><p>This bill directs the Securities and Exchange Commission to revise venture capital investment regulations to allow additional types of investments to be considered as qualifying investments. Venture capital funds are exempt from certain regulations applicable to other investment firms, including those related to filings, audits, and restricted communications with investors. Under current regulations, non-qualifying investments—which include secondary transactions and investments in other venture capital funds—may comprise up to 20% of a venture capital fund.</p><p>The bill allows investments acquired through secondary transactions or investments in other venture capital funds to be considered as qualifying investments for venture capital funds. However, for a private fund to qualify as a venture capital fund, the fund''s investments must predominately (1) be acquired directly, or (2) be investments in other venture capital funds.</p>', '2025-11-26T19:24:36Z', '00', 2777);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (345, '2025-12-04', 'Reported to House', '<p><strong>Standardizing Permitting and Expediting Economic Development Act or the SPEED Act</strong></p><p>This bill limits the scope of the National Environmental Policy Act of 1969 (NEPA) and modifies the environmental review of major federal actions under NEPA to generally limit the number of federal actions that trigger NEPA review and to expedite the review process.</p><p>For example, the bill&nbsp;redefines <em>major federal actions</em>, including to specify that an agency may not determine that an action is a major federal action based solely on the provision of federal funds.</p><p>It also excludes from the requirement for NEPA review certain proposed agency actions that have already been reviewed under another federal, state, or tribal environmental review statute that meets the requirements of&nbsp;NEPA.</p><p>The bill directs an agency, when preparing an environmental document for a proposed agency action, to consider only those effects  proximately caused by the immediate project or action under consideration. Agencies may not consider effects that are speculative, attenuated from the project or action, separate in time or place from the project or action, or in relation to separate projects or actions.</p><p>The bill modifies the requirement for agencies to prepare an environmental assessment to apply to agency actions that are not likely to have a reasonably foreseeable significant effect on the quality of the human environment. (Currently, the requirement only applies to actions that do not have such an effect.) </p><p>The bill makes a variety of other modifications to NEPA, including by limiting judicial review of NEPA cases.</p>', '2025-12-16T21:22:24Z', '07', 2789);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (346, '2025-02-24', 'Introduced in House', '<p><strong>Dentist and Optometric Care Access Act of 2025 or the DOC Access Act</strong> <strong>of 20</strong><strong>25</strong></p><p>This bill prohibits private health insurance plans from setting rates for items and services, except for dental cleanings, provided by a doctor of optometry, of dental surgery, or of dental medicine&nbsp;(or an employer of such a doctor) for which the plan does not pay a substantial amount.</p><p>Additionally, an agreement between a plan and such a doctor for limited scope dental or vision benefits may last longer than two years only with the prior acceptance of the doctor for each term extension. Plans also may not restrict such a doctor''s choice of laboratories or suppliers.</p><p>Such doctors may elect to waive the application of the payment amount and choice of laboratories provisions of this bill.</p><p>The bill does not supersede state laws regarding health insurers and dental or vision benefit plans.</p>', '2026-03-05T02:01:09Z', '00', 2793);
INSERT INTO `bill_summaries` (`id`, `action_date`, `action_desc`, `text`, `update_date`, `version_code`, `legislation_id`) VALUES (347, '2025-10-24', 'Introduced in House', 'This bill designates the facility of the United States Postal Service located at 306 South Main Street in Waupaca, Wisconsin, as the "Master Sergeant Melvin O. Handrich Post Office Building".', '2025-10-28T05:28:47Z', '00', 2796);
